"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([["6607"],{77735(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"raspberry-pi-ssh-setup","metadata":{"permalink":"/blog/raspberry-pi-ssh-setup","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/raspberry-pi-ssh-setup.md","source":"@site/blog/linux/raspberry-pi-ssh-setup.md","title":"Raspberry Pi Remote Development with VS Code & SSH","description":"Connect VS Code to Raspberry Pi via SSH for IoT development with GPIO access and real-time testing","date":"2024-10-15T00:00:00.000Z","tags":[{"inline":false,"label":"Raspberry Pi","permalink":"/blog/tags/raspberry-pi","description":"Raspberry Pi single-board computers"},{"inline":false,"label":"SSH","permalink":"/blog/tags/ssh","description":"Secure Shell protocol"},{"inline":false,"label":"VS Code","permalink":"/blog/tags/vscode","description":"Visual Studio Code editor"},{"inline":false,"label":"Remote Development","permalink":"/blog/tags/remote-development","description":"Remote development environments"},{"inline":false,"label":"Embedded Systems","permalink":"/blog/tags/embedded-systems","description":"Embedded systems development"}],"readingTime":9.93,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Raspberry Pi Remote Development with VS Code & SSH","description":"Connect VS Code to Raspberry Pi via SSH for IoT development with GPIO access and real-time testing","slug":"raspberry-pi-ssh-setup","authors":"youkoutaku","date":"2024-10-15T00:00:00.000Z","tags":["raspberry-pi","ssh","vscode","remote-development","embedded-systems"],"keywords":["raspberry pi","ssh","vscode","remote development","embedded systems"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","nextItem":{"title":"Build ROS/ROS2 Development Environment with Docker - Complete Guide","permalink":"/blog/docker-ros"}},"content":"This guide explains how to set up Visual Studio Code (VS Code) for remote development on a Raspberry Pi using SSH. This setup allows you to develop IoT and embedded projects directly on the Raspberry Pi while maintaining the comfort of your local development environment.\\n\\n![VS Code Remote Development on Raspberry Pi](https://preview.redd.it/i-just-set-up-visual-studio-code-for-remote-development-on-v0-ieh7oacw9bge1.png?width=640&crop=smart&auto=webp&s=93192dc0f9df66059316a00358c91303cde7c64a)\\n\\n## Overview\\n\\nRemote development on Raspberry Pi offers several advantages:\\n\\n- **Direct hardware access**: Work with GPIO, sensors, and peripherals directly\\n- **Consistent environment**: Use your local VS Code setup with Pi\'s resources\\n- **Efficient development**: No need to transfer files manually\\n- **Real-time testing**: Test embedded applications in the target environment\\n\\n## Prerequisites\\n\\n- Raspberry Pi with Raspberry Pi OS installed\\n- Local machine with VS Code\\n- Network connection between both devices\\n- Basic familiarity with SSH and command line\\n\\n{/* truncate */}\\n\\n## 1. Install VS Code and Extensions\\n\\n### 1.1 Install VS Code on Local Machine\\n\\nDownload and install Visual Studio Code from the [official website](https://code.visualstudio.com/).\\n\\n### 1.2 Install Remote Development Extensions\\n\\nInstall the **Remote Development** extension pack:\\n\\n1. Open VS Code\\n2. Click on the **Extensions** view icon on the sidebar (Ctrl+Shift+X)\\n3. Search for **Remote Development**\\n4. Install the extension pack by Microsoft\\n\\nThis pack includes:\\n- Remote - SSH\\n- Remote - Containers  \\n- Remote - WSL\\n\\n### 1.3 Alternative: Install Remote - SSH Only\\n\\nIf you only need SSH functionality:\\n1. Search for **Remote - SSH**\\n2. Install the extension by Microsoft\\n\\n## 2. Configure SSH on Raspberry Pi\\n\\n### 2.1 Enable SSH Service\\n\\nSSH is typically enabled by default on newer Raspberry Pi OS installations. To verify or enable it:\\n\\n**Method 1: Using raspi-config (Recommended)**\\n```bash\\n# Open Raspberry Pi configuration tool\\nsudo raspi-config\\n\\n# Navigate: Interfacing Options > SSH > Enable\\n# Select \\"Yes\\" to enable SSH\\n# Finish and reboot if prompted\\n```\\n\\n**Method 2: Using systemctl**\\n```bash\\n# Enable SSH service\\nsudo systemctl enable ssh\\n\\n# Start SSH service  \\nsudo systemctl start ssh\\n\\n# Check SSH status\\nsudo systemctl status ssh\\n```\\n\\n**Method 3: Enable SSH via desktop**\\n1. Go to Raspberry Pi Configuration from the Preferences menu\\n2. Navigate to the Interfaces tab\\n3. Enable SSH\\n4. Click OK and reboot if prompted\\n\\n### 2.2 Configure SSH Security (Recommended)\\n\\n```bash\\n# Edit SSH configuration\\nsudo nano /etc/ssh/sshd_config\\n```\\n\\n**Recommended settings:**\\n```bash\\n# Change default port (optional)\\n# Port 2222\\n\\n# Disable root login\\nPermitRootLogin no\\n\\n# Enable public key authentication\\nPubkeyAuthentication yes\\n\\n# Keep connections alive\\nClientAliveInterval 60\\nClientAliveCountMax 3\\n\\n# Limit login attempts\\nMaxAuthTries 3\\n```\\n\\n**Apply changes:**\\n```bash\\nsudo systemctl restart ssh\\n```\\n\\n## 3. Network Configuration\\n\\n### 3.1 Find Raspberry Pi IP Address\\n\\n**Method 1: Using hostname command**\\n```bash\\n# Get IP address\\nhostname -I\\n\\n# Get detailed network information\\nip addr show\\n```\\n\\n**Method 2: Using ifconfig**\\n```bash\\nifconfig\\n```\\n\\n**Method 3: Check router\'s admin panel**\\n- Access your router\'s web interface\\n- Look for connected devices\\n- Find your Raspberry Pi in the device list\\n\\n### 3.2 Set Static IP (Recommended)\\n\\nFor consistent connections, set a static IP address:\\n\\n```bash\\n# Edit dhcpcd configuration\\nsudo nano /etc/dhcpcd.conf\\n```\\n\\nAdd at the end of the file:\\n```bash\\n# Static IP configuration\\ninterface eth0  # or wlan0 for WiFi\\nstatic ip_address=192.168.1.100/24\\nstatic routers=192.168.1.1\\nstatic domain_name_servers=192.168.1.1 8.8.8.8\\n```\\n\\n**Apply changes:**\\n```bash\\nsudo systemctl restart dhcpcd\\n```\\n\\n### 3.3 Configure Firewall (If Enabled)\\n\\n```bash\\n# Check if ufw is active\\nsudo ufw status\\n\\n# Allow SSH through firewall\\nsudo ufw allow ssh\\n\\n# For custom SSH port\\nsudo ufw allow 2222/tcp\\n```\\n\\n## 4. SSH Key Setup\\n\\n### 4.1 Generate SSH Key Pair (Local Machine)\\n\\n**On Windows:**\\n```powershell\\n# Open Command Prompt or PowerShell\\nssh-keygen -t rsa -b 4096 -C \\"your_email@example.com\\"\\n\\n# Follow prompts:\\n# Enter file: Press Enter for default (C:\\\\Users\\\\<username>\\\\.ssh\\\\id_rsa)\\n# Enter passphrase: Optional but recommended\\n# Confirm passphrase\\n```\\n\\n**On Linux/macOS:**\\n```bash\\n# Generate SSH key pair\\nssh-keygen -t rsa -b 4096 -C \\"your_email@example.com\\"\\n\\n# Follow prompts:\\n# Enter file: Press Enter for default (~/.ssh/id_rsa)\\n# Enter passphrase: Optional but recommended  \\n# Confirm passphrase\\n```\\n\\n### 4.2 Copy Public Key to Raspberry Pi\\n\\n**Method 1: Using ssh-copy-id (Linux/macOS)**\\n```bash\\n# Copy public key to Raspberry Pi\\nssh-copy-id pi@192.168.1.100\\n\\n# Replace with your Pi\'s username and IP\\nssh-copy-id <raspberry_pi_username>@<raspberry_pi_ip>\\n```\\n\\n**Method 2: Manual Copy (All Platforms)**\\n\\n**Display your public key:**\\n```bash\\n# Windows\\ntype C:\\\\Users\\\\<username>\\\\.ssh\\\\id_rsa.pub\\n\\n# Linux/macOS\\ncat ~/.ssh/id_rsa.pub\\n```\\n\\n**Copy the displayed key, then:**\\n```bash\\n# Connect to Raspberry Pi\\nssh pi@192.168.1.100\\n\\n# Create .ssh directory (if it doesn\'t exist)\\nmkdir -p ~/.ssh\\n\\n# Edit authorized_keys file\\nnano ~/.ssh/authorized_keys\\n\\n# Paste your public key into this file\\n# Save and exit (Ctrl+X, Y, Enter)\\n\\n# Set proper permissions\\nchmod 700 ~/.ssh\\nchmod 600 ~/.ssh/authorized_keys\\n```\\n\\n:::warning[Important Note]\\n`authorized_keys` is a fixed filename. If you have multiple keys, save all of them in this file, each on a separate line.\\n:::\\n\\n### 4.3 Test SSH Connection\\n\\n```bash\\n# Test passwordless SSH connection\\nssh pi@192.168.1.100\\n\\n# Should connect without asking for password\\n# Exit the session\\nexit\\n```\\n\\n## 5. Configure VS Code SSH Connection\\n\\n### 5.1 Connect via Command Palette\\n\\n1. Open VS Code\\n2. Press `Ctrl+Shift+P` (Cmd+Shift+P on macOS)\\n3. Type **Remote-SSH: Connect to Host...**\\n4. Enter: `pi@192.168.1.100` (replace with your Pi\'s details)\\n5. Select the platform: **Linux**\\n6. VS Code will install the server components automatically\\n\\n### 5.2 Create SSH Configuration File\\n\\nCreate an SSH config file for easier connection management:\\n\\n**File locations:**\\n- **Windows**: `C:\\\\Users\\\\<username>\\\\.ssh\\\\config`\\n- **Linux/macOS**: `~/.ssh/config`\\n\\n**Example configuration:**\\n```bash\\n# Raspberry Pi Development\\nHost raspberry_pi\\n    HostName 192.168.1.100\\n    User pi\\n    Port 22\\n    IdentityFile ~/.ssh/id_rsa\\n    ServerAliveInterval 60\\n    ServerAliveCountMax 3\\n\\n# Multiple Pi setup example\\nHost pi-zero\\n    HostName 192.168.1.101\\n    User pi\\n    Port 22\\n\\nHost pi-4\\n    HostName 192.168.1.102\\n    User pi\\n    Port 22\\n```\\n\\n**For Windows, use full paths:**\\n```bash\\nHost raspberry_pi\\n    HostName 192.168.1.100\\n    User pi\\n    IdentityFile C:\\\\Users\\\\<username>\\\\.ssh\\\\id_rsa\\n```\\n\\n### 5.3 Connect Using SSH Config\\n\\n1. Open Command Palette (`Ctrl+Shift+P`)\\n2. Type **Remote-SSH: Connect to Host...**\\n3. Select **raspberry_pi** from the list\\n4. VS Code will connect using your saved configuration\\n\\n## 6. VS Code Remote Development on Pi\\n\\n### 6.1 First Connection Setup\\n\\n1. VS Code will automatically install the VS Code Server on your Pi\\n2. Wait for the installation to complete (may take several minutes)\\n3. You\'ll see \\"SSH: raspberry_pi\\" in the bottom-left corner when connected\\n\\n### 6.2 Working with Raspberry Pi Files\\n\\n```bash\\n# Open a folder on the Pi\\nCtrl+K Ctrl+O\\n\\n# Open terminal on Raspberry Pi\\nCtrl+` (backtick)\\n\\n# File explorer shows Pi\'s file system\\n# All extensions run on the Raspberry Pi\\n```\\n\\n### 6.3 Install Extensions for Pi Development\\n\\nInstall these extensions on the remote (Raspberry Pi) side:\\n\\n**Essential Extensions:**\\n- **Python** - For Python development\\n- **C/C++** - For compiled languages\\n- **GitLens** - Enhanced Git capabilities\\n- **Bracket Pair Colorizer** - Better code readability\\n\\n**IoT/Embedded Specific:**\\n- **PlatformIO IDE** - For embedded development\\n- **Arduino** - Arduino development support\\n- **Circuit Python** - MicroPython support\\n\\n**Installation steps:**\\n1. Go to Extensions view (Ctrl+Shift+X)\\n2. Look for \\"SSH: raspberry_pi - Installed\\" section\\n3. Install extensions in the remote section\\n\\n### 6.4 Raspberry Pi Specific Development\\n\\n**GPIO and Hardware Access:**\\n```python\\n# Example: LED control with RPi.GPIO\\nimport RPi.GPIO as GPIO\\nimport time\\n\\n# Setup\\nGPIO.setmode(GPIO.BCM)\\nGPIO.setup(18, GPIO.OUT)\\n\\n# Blink LED\\nfor i in range(10):\\n    GPIO.output(18, GPIO.HIGH)\\n    time.sleep(0.5)\\n    GPIO.output(18, GPIO.LOW)\\n    time.sleep(0.5)\\n\\n# Cleanup\\nGPIO.cleanup()\\n```\\n\\n**Install common Pi libraries:**\\n```bash\\n# Python libraries for Raspberry Pi\\npip install RPi.GPIO\\npip install gpiozero\\npip install adafruit-circuitpython-*\\npip install w1thermsensor\\n\\n# For camera module\\npip install picamera2\\n```\\n\\n## 7. Development Workflow Examples\\n\\n### 7.1 Python IoT Project Setup\\n\\n```bash\\n# Create project directory\\nmkdir ~/my_iot_project\\ncd ~/my_iot_project\\n\\n# Create virtual environment\\npython -m venv venv\\nsource venv/bin/activate\\n\\n# Install dependencies\\npip install RPi.GPIO requests flask\\n\\n# Create requirements file\\npip freeze > requirements.txt\\n```\\n\\n### 7.2 GPIO Programming\\n\\n```python\\n# sensor_reader.py\\nfrom gpiozero import MotionSensor, LED\\nfrom signal import pause\\n\\n# Setup components\\npir = MotionSensor(4)\\nled = LED(18)\\n\\n# Event handlers\\ndef motion_detected():\\n    print(\\"Motion detected!\\")\\n    led.on()\\n\\ndef no_motion():\\n    print(\\"Motion stopped\\")\\n    led.off()\\n\\n# Assign events\\npir.when_motion = motion_detected\\npir.when_no_motion = no_motion\\n\\n# Keep program running\\npause()\\n```\\n\\n### 7.3 Web Server for IoT Control\\n\\n```python\\n# app.py - Simple Flask web server\\nfrom flask import Flask, render_template, request\\nfrom gpiozero import LED\\n\\napp = Flask(__name__)\\nled = LED(18)\\n\\n@app.route(\'/\')\\ndef index():\\n    return \'\'\'\\n    <h1>Raspberry Pi LED Control</h1>\\n    <a href=\\"/led/on\\"><button>Turn ON</button></a>\\n    <a href=\\"/led/off\\"><button>Turn OFF</button></a>\\n    \'\'\'\\n\\n@app.route(\'/led/<state>\')\\ndef led_control(state):\\n    if state == \'on\':\\n        led.on()\\n        return \\"LED is ON\\"\\n    elif state == \'off\':\\n        led.off()\\n        return \\"LED is OFF\\"\\n\\nif __name__ == \'__main__\':\\n    app.run(host=\'0.0.0.0\', port=5000)\\n```\\n\\n## 8. Port Forwarding for Web Development\\n\\n### 8.1 Forward Ports from Pi to Local Machine\\n\\n1. Open Command Palette (`Ctrl+Shift+P`)\\n2. Type **Remote-SSH: Forward Port from Active Host**\\n3. Enter port number (e.g., 5000 for Flask)\\n4. Access via `http://localhost:5000` on your local machine\\n\\n### 8.2 Automatic Port Forwarding\\n\\nVS Code can automatically detect and forward common development ports:\\n- Port 3000 (React, Node.js)\\n- Port 5000 (Flask)\\n- Port 8000 (Django, HTTP server)\\n- Port 8080 (Alternative HTTP)\\n\\n## 9. Troubleshooting\\n\\n### 9.1 Connection Issues\\n\\n#### \\"Connection Refused\\" Error\\n```bash\\n# Check SSH service on Pi\\nsudo systemctl status ssh\\n\\n# Restart SSH service\\nsudo systemctl restart ssh\\n\\n# Check if SSH port is open\\nsudo netstat -tlnp | grep :22\\n```\\n\\n#### \\"Permission Denied\\" Error\\n```bash\\n# Check SSH key permissions on local machine\\nls -la ~/.ssh/\\n\\n# Fix permissions on Pi\\nchmod 700 ~/.ssh\\nchmod 600 ~/.ssh/authorized_keys\\n```\\n\\n#### \\"Host Key Verification Failed\\"\\n```bash\\n# Remove old host key\\nssh-keygen -R 192.168.1.100\\n\\n# Connect again to accept new key\\nssh pi@192.168.1.100\\n```\\n\\n### 9.2 Performance Issues\\n\\n#### Slow Connection\\n```bash\\n# Add to SSH config for better performance\\nHost raspberry_pi\\n    HostName 192.168.1.100\\n    User pi\\n    Compression yes\\n    TCPKeepAlive yes\\n    ServerAliveInterval 60\\n```\\n\\n#### VS Code Server Issues\\n```bash\\n# Remove VS Code Server files on Pi\\nrm -rf ~/.vscode-server\\n\\n# Reconnect to reinstall\\n```\\n\\n### 9.3 Hardware-Specific Issues\\n\\n#### GPIO Permission Errors\\n```bash\\n# Add user to gpio group\\nsudo usermod -a -G gpio $USER\\n\\n# For i2c and spi\\nsudo usermod -a -G i2c,spi,gpio $USER\\n\\n# Logout and login again\\n```\\n\\n#### Camera Module Issues\\n```bash\\n# Enable camera interface\\nsudo raspi-config\\n# Navigate: Interfacing Options > Camera > Enable\\n\\n# Test camera\\nraspistill -o test.jpg\\n```\\n\\n## 10. Best Practices\\n\\n### 10.1 Security Best Practices\\n\\n1. **Use SSH keys instead of passwords**\\n2. **Change default SSH port**\\n3. **Keep Pi OS updated**\\n4. **Use firewall when needed**\\n5. **Regular security audits**\\n\\n```bash\\n# Update Raspberry Pi OS\\nsudo apt update && sudo apt upgrade -y\\n\\n# Check for security updates\\nsudo unattended-upgrade -d\\n```\\n\\n### 10.2 Development Best Practices\\n\\n1. **Use virtual environments for Python projects**\\n2. **Version control with Git**\\n3. **Regular backups of important projects**\\n4. **Document hardware connections**\\n5. **Use proper error handling in embedded code**\\n\\n### 10.3 Hardware Safety\\n\\n1. **Always shutdown Pi properly**\\n2. **Use appropriate resistors with LEDs**\\n3. **Check voltage levels before connections**\\n4. **Use proper ESD precautions**\\n\\n```bash\\n# Proper shutdown\\nsudo shutdown -h now\\n\\n# Restart\\nsudo reboot\\n```\\n\\n## 11. Advanced Features\\n\\n### 11.1 Multiple Raspberry Pi Management\\n\\n```bash\\n# SSH config for multiple Pis\\nHost pi-livingroom\\n    HostName 192.168.1.100\\n    User pi\\n\\nHost pi-garage  \\n    HostName 192.168.1.101\\n    User pi\\n\\nHost pi-garden\\n    HostName 192.168.1.102\\n    User pi\\n```\\n\\n### 11.2 Cross-Compilation Setup\\n\\nFor ARM development on x86 machines:\\n\\n```bash\\n# Install cross-compilation tools\\nsudo apt install gcc-arm-linux-gnueabihf\\n\\n# Configure for Pi Zero (ARMv6)\\nexport CC=arm-linux-gnueabihf-gcc\\nexport CXX=arm-linux-gnueabihf-g++\\n```\\n\\n### 11.3 Docker on Raspberry Pi\\n\\n```bash\\n# Install Docker on Pi\\ncurl -fsSL https://get.docker.com -o get-docker.sh\\nsh get-docker.sh\\n\\n# Add user to docker group\\nsudo usermod -aG docker pi\\n\\n# Test Docker\\ndocker run hello-world\\n```\\n\\n## Resources\\n\\n- [Raspberry Pi Documentation](https://www.raspberrypi.org/documentation/)\\n- [VS Code Remote Development](https://code.visualstudio.com/docs/remote/remote-overview)\\n- [GPIO Zero Documentation](https://gpiozero.readthedocs.io/)\\n- [Raspberry Pi GPIO Pinout](https://pinout.xyz/)\\n\\n\\n:::tip[Pro Tips]\\n- Use a high-quality SD card (Class 10 or better) for better performance\\n- Set up SSH key-based authentication for security\\n- Use VS Code\'s integrated terminal for Pi-specific commands\\n- Enable I2C/SPI/Camera through raspi-config before using them\\n- Consider using a USB-to-Ethernet adapter for more stable connections\\n:::\\n\\n:::note[Performance Note]\\nRaspberry Pi 4 with 4GB+ RAM provides the best experience for VS Code remote development. Older models may be slower but still functional.\\n:::"},{"id":"docker-ros","metadata":{"permalink":"/blog/docker-ros","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/docker/docker-ros.md","source":"@site/blog/docker/docker-ros.md","title":"Build ROS/ROS2 Development Environment with Docker - Complete Guide","description":"Solve ROS dependency issues and run multiple ROS versions with Docker on Ubuntu/WSL","date":"2024-09-08T00:00:00.000Z","tags":[{"inline":false,"label":"Docker","permalink":"/blog/tags/docker","description":"Docker containerization platform"},{"inline":false,"label":"ROS","permalink":"/blog/tags/ros","description":"Robot Operating System"},{"inline":false,"label":"ROS2","permalink":"/blog/tags/ros2","description":"Robot Operating System 2"},{"inline":false,"label":"Ubuntu","permalink":"/blog/tags/ubuntu","description":"Ubuntu Linux operating system"},{"inline":false,"label":"WSL","permalink":"/blog/tags/wsl","description":"Windows Subsystem for Linux"}],"readingTime":5.52,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Build ROS/ROS2 Development Environment with Docker - Complete Guide","description":"Solve ROS dependency issues and run multiple ROS versions with Docker on Ubuntu/WSL","slug":"docker-ros","authors":"youkoutaku","date":"2024-09-08T00:00:00.000Z","tags":["docker","ros","ros2","ubuntu","wsl"],"keywords":["docker","ros","ros2","robotics","ubuntu","wsl","gazebo","rviz"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Raspberry Pi Remote Development with VS Code & SSH","permalink":"/blog/raspberry-pi-ssh-setup"},"nextItem":{"title":"How to Start and Manage Docker Containers with GUI Support","permalink":"/blog/docker-container-start"}},"content":"Building a ROS development environment with Docker solves environment dependency issues and allows using multiple ROS versions on the same system. This guide explains in detail how to build a ROS environment with Docker.\\n\\n![Docker + ROS](https://roboticseabass.com/wp-content/uploads/2021/04/docker_ros_banner-1.png)\\n\\n{/* truncate */}\\n\\n## 1. Docker Installation\\n\\n### Installation Using APT Repository\\n\\nInstall Docker from the official Docker APT repository.\\n\\n#### 1.1 Prerequisites\\n\\n```bash\\n# Add Docker\'s official GPG key\\nsudo apt-get update\\nsudo apt-get install ca-certificates curl gnupg\\nsudo install -m 0755 -d /etc/apt/keyrings\\ncurl -fsSL https://download.docker.com/linux/ubuntu/gpg | sudo gpg --dearmor -o /etc/apt/keyrings/docker.gpg\\nsudo chmod a+r /etc/apt/keyrings/docker.gpg\\n```\\n\\n#### 1.2 Add Repository\\n\\n```bash\\n# Add repository to APT sources\\necho \\\\\\n  \\"deb [arch=$(dpkg --print-architecture) signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu \\\\\\n  $(. /etc/os-release && echo \\"$VERSION_CODENAME\\") stable\\" | \\\\\\n  sudo tee /etc/apt/sources.list.d/docker.list > /dev/null\\nsudo apt-get update\\n```\\n\\n#### 1.3 Install Docker\\n\\n```bash\\nsudo apt-get install docker-ce docker-ce-cli containerd.io docker-buildx-plugin docker-compose-plugin\\n```\\n\\n#### 1.4 Verify Installation\\n\\n```bash\\nsudo docker run hello-world\\n```\\n\\n:::warning[About Docker Desktop]\\nDo not install Docker Desktop on Ubuntu. Docker Engine is sufficient.\\n:::\\n\\n## 2. ROS Docker Images\\n\\n### Official ROS Images\\n\\nOfficial ROS images can be obtained from [Docker Hub](https://hub.docker.com/_/ros/).\\n\\n#### ROS1 Noetic\\n\\n```bash\\nsudo docker pull osrf/ros:noetic-desktop-full\\n```\\n\\n#### ROS2 Humble\\n\\n```bash\\nsudo docker pull osrf/ros:humble-desktop-full\\n```\\n\\n#### Other ROS Distributions\\n\\n```bash\\n# ROS1 Melodic\\nsudo docker pull osrf/ros:melodic-desktop-full\\n\\n# ROS2 Galactic\\nsudo docker pull osrf/ros:galactic-desktop-full\\n\\n# ROS2 Iron\\nsudo docker pull osrf/ros:iron-desktop-full\\n```\\n\\n### Available Tags\\n\\n| Tag | Contents |\\n|-----|----------|\\n| `ros-core` | Minimal ROS installation |\\n| `ros-base` | Basic ROS packages |\\n| `desktop` | ROS Desktop (includes RViz) |\\n| `desktop-full` | Full ROS Desktop (includes simulators) |\\n\\n## 3. Creating ROS Containers\\n\\n### 3.1 X11 Forwarding Setup\\n\\nConfiguration for using GUI applications (RViz, Gazebo, VS Code):\\n\\n```bash\\nxhost +\\n```\\n\\n:::info[Automation Tip]\\nYou need to run this command every time you restart the container.\\n:::\\n\\n### 3.2 Create Data Folder\\n\\nCreate a folder for sharing files between host and container:\\n\\n```bash\\nmkdir ~/ros_workspace\\n```\\n\\n### 3.3 Create ROS1 Noetic Container\\n\\n```bash\\nsudo docker run -it \\\\\\n    -v ~/ros_workspace:/data \\\\\\n    --device=/dev/dri \\\\\\n    --group-add video \\\\\\n    --volume=/tmp/.X11-unix:/tmp/.X11-unix \\\\\\n    --env=\\"DISPLAY=$DISPLAY\\" \\\\\\n    --env=\\"QT_X11_NO_MITSHM=1\\" \\\\\\n    --name=noetic_container \\\\\\n    osrf/ros:noetic-desktop-full \\\\\\n    /bin/bash\\n```\\n\\n### 3.4 Create ROS2 Humble Container\\n\\n```bash\\nsudo docker run -it \\\\\\n    -v ~/ros_workspace:/data \\\\\\n    --device=/dev/dri \\\\\\n    --group-add video \\\\\\n    --volume=/tmp/.X11-unix:/tmp/.X11-unix \\\\\\n    --env=\\"DISPLAY=$DISPLAY\\" \\\\\\n    --env=\\"QT_X11_NO_MITSHM=1\\" \\\\\\n    --name=humble_container \\\\\\n    osrf/ros:humble-desktop-full \\\\\\n    /bin/bash\\n```\\n\\n### Detailed Parameter Explanation\\n\\n| Parameter | Description |\\n|-----------|-------------|\\n| `docker run` | Create and run new container |\\n| `-it` | Interactive terminal mode |\\n| `-v ~/ros_workspace:/data` | Mount host directory to container |\\n| `--device=/dev/dri` | Access to graphics device |\\n| `--group-add video` | Add to video group (for GPU access) |\\n| `--volume=/tmp/.X11-unix:/tmp/.X11-unix` | Mount X11 socket |\\n| `--env=\\"DISPLAY=$DISPLAY\\"` | Set display environment variable |\\n| `--env=\\"QT_X11_NO_MITSHM=1\\"` | Avoid Qt application display issues |\\n| `--name=<container_name>` | Assign name to container |\\n\\n## 4. ROS Environment Setup Inside Container\\n\\n### 4.1 System Update\\n\\n```bash\\nsudo apt update\\nsudo apt upgrade\\n```\\n\\n### 4.2 Install Required Tools\\n\\n#### Tmux (Terminal Multiplexer)\\n\\n```bash\\napt install tmux\\n```\\n\\nBasic Tmux usage:\\n- New session: `tmux new -s session_name`\\n- List sessions: `tmux list-sessions`\\n- Attach to session: `tmux attach -t session_name`\\n\\n#### Git (Version Control)\\n\\n```bash\\napt install git\\n```\\n\\n#### Additional Development Tools\\n\\n```bash\\n# Editors\\napt install vim nano\\n\\n# Build tools\\napt install build-essential cmake\\n\\n# Python tools\\napt install python3-pip python3-dev\\n\\n# ROS build tools\\napt install python3-catkin-tools  # For ROS1\\napt install python3-colcon-common-extensions  # For ROS2\\n```\\n\\n### 4.3 Verify ROS Environment\\n\\n#### ROS1 Verification\\n\\n1. **Start roscore**\\n   ```bash\\n   roscore\\n   ```\\n\\n2. **Launch RViz (in new terminal)**\\n   ```bash\\n   rviz\\n   ```\\n\\n3. **Launch Gazebo (in new terminal)**\\n   ```bash\\n   gazebo\\n   ```\\n\\n#### ROS2 Verification\\n\\n1. **Run demo_nodes_cpp**\\n   ```bash\\n   ros2 run demo_nodes_cpp talker\\n   ```\\n\\n2. **Run listener in another terminal**\\n   ```bash\\n   ros2 run demo_nodes_cpp listener\\n   ```\\n\\n3. **Launch RViz2**\\n   ```bash\\n   rviz2\\n   ```\\n\\n## 5. Workspace Setup\\n\\n### ROS1 Workspace\\n\\n```bash\\n# Create workspace\\nmkdir -p /data/catkin_ws/src\\ncd /data/catkin_ws\\n\\n# Initialize workspace\\ncatkin_make\\n\\n# Add environment setup\\necho \\"source /data/catkin_ws/devel/setup.bash\\" >> ~/.bashrc\\nsource ~/.bashrc\\n```\\n\\n### ROS2 Workspace\\n\\n```bash\\n# Create workspace\\nmkdir -p /data/ros2_ws/src\\ncd /data/ros2_ws\\n\\n# Build workspace\\ncolcon build\\n\\n# Add environment setup\\necho \\"source /data/ros2_ws/install/setup.bash\\" >> ~/.bashrc\\nsource ~/.bashrc\\n```\\n\\n## 6. Network Configuration\\n\\n### ROS1 Master Configuration\\n\\n```bash\\n# Set environment variables\\nexport ROS_MASTER_URI=http://localhost:11311\\nexport ROS_HOSTNAME=localhost\\n```\\n\\n### ROS2 Domain ID Configuration\\n\\n```bash\\n# Set domain ID (for network isolation)\\nexport ROS_DOMAIN_ID=42\\n```\\n\\n## 7. Container Management\\n\\n### Start and Stop Containers\\n\\n```bash\\n# Start container\\nsudo docker start -ia noetic_container\\n\\n# Stop container\\nsudo docker stop noetic_container\\n\\n# Connect with multiple terminals\\nsudo docker exec -it noetic_container /bin/bash\\n```\\n\\n### Create Container Snapshot\\n\\n```bash\\n# Save current state as an image\\nsudo docker commit noetic_container my_ros_environment:v1.0\\n```\\n\\n## 8. Docker Compose Configuration Example\\n\\nDocker Compose configuration for managing multiple ROS services:\\n\\n```yaml\\nversion: \'3.8\'\\n\\nservices:\\n  ros-master:\\n    image: osrf/ros:noetic-desktop-full\\n    container_name: ros_master\\n    environment:\\n      - DISPLAY=${DISPLAY}\\n      - QT_X11_NO_MITSHM=1\\n    volumes:\\n      - /tmp/.X11-unix:/tmp/.X11-unix:rw\\n      - ./workspace:/workspace\\n    devices:\\n      - /dev/dri:/dev/dri\\n    networks:\\n      - ros_network\\n    command: roscore\\n\\n  rviz:\\n    image: osrf/ros:noetic-desktop-full\\n    container_name: rviz_container\\n    environment:\\n      - DISPLAY=${DISPLAY}\\n      - QT_X11_NO_MITSHM=1\\n      - ROS_MASTER_URI=http://ros-master:11311\\n    volumes:\\n      - /tmp/.X11-unix:/tmp/.X11-unix:rw\\n    devices:\\n      - /dev/dri:/dev/dri\\n    networks:\\n      - ros_network\\n    depends_on:\\n      - ros-master\\n    command: rviz\\n\\nnetworks:\\n  ros_network:\\n    driver: bridge\\n```\\n\\n## 9. Troubleshooting\\n\\n### Common Issues and Solutions\\n\\n#### 1. GUI Applications Don\'t Display\\n\\n```bash\\n# Check X11 forwarding\\necho $DISPLAY\\n\\n# Check xhost settings\\nxhost +local:\\n\\n# Qt-related errors\\nexport QT_X11_NO_MITSHM=1\\n```\\n\\n#### 2. GPU Access Errors\\n\\n```bash\\n# Check NVIDIA drivers\\nnvidia-smi\\n\\n# Install Docker nvidia runtime\\nsudo apt install nvidia-docker2\\nsudo systemctl restart docker\\n```\\n\\n#### 3. Network Connection Issues\\n\\n```bash\\n# Check ROS network settings\\necho $ROS_MASTER_URI\\necho $ROS_HOSTNAME\\n\\n# Check firewall settings\\nsudo ufw status\\n```\\n\\n## 10. Performance Optimization\\n\\n### Reduce Image Size\\n\\n```dockerfile\\n# Multi-stage build example\\nFROM osrf/ros:noetic-desktop-full as builder\\n# Install build packages\\nRUN apt-get update && apt-get install -y build-essential\\n\\nFROM osrf/ros:noetic-desktop-full\\n# Copy only minimal runtime packages\\nCOPY --from=builder /opt/ros/noetic /opt/ros/noetic\\n```\\n\\n### Memory and CPU Limits\\n\\n```bash\\n# Start container with resource limits\\ndocker run -it \\\\\\n    --memory=\\"4g\\" \\\\\\n    --cpus=\\"2.0\\" \\\\\\n    --name=limited_ros \\\\\\n    osrf/ros:noetic-desktop-full\\n```\\n\\n## References\\n\\n1. [Install Docker Engine on Ubuntu](https://docs.docker.com/engine/install/ubuntu/#install-using-the-repository)\\n2. [ROS Official Docker Images](https://hub.docker.com/_/ros/)\\n3. [ROS Getting Started Guide](https://www.ros.org/blog/getting-started/)\\n4. [Tmux Getting Started](https://github.com/tmux/tmux/wiki/Getting-Started)\\n5. [Docker Compose Documentation](https://docs.docker.com/compose/)\\n\\n:::tip[Development Efficiency Tips]\\n- Use VS Code Remote-Containers extension\\n- Maintain consistent directory structure for ROS package development\\n- Standardize development environment with Docker Compose\\n- Use .dockerignore files to reduce build time\\n:::"},{"id":"docker-container-start","metadata":{"permalink":"/blog/docker-container-start","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/docker/docker-container-start.md","source":"@site/blog/docker/docker-container-start.md","title":"How to Start and Manage Docker Containers with GUI Support","description":"Complete guide to creating, starting, and managing Docker containers with X11 forwarding for GUI applications","date":"2024-08-10T00:00:00.000Z","tags":[{"inline":false,"label":"Docker","permalink":"/blog/tags/docker","description":"Docker containerization platform"},{"inline":false,"label":"Container","permalink":"/blog/tags/container","description":"Containerization technology"},{"inline":false,"label":"Ubuntu","permalink":"/blog/tags/ubuntu","description":"Ubuntu Linux operating system"},{"inline":false,"label":"ROS","permalink":"/blog/tags/ros","description":"Robot Operating System"}],"readingTime":2.65,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"How to Start and Manage Docker Containers with GUI Support","description":"Complete guide to creating, starting, and managing Docker containers with X11 forwarding for GUI applications","slug":"docker-container-start","authors":"youkoutaku","date":"2024-08-10T00:00:00.000Z","tags":["docker","container","ubuntu","ros"],"keywords":["docker","container","docker run","docker start","x11","gui","ros"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Build ROS/ROS2 Development Environment with Docker - Complete Guide","permalink":"/blog/docker-ros"},"nextItem":{"title":"How to Run Docker Commands Without Sudo - User Permissions Setup","permalink":"/blog/docker-without-sudo"}},"content":"This guide explains the basic operations for creating, starting, and managing Docker containers. It includes settings for using GUI applications (VS Code, RViz, etc.) within Docker.\\n\\n{/* truncate */}\\n\\n## Initial Setup\\n\\n### X11 Forwarding Configuration\\n\\nTo use GUI applications within Docker, enable X11 forwarding:\\n\\n```bash\\nxhost +\\n```\\n\\n:::info[About X11 Forwarding]\\nThis setting allows you to run VS Code, RViz, and other GUI applications inside Docker containers.\\n:::\\n\\n:::warning[Security Notice]\\n`xhost +` allows X11 connections from all hosts. For production environments, consider using `xhost +local:` for better security.\\n:::\\n\\n## Container Creation\\n\\n### Creating GUI-Enabled Containers\\n\\n```bash\\nsudo docker run -it -v <local_path>:/data \\\\\\n\\t--device=/dev/dri \\\\\\n\\t--group-add video \\\\\\n\\t--volume=/tmp/.X11-unix:/tmp/.X11-unix \\\\\\n\\t--env=\\"DISPLAY=$DISPLAY\\" \\\\\\n\\t--env=\\"QT_X11_NO_MITSHM=1\\" \\\\\\n\\t--name=<container_name> \\\\\\n\\t<image_name>:<tag> \\\\\\n\\t/bin/bash\\n```\\n\\n### Parameter Explanation\\n\\n| Parameter | Description |\\n|-----------|-------------|\\n| `-it` | Enable interactive mode and TTY |\\n| `-v <local_path>:/data` | Mount local directory to container |\\n| `--device=/dev/dri` | Access to GPU/graphics device |\\n| `--group-add video` | Add to video group (graphics permissions) |\\n| `--volume=/tmp/.X11-unix:/tmp/.X11-unix` | Mount X11 socket |\\n| `--env=\\"DISPLAY=$DISPLAY\\"` | Set display environment variable |\\n| `--env=\\"QT_X11_NO_MITSHM=1\\"` | Avoid Qt application display issues |\\n| `--name=<container_name>` | Assign name to container |\\n\\n### Example Usage\\n\\n```bash\\nsudo docker run -it -v /home/user/workspace:/data \\\\\\n\\t--device=/dev/dri \\\\\\n\\t--group-add video \\\\\\n\\t--volume=/tmp/.X11-unix:/tmp/.X11-unix \\\\\\n\\t--env=\\"DISPLAY=$DISPLAY\\" \\\\\\n\\t--env=\\"QT_X11_NO_MITSHM=1\\" \\\\\\n\\t--name=ros_container \\\\\\n\\tros:humble \\\\\\n\\t/bin/bash\\n```\\n\\n### Verify Mounted Directory\\n\\nCheck mounted directory inside the container:\\n\\n```bash\\ncd /data\\nls -la\\n```\\n\\n## Environment Setup Inside Container\\n\\n### Update Package Management System\\n\\n```bash\\nsudo apt update\\nsudo apt upgrade\\n```\\n\\n### Install Basic Tools\\n\\n#### Install Tmux\\n\\n```bash\\napt install tmux\\n```\\n\\nTmux is a useful tool for managing multiple terminal sessions.\\n\\n#### Install Git\\n\\n```bash\\napt install git\\n```\\n\\nEssential tool for version control systems.\\n\\n### Additional Package Examples\\n\\n```bash\\n# Editors\\napt install vim nano\\n\\n# Network tools\\napt install curl wget net-tools\\n\\n# Development tools\\napt install build-essential cmake\\n```\\n\\n## Container Management\\n\\n### Start Existing Container\\n\\n```bash\\nsudo docker start -ia <container_id>\\n```\\n\\n**Parameter explanation:**\\n- `-i`: Interactive mode\\n- `-a`: Attach mode\\n\\n### Check Container Status\\n\\n#### Check running containers\\n\\n```bash\\ndocker ps\\n```\\n\\n#### Check all containers\\n\\n```bash\\ndocker ps -a\\n```\\n\\n#### Check available images\\n\\n```bash\\ndocker images\\n```\\n\\n## Commonly Used Docker Commands\\n\\n### Container Operations\\n\\n```bash\\n# Stop container\\ndocker stop <container_id>\\n\\n# Remove container\\ndocker rm <container_id>\\n\\n# Connect to container (if running)\\ndocker exec -it <container_id> /bin/bash\\n\\n# Check container logs\\ndocker logs <container_id>\\n```\\n\\n### Image Operations\\n\\n```bash\\n# Remove image\\ndocker rmi <image_id>\\n\\n# Remove unused images\\ndocker image prune\\n\\n# Remove all unused resources\\ndocker system prune\\n```\\n\\n## Troubleshooting\\n\\n### Common Issues and Solutions\\n\\n1. **GUI applications don\'t display**\\n   ```bash\\n   # Check X11 forwarding\\n   echo $DISPLAY\\n   \\n   # Check xhost settings\\n   xhost +local:\\n   ```\\n\\n2. **Permission errors**\\n   ```bash\\n   # Add user to docker group\\n   sudo usermod -aG docker $USER\\n   \\n   # Logout/login or\\n   newgrp docker\\n   ```\\n\\n3. **Port access issues**\\n   ```bash\\n   # Add port mapping when creating container\\n   docker run -p <host_port>:<container_port> ...\\n   ```\\n\\n## Best Practices\\n\\n### Data Persistence\\n\\nAlways use volume mounts for important data:\\n\\n```bash\\n-v /host/data:/container/data\\n```\\n\\n### Resource Limits\\n\\n```bash\\n# Memory limit\\n--memory=\\"2g\\"\\n\\n# CPU limit  \\n--cpus=\\"1.5\\"\\n```\\n\\n### Network Configuration\\n\\n```bash\\n# Use custom network\\ndocker network create mynetwork\\ndocker run --network=mynetwork ...\\n```\\n\\n:::tip[For Efficient Development]\\n- Create development Dockerfiles with pre-installed necessary tools\\n- Use Docker Compose to simplify multi-container management\\n- Use .dockerignore files to reduce build time\\n:::"},{"id":"docker-without-sudo","metadata":{"permalink":"/blog/docker-without-sudo","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/docker/docker-without-sudo.md","source":"@site/blog/docker/docker-without-sudo.md","title":"How to Run Docker Commands Without Sudo - User Permissions Setup","description":"Configure Docker user group permissions to eliminate sudo requirements for Linux users","date":"2024-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Docker","permalink":"/blog/tags/docker","description":"Docker containerization platform"},{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"}],"readingTime":2.84,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"How to Run Docker Commands Without Sudo - User Permissions Setup","description":"Configure Docker user group permissions to eliminate sudo requirements for Linux users","slug":"docker-without-sudo","authors":"youkoutaku","date":"2024-08-01T00:00:00.000Z","tags":["docker","linux"],"keywords":["docker","sudo","linux","user group","permissions","security"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"How to Start and Manage Docker Containers with GUI Support","permalink":"/blog/docker-container-start"},"nextItem":{"title":"Docker Hub Tutorial - Login, Push Images & Access Token Setup","permalink":"/blog/docker-hub"}},"content":"By default, Docker commands require root privileges (sudo) to execute. However, with proper configuration, regular users can run Docker commands without sudo.\\n\\n{/* truncate */}\\n\\n## Why sudo is Required\\n\\nThe Docker daemon binds to a Unix socket, which is owned by the root user by default. Therefore, the Docker CLI requires root privileges to communicate with the daemon.\\n\\n## Steps to Use Docker without sudo\\n\\n### 1. Create Docker Group\\n\\nCreate the `docker` group. Users in this group can run Docker commands without root privileges.\\n\\n```bash\\nsudo groupadd docker\\n```\\n\\n:::info[If Group Already Exists]\\nIf the group already exists, this command will have no effect.\\n:::\\n\\n### 2. Add User to Docker Group\\n\\nAdd the current user to the `docker` group:\\n\\n```bash\\nsudo gpasswd -a $USER docker\\n```\\n\\n:::tip[Specifying Username]\\nTo add other users, replace `$USER` with the appropriate username.\\n:::\\n\\n#### Alternative Method\\n\\nYou can also use the `usermod` command:\\n\\n```bash\\nsudo usermod -aG docker $USER\\n```\\n\\n### 3. Apply Group Changes\\n\\nTo apply group changes without logging out and back in, use the `newgrp` command:\\n\\n```bash\\nnewgrp docker\\n```\\n\\n:::warning[About Session Changes]\\nThe `newgrp` command is only effective for the current session. To fully apply the settings, we recommend logging out and back in or restarting the system.\\n:::\\n\\n### 4. Test Configuration\\n\\nVerify that Docker works without sudo:\\n\\n```bash\\ndocker run hello-world\\n```\\n\\nIf successful, you\'ll see a message like this:\\n\\n```\\nHello from Docker!\\nThis message shows that your installation appears to be working correctly.\\n...\\n```\\n\\n## Additional Verification Commands\\n\\n### Check Docker Status\\n\\n```bash\\n# Check Docker daemon status\\ndocker info\\n\\n# Check Docker version\\ndocker version\\n\\n# Check current user\'s groups\\ngroups\\n```\\n\\n### Detailed Permission Check\\n\\n```bash\\n# Check Docker socket permissions\\nls -la /var/run/docker.sock\\n\\n# Check current user ID\\nid\\n```\\n\\n## Troubleshooting\\n\\n### Common Issues and Solutions\\n\\n#### 1. \\"permission denied\\" Error\\n\\n```\\ndocker: Got permission denied while trying to connect to the Docker daemon socket\\n```\\n\\n**Solution:**\\n- Verify user is added to docker group\\n- Log out and log back in\\n- Check if Docker service is running\\n\\n```bash\\n# Check group membership\\ngroups | grep docker\\n\\n# Check Docker service status\\nsudo systemctl status docker\\n\\n# Start Docker service\\nsudo systemctl start docker\\n```\\n\\n#### 2. Group Changes Not Applied\\n\\n**Solution:**\\n1. Completely log out and log back in\\n2. Restart the system\\n3. Force application with these commands:\\n\\n```bash\\nsudo systemctl restart docker\\nnewgrp docker\\n```\\n\\n#### 3. Docker Daemon Won\'t Start\\n\\n```bash\\n# Enable Docker service\\nsudo systemctl enable docker\\n\\n# Check detailed service status\\nsudo journalctl -u docker.service\\n```\\n\\n## Security Considerations\\n\\n### Important Notes\\n\\n:::danger[Security Risk]\\nMembers of the docker group have effectively root-equivalent privileges. This is because:\\n\\n1. **Host Filesystem Access**: Containers can mount the host filesystem\\n2. **Privilege Escalation Potential**: Can run privileged containers\\n3. **System Resource Access**: Control over network, processes, etc.\\n:::\\n\\n### Guidelines for Safe Usage\\n\\n1. **Add Only Trusted Users**\\n   ```bash\\n   # Add only necessary users to docker group\\n   sudo gpasswd -a trusted_user docker\\n   ```\\n\\n2. **Regular Permission Review**\\n   ```bash\\n   # Check docker group members\\n   getent group docker\\n   ```\\n\\n3. **Consider Alternatives**\\n   - **Podman**: Docker alternative with rootless execution capability\\n   - **Docker Rootless Mode**: Available in Docker 20.10+\\n\\n### Docker Rootless Mode\\n\\nConsider using Docker Rootless Mode as a safer alternative:\\n\\n```bash\\n# Install Rootless Docker\\ncurl -fsSL https://get.docker.com/rootless | sh\\n\\n# Set environment variables\\nexport PATH=$HOME/bin:$PATH\\nexport DOCKER_HOST=unix://$XDG_RUNTIME_DIR/docker.sock\\n```\\n\\n## References\\n\\n- [Docker Official Documentation - Post-installation steps](https://docs.docker.com/engine/install/linux-postinstall/)\\n- [Docker Rootless Mode](https://docs.docker.com/engine/security/rootless/)\\n- [Ask Ubuntu - How can I use docker without sudo?](https://askubuntu.com/questions/477551/how-can-i-use-docker-without-sudo)"},{"id":"docker-hub","metadata":{"permalink":"/blog/docker-hub","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/docker/docker-hub.md","source":"@site/blog/docker/docker-hub.md","title":"Docker Hub Tutorial - Login, Push Images & Access Token Setup","description":"Step-by-step guide to Docker Hub authentication, image pushing, and troubleshooting credential errors","date":"2024-07-25T00:00:00.000Z","tags":[{"inline":false,"label":"Docker","permalink":"/blog/tags/docker","description":"Docker containerization platform"}],"readingTime":2.03,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Docker Hub Tutorial - Login, Push Images & Access Token Setup","description":"Step-by-step guide to Docker Hub authentication, image pushing, and troubleshooting credential errors","slug":"docker-hub","authors":"youkoutaku","date":"2024-07-25T00:00:00.000Z","tags":["docker"],"keywords":["docker","docker hub","docker login","access token","image push"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"How to Run Docker Commands Without Sudo - User Permissions Setup","permalink":"/blog/docker-without-sudo"},"nextItem":{"title":"Tmux Tutorial - Master Terminal Multiplexing for Productivity","permalink":"/blog/tmux-terminal-multiplexer"}},"content":"Docker Hub is a cloud-based registry service for storing and sharing Docker images. This guide covers Docker Hub login, image pushing, and troubleshooting.\\n\\n{/* truncate */}\\n\\n## Docker Login\\n\\n### Basic Login\\n\\n```bash\\ndocker login\\n```\\n\\nWhen you run this command, you\'ll be prompted to enter your username and password (or access token).\\n\\n### Error Troubleshooting\\n\\nIf you encounter credential storage errors:\\n\\n```\\n>> Error saving credentials: error storing credentials - err: exec: \\"docker-credential-desktop\\": executable file not found in $PATH, out: `` \\n```\\n\\n**Solution:**\\n\\n1. Edit Docker configuration file:\\n```bash\\nsudo nano ~/.docker/config.json\\n```\\n\\n2. Change `credsStore` to `credStore`\\n\\n:::warning[Important]\\nWhen editing the configuration file, ensure you maintain proper JSON syntax.\\n:::\\n\\n### Using Access Tokens\\n\\nFor improved security, we recommend using access tokens instead of passwords.\\n\\n1. Visit [Docker Hub](https://hub.docker.com/)\\n2. Navigate to **My Account** \u2192 **Security** \u2192 **New Access Token**\\n3. Set token name and select required permissions\\n4. Use the generated token in place of your password\\n\\n:::tip[Security Best Practices]\\n- Store access tokens in a secure location\\n- Grant only minimum required permissions\\n- Rotate tokens regularly\\n:::\\n\\n## Pushing Images to Docker Hub\\n\\n### 1. Rename Container\\n\\n```bash\\ndocker rename old_container_name_or_id new_container_name\\n```\\n\\n### 2. Create Image from Container\\n\\n```bash\\ndocker commit -a=\\"<username>\\" -m=\\"<commit message>\\" <container_id_or_name> <new_image_name>:<version>\\n```\\n\\n**Parameter explanation:**\\n- `-a`: Author name\\n- `-m`: Commit message\\n- `<container_id_or_name>`: Source container\\n- `<new_image_name>:<version>`: New image name and tag\\n\\n### 3. Tag Image\\n\\nTag the image following Docker Hub naming convention `<username>/<repository>:<TAG>`:\\n\\n```bash\\ndocker tag <image_id> <username>/<repository>:<TAG>\\n```\\n\\n**Example:**\\n```bash\\ndocker tag myapp:latest youkoutaku/myapp:v1.0\\n```\\n\\n### 4. Push to Docker Hub\\n\\n```bash\\ndocker push <username>/<repository>:<TAG>\\n```\\n\\n**Example:**\\n```bash\\ndocker push youkoutaku/myapp:v1.0\\n```\\n\\n## Complete Workflow Example\\n\\nHere\'s a complete workflow for pushing a local container to Docker Hub:\\n\\n```bash\\n# 1. Check current containers\\ndocker ps -a\\n\\n# 2. Create image from container\\ndocker commit -a=\\"youkoutaku\\" -m=\\"Initial release\\" my_container myapp:latest\\n\\n# 3. Tag for Docker Hub naming convention\\ndocker tag myapp:latest youkoutaku/myapp:v1.0\\n\\n# 4. Login to Docker Hub\\ndocker login\\n\\n# 5. Push image\\ndocker push youkoutaku/myapp:v1.0\\n```\\n\\n## Troubleshooting\\n\\n### Common Issues and Solutions\\n\\n1. **Authentication Error**\\n   ```\\n   unauthorized: authentication required\\n   ```\\n   - Verify you\'re logged into Docker Hub\\n   - Check username and password/token are correct\\n\\n2. **Naming Error**\\n   ```\\n   denied: requested access to the resource is denied\\n   ```\\n   - Ensure image name follows `<username>/<repository>:<tag>` format\\n   - Verify you have owner permissions for the repository\\n\\n3. **Network Error**\\n   - Check internet connection\\n   - Verify proxy settings are correct\\n\\n:::info[Reference Links]\\n- [Docker Hub Official Documentation](https://docs.docker.com/docker-hub/)\\n- [Docker CLI Reference](https://docs.docker.com/engine/reference/commandline/)\\n:::"},{"id":"tmux-terminal-multiplexer","metadata":{"permalink":"/blog/tmux-terminal-multiplexer","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/tmux-terminal-multiplexer.md","source":"@site/blog/linux/tmux-terminal-multiplexer.md","title":"Tmux Tutorial - Master Terminal Multiplexing for Productivity","description":"Complete tmux guide with shortcuts, session management, and SSH persistence for developers","date":"2024-07-12T00:00:00.000Z","tags":[{"inline":false,"label":"Terminal","permalink":"/blog/tags/terminal","description":"Command-line terminal and shell"},{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"},{"inline":false,"label":"Productivity","permalink":"/blog/tags/productivity","description":"Productivity tips and tools"},{"inline":false,"label":"Development Tools","permalink":"/blog/tags/development-tools","description":"Software development tools and utilities"}],"readingTime":9.49,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Tmux Tutorial - Master Terminal Multiplexing for Productivity","description":"Complete tmux guide with shortcuts, session management, and SSH persistence for developers","slug":"tmux-terminal-multiplexer","authors":"youkoutaku","date":"2024-07-12T00:00:00.000Z","tags":["terminal","linux","productivity","development-tools"],"keywords":["tmux","terminal","multiplexer","session management","linux","productivity"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Docker Hub Tutorial - Login, Push Images & Access Token Setup","permalink":"/blog/docker-hub"},"nextItem":{"title":"Safely Remove Ubuntu from Windows Dual-Boot - Complete UEFI & GRUB Cleanup","permalink":"/blog/remove-ubuntu-dual-boot"}},"content":"**Tmux** (Terminal Multiplexer) is a powerful command-line tool that allows you to manage multiple terminal sessions within a single window. It\'s essential for developers, system administrators, and anyone who works extensively with the command line.\\n\\n## Overview\\n\\nTmux enables you to:\\n\\n- **Run multiple programs simultaneously** in separate windows and panes\\n- **Detach and reattach** to sessions, maintaining long-running processes\\n- **Share sessions** between multiple users or terminals\\n- **Organize workflows** with custom layouts and configurations\\n- **Maintain persistent sessions** that survive SSH disconnections\\n\\n### Key Concepts\\n\\n- **Session**: A collection of windows managed together\\n- **Window**: A single screen containing one or more panes\\n- **Pane**: Individual terminal instances within a window\\n- **Prefix Key**: Command key combination (default: `Ctrl+b`)\\n\\n{/* truncate */}\\n\\n## Installation\\n\\n### Ubuntu/Debian\\n\\n```bash\\nsudo apt update\\nsudo apt install tmux\\n```\\n\\n### CentOS/RHEL/Fedora\\n\\n```bash\\n# CentOS/RHEL\\nsudo yum install tmux\\n\\n# Fedora\\nsudo dnf install tmux\\n```\\n\\n### macOS\\n\\n```bash\\n# Using Homebrew\\nbrew install tmux\\n\\n# Using MacPorts\\nsudo port install tmux\\n```\\n\\n### From Source\\n\\n```bash\\n# Install dependencies (Ubuntu/Debian)\\nsudo apt install libevent-dev libncurses-dev build-essential\\n\\n# Download and compile\\ngit clone https://github.com/tmux/tmux.git\\ncd tmux\\nsh autogen.sh\\n./configure\\nmake && sudo make install\\n```\\n\\n## Basic Usage\\n\\n### Starting Tmux\\n\\n```bash\\n# Start new session\\ntmux\\n\\n# Start session with name\\ntmux new-session -s mysession\\n\\n# Short form\\ntmux new -s mysession\\n\\n# Start with specific command\\ntmux new-session -s work -c ~/projects\\n```\\n\\n### Session Management\\n\\n```bash\\n# List active sessions\\ntmux list-sessions\\ntmux ls\\n\\n# Attach to session\\ntmux attach-session -t mysession\\ntmux a -t mysession\\n\\n# Attach to last session\\ntmux attach\\n\\n# Kill session\\ntmux kill-session -t mysession\\n\\n# Kill all sessions\\ntmux kill-server\\n```\\n\\n### Detaching from Sessions\\n\\n```bash\\n# Detach current session\\nCtrl+b d\\n\\n# List sessions and choose one to detach\\nCtrl+b D\\n```\\n\\n## Window Management\\n\\n### Creating and Managing Windows\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b c` | Create new window |\\n| `Ctrl+b ,` | Rename current window |\\n| `Ctrl+b &` | Kill current window |\\n| `Ctrl+b w` | List windows (interactive) |\\n\\n### Navigating Windows\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b 0-9` | Switch to window 0-9 |\\n| `Ctrl+b n` | Next window |\\n| `Ctrl+b p` | Previous window |\\n| `Ctrl+b l` | Last window |\\n| `Ctrl+b f` | Find window by name |\\n\\n### Window Operations\\n\\n```bash\\n# Create window with name\\nCtrl+b c\\n# Then rename: Ctrl+b ,\\n\\n# Move window position\\nCtrl+b .  # Prompts for new index\\n\\n# Swap windows\\ntmux swap-window -s 1 -t 2\\n```\\n\\n## Pane Management\\n\\n### Creating Panes\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b %` | Split horizontally (side by side) |\\n| `Ctrl+b \\"` | Split vertically (top and bottom) |\\n| `Ctrl+b x` | Kill current pane |\\n\\n### Navigating Panes\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b \u2191 \u2193 \u2190 \u2192` | Navigate panes |\\n| `Ctrl+b o` | Next pane |\\n| `Ctrl+b ;` | Last pane |\\n| `Ctrl+b q` | Show pane numbers |\\n| `Ctrl+b q 0-9` | Go to pane number |\\n\\n### Resizing Panes\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b Ctrl+\u2191 \u2193 \u2190 \u2192` | Resize pane |\\n| `Ctrl+b Alt+\u2191 \u2193 \u2190 \u2192` | Resize pane (5 cells) |\\n| `Ctrl+b space` | Cycle through layouts |\\n\\n### Pane Operations\\n\\n```bash\\n# Break pane to new window\\nCtrl+b !\\n\\n# Join pane from another window\\nCtrl+b :join-pane -s 2.1  # Join pane 1 from window 2\\n\\n# Swap panes\\nCtrl+b {  # Swap with previous pane\\nCtrl+b }  # Swap with next pane\\n\\n# Synchronize panes (type in all panes)\\nCtrl+b :setw synchronize-panes on\\n```\\n\\n## Advanced Features\\n\\n### Copy Mode\\n\\nTmux includes a powerful copy mode for scrolling and text selection:\\n\\n```bash\\n# Enter copy mode\\nCtrl+b [\\n\\n# Navigate in copy mode\\n\u2191 \u2193 \u2190 \u2192  # Move cursor\\nPage Up/Down  # Scroll pages\\ng / G  # Go to top/bottom\\n/ ? # Search forward/backward\\n\\n# Select and copy text\\nSpace  # Start selection\\nEnter  # Copy selection\\nCtrl+b ]  # Paste\\n```\\n\\n### Copy Mode with vi Keys\\n\\n```bash\\n# Enable vi mode in .tmux.conf\\nsetw -g mode-keys vi\\n\\n# vi-style copy mode bindings\\nCtrl+b [  # Enter copy mode\\nh j k l  # Navigate\\nv  # Start selection (visual mode)\\ny  # Copy selection\\nCtrl+b ]  # Paste\\n```\\n\\n### Session Sharing\\n\\n```bash\\n# Create shared session\\ntmux new-session -s shared\\n\\n# Multiple users attach to same session\\ntmux attach-session -t shared\\n\\n# Read-only attachment\\ntmux attach-session -r -t shared\\n```\\n\\n### Scripting and Automation\\n\\n```bash\\n# Create complex layouts via script\\ntmux new-session -d -s development\\ntmux split-window -h\\ntmux split-window -v\\ntmux select-pane -t 0\\ntmux send-keys \'cd ~/project && vim\' Enter\\ntmux select-pane -t 1\\ntmux send-keys \'cd ~/project && npm start\' Enter\\ntmux select-pane -t 2\\ntmux send-keys \'cd ~/project && git status\' Enter\\n```\\n\\n## Configuration\\n\\n### Configuration File\\n\\nCreate `~/.tmux.conf` for custom settings:\\n\\n```bash\\n# Basic configuration example\\n# Set prefix to Ctrl+a (instead of Ctrl+b)\\nunbind C-b\\nset -g prefix C-a\\nbind C-a send-prefix\\n\\n# Enable mouse support\\nset -g mouse on\\n\\n# Start windows and panes at 1, not 0\\nset -g base-index 1\\nsetw -g pane-base-index 1\\n\\n# Renumber windows when one is closed\\nset -g renumber-windows on\\n\\n# Increase scrollback buffer\\nset -g history-limit 10000\\n\\n# Vi mode\\nsetw -g mode-keys vi\\n\\n# Status bar configuration\\nset -g status-bg colour235\\nset -g status-fg colour255\\nset -g status-left \'#S: \'\\nset -g status-right \'%Y-%m-%d %H:%M\'\\n\\n# Pane borders\\nset -g pane-border-style fg=colour240\\nset -g pane-active-border-style fg=colour166\\n\\n# Window status\\nsetw -g window-status-current-style fg=colour166,bg=colour235,bold\\n```\\n\\n### Advanced Configuration\\n\\n```bash\\n# Custom key bindings\\nbind h select-pane -L\\nbind j select-pane -D\\nbind k select-pane -U\\nbind l select-pane -R\\n\\n# Resize panes with vi keys\\nbind -r H resize-pane -L 5\\nbind -r J resize-pane -D 5\\nbind -r K resize-pane -U 5\\nbind -r L resize-pane -R 5\\n\\n# Split panes with | and -\\nbind | split-window -h\\nbind - split-window -v\\n\\n# Quick pane cycling\\nbind -r Tab select-pane -t :.+\\n\\n# Reload configuration\\nbind r source-file ~/.tmux.conf \\\\; display-message \\"Config reloaded!\\"\\n```\\n\\n### Plugin Management with TPM\\n\\nInstall Tmux Plugin Manager:\\n\\n```bash\\n# Clone TPM\\ngit clone https://github.com/tmux-plugins/tpm ~/.tmux/plugins/tpm\\n\\n# Add to .tmux.conf\\nset -g @plugin \'tmux-plugins/tpm\'\\nset -g @plugin \'tmux-plugins/tmux-sensible\'\\nset -g @plugin \'tmux-plugins/tmux-resurrect\'\\n\\n# Initialize TPM (add to bottom of .tmux.conf)\\nrun \'~/.tmux/plugins/tpm/tpm\'\\n```\\n\\n**Install plugins**: `Ctrl+b I`  \\n**Update plugins**: `Ctrl+b U`  \\n**Remove plugins**: `Ctrl+b Alt+u`\\n\\n## Workflow Examples\\n\\n### Development Environment\\n\\n```bash\\n#!/bin/bash\\n# dev-setup.sh - Create development environment\\n\\nSESSION=\\"development\\"\\n\\n# Create session\\ntmux new-session -d -s $SESSION\\n\\n# Window 1: Editor\\ntmux rename-window -t $SESSION:1 \'editor\'\\ntmux send-keys -t $SESSION:1 \'cd ~/project && vim\' Enter\\n\\n# Window 2: Server\\ntmux new-window -t $SESSION:2 -n \'server\'\\ntmux send-keys -t $SESSION:2 \'cd ~/project && npm start\' Enter\\n\\n# Window 3: Terminal\\ntmux new-window -t $SESSION:3 -n \'terminal\'\\ntmux send-keys -t $SESSION:3 \'cd ~/project\' Enter\\n\\n# Split terminal window\\ntmux split-window -h -t $SESSION:3\\ntmux send-keys -t $SESSION:3.2 \'cd ~/project && git status\' Enter\\n\\n# Attach to session\\ntmux attach-session -t $SESSION\\n```\\n\\n### Monitoring Setup\\n\\n```bash\\n# Create monitoring session\\ntmux new-session -d -s monitoring\\n\\n# System monitoring\\ntmux send-keys \'htop\' Enter\\ntmux split-window -h\\ntmux send-keys \'iotop\' Enter\\ntmux split-window -v\\ntmux send-keys \'tail -f /var/log/syslog\' Enter\\n\\n# Network monitoring window\\ntmux new-window\\ntmux send-keys \'netstat -i 1\' Enter\\ntmux split-window -h\\ntmux send-keys \'ss -tuln\' Enter\\n```\\n\\n### Remote Work Session\\n\\n```bash\\n# Long-running tasks\\ntmux new-session -d -s remote-work\\n\\n# Backup process\\ntmux send-keys \'rsync -av --progress /home/ backup@server:/backups/\' Enter\\n\\n# Log monitoring\\ntmux split-window -h\\ntmux send-keys \'tail -f /var/log/application.log\' Enter\\n\\n# Detach and disconnect\\ntmux detach\\n```\\n\\n## Keyboard Shortcuts Reference\\n\\n### Session Commands\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b s` | List sessions |\\n| `Ctrl+b $` | Rename session |\\n| `Ctrl+b d` | Detach session |\\n| `Ctrl+b D` | Choose session to detach |\\n\\n### Window Commands\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b c` | Create window |\\n| `Ctrl+b ,` | Rename window |\\n| `Ctrl+b &` | Kill window |\\n| `Ctrl+b w` | List windows |\\n| `Ctrl+b n/p` | Next/Previous window |\\n| `Ctrl+b 0-9` | Select window 0-9 |\\n| `Ctrl+b l` | Last window |\\n\\n### Pane Commands\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b %` | Split horizontal |\\n| `Ctrl+b \\"` | Split vertical |\\n| `Ctrl+b x` | Kill pane |\\n| `Ctrl+b o` | Next pane |\\n| `Ctrl+b ;` | Last pane |\\n| `Ctrl+b \u2191 \u2193 \u2190 \u2192` | Navigate panes |\\n| `Ctrl+b space` | Cycle layouts |\\n| `Ctrl+b z` | Zoom pane |\\n\\n### Copy Mode Commands\\n\\n| Command | Action |\\n|---------|--------|\\n| `Ctrl+b [` | Enter copy mode |\\n| `q` | Exit copy mode |\\n| `Space` | Start selection |\\n| `Enter` | Copy selection |\\n| `Ctrl+b ]` | Paste |\\n\\n## Troubleshooting\\n\\n### Common Issues\\n\\n#### Tmux Not Starting\\n\\n```bash\\n# Check if tmux is installed\\nwhich tmux\\n\\n# Check version\\ntmux -V\\n\\n# Start with verbose output\\ntmux -v new-session\\n```\\n\\n#### Configuration Issues\\n\\n```bash\\n# Validate configuration\\ntmux source-file ~/.tmux.conf\\n\\n# Start with default configuration\\ntmux -f /dev/null new-session\\n\\n# Check for syntax errors\\ntmux show-messages\\n```\\n\\n#### Session Recovery\\n\\n```bash\\n# List all tmux processes\\nps aux | grep tmux\\n\\n# Kill stuck tmux server\\ntmux kill-server\\n\\n# Recover from crash\\ntmux new-session -d -s recovery\\ntmux list-sessions\\n```\\n\\n#### Performance Issues\\n\\n```bash\\n# Reduce history limit\\nset -g history-limit 1000\\n\\n# Disable mouse if causing issues\\nset -g mouse off\\n\\n# Check for problematic plugins\\ntmux show-environment\\n```\\n\\n### Debugging\\n\\n```bash\\n# Start tmux with debugging\\ntmux -v -f ~/.tmux.conf new-session\\n\\n# Show current options\\ntmux show-options -g\\ntmux show-window-options -g\\n\\n# Display messages\\ntmux display-message \\"Debug info: #{session_name}\\"\\n```\\n\\n## Integration with Other Tools\\n\\n### SSH Integration\\n\\n```bash\\n# Auto-attach to tmux on SSH\\n# Add to ~/.bashrc or ~/.zshrc\\nif [[ -n \\"$SSH_TTY\\" ]] && [[ -z \\"$TMUX\\" ]]; then\\n    tmux attach-session -t ssh_session || tmux new-session -s ssh_session\\nfi\\n```\\n\\n### Git Integration\\n\\n```bash\\n# Show git branch in status bar\\nset -g status-right \'#(cd #{pane_current_path}; git rev-parse --abbrev-ref HEAD 2>/dev/null)\'\\n```\\n\\n### Vim Integration\\n\\n```bash\\n# Smart pane switching between vim and tmux\\n# Add to ~/.vimrc\\nif exists(\'$TMUX\')\\n  function! TmuxOrSplitSwitch(wincmd, tmuxdir)\\n    let previous_winnr = winnr()\\n    silent! execute \\"wincmd \\" . a:wincmd\\n    if previous_winnr == winnr()\\n      call system(\\"tmux select-pane -\\" . a:tmuxdir)\\n    endif\\n  endfunction\\n\\n  nnoremap <silent> <C-h> :call TmuxOrSplitSwitch(\'h\', \'L\')<cr>\\n  nnoremap <silent> <C-j> :call TmuxOrSplitSwitch(\'j\', \'D\')<cr>\\n  nnoremap <silent> <C-k> :call TmuxOrSplitSwitch(\'k\', \'U\')<cr>\\n  nnoremap <silent> <C-l> :call TmuxOrSplitSwitch(\'l\', \'R\')<cr>\\nendif\\n```\\n\\n## Best Practices\\n\\n### Session Organization\\n\\n1. **Use descriptive session names**:\\n   ```bash\\n   tmux new-session -s \\"project-frontend\\"\\n   tmux new-session -s \\"monitoring-prod\\"\\n   ```\\n\\n2. **Create session templates**:\\n   ```bash\\n   # Save as tmux-dev-template.sh\\n   tmux new-session -d -s development\\n   tmux split-window -h\\n   tmux split-window -v\\n   tmux send-keys -t 0 \'vim\' Enter\\n   tmux send-keys -t 1 \'npm start\' Enter\\n   tmux send-keys -t 2 \'git status\' Enter\\n   ```\\n\\n3. **Use consistent window naming**:\\n   ```bash\\n   tmux rename-window \\"editor\\"\\n   tmux rename-window \\"server\\"\\n   tmux rename-window \\"logs\\"\\n   ```\\n\\n### Performance Optimization\\n\\n```bash\\n# Optimize for large sessions\\nset -g history-limit 5000\\nset -s escape-time 0\\nset -g display-time 1000\\nset -g status-interval 5\\n```\\n\\n### Security Considerations\\n\\n```bash\\n# Restrict socket permissions\\nset -g @socket-mode \'0600\'\\n\\n# Lock session after inactivity\\nset -g lock-after-time 1800\\nset -g lock-command \'vlock\'\\n```\\n\\n## Resources and References\\n\\n- [Official Tmux Documentation](https://github.com/tmux/tmux/wiki)\\n- [Tmux Manual Page](https://man.openbsd.org/tmux.1)\\n- [Tmux Plugin Manager (TPM)](https://github.com/tmux-plugins/tpm)\\n- [Awesome Tmux](https://github.com/rothgar/awesome-tmux)\\n\\n\\n:::tip[Productivity Tips]\\n- Create custom scripts for common session layouts\\n- Use tmux with SSH for persistent remote sessions\\n- Combine with screen sharing for collaborative debugging\\n- Set up automatic session restoration with tmux-resurrect\\n- Use mouse mode for easier pane management when learning\\n:::\\n\\n:::info[Quick Start]\\n1. Install tmux: `sudo apt install tmux`\\n2. Start session: `tmux new -s mysession`\\n3. Split panes: `Ctrl+b %` (horizontal) `Ctrl+b \\"` (vertical)\\n4. Navigate: `Ctrl+b \u2191 \u2193 \u2190 \u2192`\\n5. Detach: `Ctrl+b d`\\n6. Reattach: `tmux attach -t mysession`\\n:::"},{"id":"remove-ubuntu-dual-boot","metadata":{"permalink":"/blog/remove-ubuntu-dual-boot","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/remove-ubuntu-dual-boot.md","source":"@site/blog/linux/remove-ubuntu-dual-boot.md","title":"Safely Remove Ubuntu from Windows Dual-Boot - Complete UEFI & GRUB Cleanup","description":"Step-by-step guide to delete Ubuntu partitions, restore Windows bootloader, and fix UEFI boot entries","date":"2024-06-20T00:00:00.000Z","tags":[{"inline":false,"label":"Ubuntu","permalink":"/blog/tags/ubuntu","description":"Ubuntu Linux operating system"},{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"},{"inline":false,"label":"Windows","permalink":"/blog/tags/windows","description":"Microsoft Windows operating system"},{"inline":false,"label":"Dual Boot","permalink":"/blog/tags/dual-boot","description":"Dual-boot system configuration"},{"inline":false,"label":"UEFI","permalink":"/blog/tags/uefi","description":"UEFI firmware interface"},{"inline":false,"label":"GRUB","permalink":"/blog/tags/grub","description":"GRUB bootloader"}],"readingTime":8.22,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Safely Remove Ubuntu from Windows Dual-Boot - Complete UEFI & GRUB Cleanup","description":"Step-by-step guide to delete Ubuntu partitions, restore Windows bootloader, and fix UEFI boot entries","slug":"remove-ubuntu-dual-boot","authors":"youkoutaku","date":"2024-06-20T00:00:00.000Z","tags":["ubuntu","linux","windows","dual-boot","uefi","grub"],"keywords":["ubuntu","dual boot","remove ubuntu","windows","uefi","grub","partition management"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Tmux Tutorial - Master Terminal Multiplexing for Productivity","permalink":"/blog/tmux-terminal-multiplexer"},"nextItem":{"title":"Run Linux GUI Apps on Windows via SSH","permalink":"/blog/x-server-setup"}},"content":"This comprehensive guide explains how to safely remove Ubuntu from a Windows dual-boot system, clean up partitions, and restore the Windows bootloader. Follow these steps carefully to avoid data loss and system issues.\\n\\n:::danger[Data Loss Warning]\\nRemoving Ubuntu involves deleting partitions and modifying system boot files. **Always backup important data** before proceeding. Incorrect execution can make your system unbootable.\\n:::\\n\\n## Overview\\n\\nWhen Ubuntu is installed alongside Windows in a dual-boot configuration, it typically:\\n\\n- Creates Linux partitions (root, swap, sometimes home)\\n- Installs GRUB bootloader to manage boot options\\n- Adds EFI entries for Linux boot process\\n- Modifies system boot sequence\\n\\nProper removal requires:\\n1. **Backing up important data**\\n2. **Removing Ubuntu EFI entries**\\n3. **Deleting Ubuntu partitions**\\n4. **Restoring Windows bootloader**\\n5. **Reclaiming disk space**\\n\\n## Prerequisites\\n\\n### Required Access\\n- **Windows Administrator privileges**\\n- **Physical access to the computer**\\n- **Windows installation media** (for recovery if needed)\\n\\n### Recommended Preparations\\n- **Complete data backup** of important files\\n- **Create Windows recovery drive**\\n- **Document current partition layout**\\n- **Note Ubuntu version and installation details**\\n\\n### System Requirements\\n- **UEFI-based system** (most modern computers)\\n- **Windows 10/11** with Disk Management tools\\n- **Stable power supply** during the process\\n\\n{/* truncate */}\\n\\n## Understanding Your Current Setup\\n\\n### Identify Dual-Boot Configuration\\n\\nBefore proceeding, understand your current setup:\\n\\n```cmd\\n# Open Command Prompt as Administrator\\n# Check current boot configuration\\nbcdedit /enum firmware\\n\\n# Check disk configuration\\ndiskpart\\nlist disk\\nlist partition\\n```\\n\\n### Common Dual-Boot Layouts\\n\\n**Typical UEFI Dual-Boot Setup:**\\n```\\nDisk 0:\\n\u251C\u2500\u2500 EFI System Partition (ESP) - 100-500MB FAT32\\n\u2502   \u251C\u2500\u2500 /EFI/Microsoft/ (Windows boot files)\\n\u2502   \u2514\u2500\u2500 /EFI/ubuntu/ (Ubuntu boot files)\\n\u251C\u2500\u2500 Windows C: Drive - NTFS\\n\u251C\u2500\u2500 Ubuntu Root (/) - ext4\\n\u251C\u2500\u2500 Ubuntu Swap - linux-swap\\n\u2514\u2500\u2500 Ubuntu Home (/home) - ext4 (optional)\\n```\\n\\n### Check Current Partitions\\n\\n1. **Open Disk Management**:\\n   - Right-click \\"This PC\\" \u2192 \\"Manage\\" \u2192 \\"Disk Management\\"\\n   - Or press `Win + X` \u2192 \\"Disk Management\\"\\n\\n2. **Identify Ubuntu partitions**:\\n   - Look for partitions without drive letters\\n   - Usually shows as \\"Healthy (Primary Partition)\\"\\n   - May show file system types like \\"ext4\\" or \\"linux-swap\\"\\n\\n## Method 1: Safe Removal (Recommended)\\n\\n### Step 1: Backup Important Data\\n\\n```bash\\n# If Ubuntu is still bootable, backup data first\\n# Boot into Ubuntu and copy important files to external storage\\nsudo rsync -av /home/username/ /media/backup/\\n```\\n\\n### Step 2: Remove Ubuntu EFI Entries\\n\\n#### Access EFI System Partition\\n\\n1. **Open Command Prompt as Administrator**\\n2. **Launch Diskpart**:\\n\\n```cmd\\ndiskpart\\n```\\n\\n3. **List and select the disk**:\\n\\n```cmd\\n# Display all disks\\nlist disk\\n\\n# Select disk containing Windows (usually disk 0)\\nselect disk 0\\n```\\n\\n4. **List and select EFI partition**:\\n\\n```cmd\\n# Display partitions\\nlist partition\\n\\n# Select EFI System Partition (usually partition 1, ~100-500MB)\\nselect partition 1\\n\\n# Assign temporary drive letter\\nassign letter=Z\\n```\\n\\n#### Remove Ubuntu EFI Files\\n\\n1. **Open File Explorer as Administrator**:\\n   - Right-click File Explorer \u2192 \\"Run as administrator\\"\\n\\n2. **Navigate to EFI partition**:\\n   - Go to `Z:\\\\EFI\\\\`\\n   - You should see folders like `Microsoft`, `ubuntu`, `Boot`\\n\\n3. **Delete Ubuntu folder**:\\n   - Right-click `ubuntu` folder \u2192 \\"Delete\\"\\n   - Confirm deletion\\n\\n#### Clean Up Drive Letter\\n\\nReturn to Diskpart:\\n```cmd\\n# Remove the assigned drive letter\\nremove letter=Z\\n\\n# Exit diskpart\\nexit\\n```\\n\\n### Step 3: Remove Ubuntu Partitions\\n\\n#### Using Disk Management (GUI Method)\\n\\n1. **Open Disk Management**:\\n   - Press `Win + X` \u2192 \\"Disk Management\\"\\n\\n2. **Identify Ubuntu partitions**:\\n   - Look for partitions without drive letters\\n   - Usually appear as \\"Healthy (Primary Partition)\\"\\n   - Common sizes: 20GB+ for root, 2-8GB for swap\\n\\n3. **Delete Ubuntu partitions**:\\n   - Right-click each Ubuntu partition\\n   - Select \\"Delete Volume\\"\\n   - Confirm deletion\\n   - Partitions become \\"Unallocated\\"\\n\\n#### Using Diskpart (Command Line Method)\\n\\n```cmd\\n# Open diskpart as administrator\\ndiskpart\\n\\n# List and select disk\\nlist disk\\nselect disk 0\\n\\n# List partitions\\nlist partition\\n\\n# Delete Ubuntu partitions (replace X with partition number)\\nselect partition X\\ndelete partition\\n\\n# Repeat for all Ubuntu partitions\\n```\\n\\n### Step 4: Extend Windows Partition\\n\\n1. **In Disk Management**:\\n   - Right-click Windows C: drive\\n   - Select \\"Extend Volume\\"\\n   - Follow wizard to use unallocated space\\n\\n2. **Alternative using Diskpart**:\\n\\n```cmd\\ndiskpart\\nlist disk\\nselect disk 0\\nlist partition\\nselect partition 2  # Windows partition\\nextend  # Uses all available space\\n```\\n\\n### Step 5: Restore Windows Boot Manager\\n\\n#### Update Boot Configuration\\n\\n```cmd\\n# Open Command Prompt as Administrator\\n\\n# Rebuild BCD store\\nbcdedit /export C:\\\\BCD_Backup\\nbcdboot C:\\\\Windows /s C: /f UEFI\\n\\n# Remove any remaining Ubuntu entries\\nbcdedit /enum firmware\\n# Note the identifier of Ubuntu entries\\nbcdedit /delete {ubuntu-identifier}\\n```\\n\\n#### Verify Boot Configuration\\n\\n```cmd\\n# Check current boot options\\nbcdedit /enum firmware\\n\\n# Set Windows as default\\nbcdedit /default {current}\\n\\n# Set boot timeout\\nbcdedit /timeout 5\\n```\\n\\n## Method 2: Emergency Removal\\n\\nIf Ubuntu is corrupted or unbootable:\\n\\n### Step 1: Boot from Windows Recovery\\n\\n1. **Create Windows Recovery Drive** (if not already available)\\n2. **Boot from recovery media**\\n3. **Access Command Prompt** from recovery options\\n\\n### Step 2: Emergency EFI Cleanup\\n\\n```cmd\\n# In recovery command prompt\\ndiskpart\\nlist disk\\nselect disk 0\\nlist partition\\nselect partition 1  # EFI partition\\nassign letter=Z\\nexit\\n\\n# Navigate and delete Ubuntu files\\nZ:\\ncd EFI\\ndir\\nrmdir /s ubuntu\\n\\n# Remove drive letter\\ndiskpart\\nselect disk 0\\nselect partition 1\\nremove letter=Z\\nexit\\n```\\n\\n### Step 3: Repair Windows Boot\\n\\n```cmd\\n# Repair Windows boot files\\nbootrec /fixmbr\\nbootrec /fixboot\\nbootrec /scanos\\nbootrec /rebuildbcd\\n\\n# Alternative method\\nbcdboot C:\\\\Windows /s C: /f UEFI\\n```\\n\\n## Advanced Scenarios\\n\\n### Multiple Linux Distributions\\n\\nIf you have multiple Linux distributions:\\n\\n```cmd\\n# List all EFI entries\\nbcdedit /enum firmware\\n\\n# Remove specific entries\\nbcdedit /delete {linux-entry-id}\\n\\n# In EFI partition, check folders\\nZ:\\\\EFI\\\\\\n\u251C\u2500\u2500 Microsoft\\\\\\n\u251C\u2500\u2500 ubuntu\\\\\\n\u251C\u2500\u2500 fedora\\\\\\n\u2514\u2500\u2500 arch\\\\\\n```\\n\\n### Encrypted Ubuntu Installation\\n\\nFor encrypted Ubuntu (LUKS):\\n\\n1. **Ubuntu partitions may not be visible in Windows**\\n2. **Use Linux live USB to decrypt and backup data first**\\n3. **Proceed with normal removal steps**\\n4. **Encrypted partitions appear as regular partitions to Windows**\\n\\n### Custom GRUB Configuration\\n\\nIf GRUB was customized:\\n\\n```cmd\\n# Check for custom boot entries\\nbcdedit /enum all\\n\\n# Remove custom entries\\nbcdedit /delete {custom-id}\\n\\n# Reset to Windows default\\nbcdedit /set {fwbootmgr} displayorder {bootmgr}\\n```\\n\\n## Troubleshooting\\n\\n### Boot Issues After Removal\\n\\n#### System Won\'t Boot\\n\\n**Solution 1: Windows Recovery**\\n```cmd\\n# Boot from Windows installation media\\n# Choose \\"Repair your computer\\"\\n# Select \\"Troubleshoot\\" \u2192 \\"Advanced options\\" \u2192 \\"Command Prompt\\"\\n\\nbootrec /fixmbr\\nbootrec /fixboot\\nbootrec /rebuildbcd\\n```\\n\\n**Solution 2: UEFI Boot Repair**\\n```cmd\\n# In recovery command prompt\\nbcdboot C:\\\\Windows /s C: /f UEFI\\n\\n# If EFI partition needs repair\\ndiskpart\\nselect disk 0\\nselect partition 1\\nformat fs=fat32 quick\\nassign letter=Z\\nexit\\n\\nbcdboot C:\\\\Windows /s Z: /f UEFI\\n```\\n\\n#### GRUB Still Appears\\n\\nIf GRUB bootloader still appears:\\n\\n```cmd\\n# Check EFI boot order\\nbcdedit /enum firmware\\n\\n# Set Windows as first boot option\\nbcdedit /set {fwbootmgr} displayorder {bootmgr} {other-entries}\\n\\n# Access BIOS/UEFI settings\\n# Set Windows Boot Manager as first boot option\\n```\\n\\n### Partition Issues\\n\\n#### Can\'t Delete Ubuntu Partitions\\n\\n**Possible causes:**\\n- Partitions are mounted or in use\\n- System protection is enabled\\n- Third-party software interference\\n\\n**Solutions:**\\n```cmd\\n# Force delete in diskpart\\ndiskpart\\nselect disk 0\\nselect partition X\\ninactive  # If partition is active\\ndelete partition override\\n\\n# Use third-party tools if needed\\n# - GParted Live USB\\n# - EaseUS Partition Master\\n# - MiniTool Partition Wizard\\n```\\n\\n#### Unallocated Space Can\'t Be Extended\\n\\n**Common issue:** Unallocated space not adjacent to Windows partition\\n\\n**Solution:**\\n1. Use third-party partition manager\\n2. Move partitions to make space adjacent\\n3. Then extend Windows partition\\n\\n### Data Recovery\\n\\n#### Accidentally Deleted Wrong Partition\\n\\n**Immediate actions:**\\n1. **Stop using the computer immediately**\\n2. **Boot from external media only**\\n3. **Use data recovery tools:**\\n   - TestDisk & PhotoRec\\n   - R-Studio\\n   - Recuva\\n\\n```bash\\n# Using TestDisk (from Linux Live USB)\\nsudo apt install testdisk\\nsudo testdisk\\n\\n# Follow prompts to recover partition table\\n```\\n\\n## Verification and Cleanup\\n\\n### Verify Complete Removal\\n\\n1. **Check Disk Management**:\\n   - No unrecognized partitions\\n   - All space allocated to Windows\\n\\n2. **Check Boot Configuration**:\\n   ```cmd\\n   bcdedit /enum firmware\\n   # Should only show Windows entries\\n   ```\\n\\n3. **Check EFI Partition**:\\n   ```cmd\\n   # Temporarily assign drive letter\\n   diskpart\\n   select disk 0\\n   select partition 1\\n   assign letter=Z\\n   \\n   # Check EFI folder contents\\n   dir Z:\\\\EFI\\\\\\n   # Should only contain Microsoft and Boot folders\\n   \\n   # Remove drive letter\\n   remove letter=Z\\n   ```\\n\\n### System Optimization\\n\\nAfter removal:\\n\\n1. **Run Disk Cleanup**:\\n   - Remove temporary files\\n   - Clean system files\\n\\n2. **Defragment Hard Drive** (if using HDD):\\n   ```cmd\\n   defrag C: /O\\n   ```\\n\\n3. **Check System Files**:\\n   ```cmd\\n   sfc /scannow\\n   DISM /Online /Cleanup-Image /RestoreHealth\\n   ```\\n\\n### Update System\\n\\n```cmd\\n# Check for Windows updates\\n# Settings \u2192 Update & Security \u2192 Windows Update\\n\\n# Update drivers\\n# Device Manager \u2192 Check for hardware changes\\n```\\n\\n## Prevention and Best Practices\\n\\n### Before Installing Linux Again\\n\\n1. **Use Virtual Machines** for testing:\\n   - VMware Workstation\\n   - VirtualBox\\n   - Hyper-V\\n\\n2. **Use Windows Subsystem for Linux (WSL)**:\\n   ```cmd\\n   wsl --install\\n   wsl --install -d Ubuntu\\n   ```\\n\\n3. **Use portable Linux**:\\n   - Live USB with persistence\\n   - Portable installations\\n\\n### Backup Strategies\\n\\n1. **Regular System Images**:\\n   ```cmd\\n   # Create system image\\n   wbadmin start backup -backupTarget:E: -include:C: -allCritical\\n   ```\\n\\n2. **EFI Partition Backup**:\\n   ```cmd\\n   # Backup EFI partition\\n   xcopy Z:\\\\EFI\\\\ E:\\\\EFI_Backup\\\\ /E /H /C /I\\n   ```\\n\\n### Documentation\\n\\nKeep records of:\\n- Partition layouts before changes\\n- Boot configuration exports\\n- Installation procedures used\\n- Custom configurations applied\\n\\n## Alternative Solutions\\n\\n### Keep Ubuntu in Virtual Machine\\n\\nInstead of dual-boot, consider:\\n\\n```bash\\n# Install VirtualBox\\n# Download Ubuntu ISO\\n# Create VM with adequate resources:\\n# - 4GB+ RAM\\n# - 20GB+ storage\\n# - Enable virtualization features\\n```\\n\\n### Windows Subsystem for Linux\\n\\nFor development needs:\\n\\n```cmd\\n# Enable WSL feature\\ndism.exe /online /enable-feature /featurename:Microsoft-Windows-Subsystem-Linux /all /norestart\\n\\n# Install Ubuntu\\nwsl --install -d Ubuntu-22.04\\n\\n# Access Ubuntu\\nwsl\\n```\\n\\n### Portable Linux Solutions\\n\\n- **Ventoy**: Multi-boot USB with multiple ISOs\\n- **Rufus**: Create persistent live USBs\\n- **Universal USB Installer**: Easy Linux USB creation\\n\\n## Resources and References\\n\\n- [Microsoft Diskpart Documentation](https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/diskpart)\\n- [Windows Boot Configuration](https://docs.microsoft.com/en-us/windows-hardware/drivers/devtest/bcd-boot-options-reference)\\n- [UEFI Boot Process](https://uefi.org/specifications)\\n- [TestDisk Data Recovery](https://www.cgsecurity.org/wiki/TestDisk)\\n\\n:::tip[Safety First]\\n- Always backup important data before modifying partitions\\n- Create Windows recovery media before starting\\n- Test the process on a virtual machine first if possible\\n- Keep Linux live USB available for emergency data recovery\\n:::\\n\\n:::warning[Critical Points]\\n- Never delete partitions without confirming their contents\\n- Always assign temporary drive letters to access EFI partitions safely\\n- Remove drive letter assignments after completing tasks\\n- Verify Windows boots correctly before considering the process complete\\n:::\\n\\n:::info[Quick Recovery]\\nIf something goes wrong:\\n1. Boot from Windows installation media\\n2. Choose \\"Repair your computer\\"\\n3. Use Command Prompt to run `bootrec /rebuildbcd`\\n4. Restore from system backup if available\\n:::"},{"id":"x-server-setup","metadata":{"permalink":"/blog/x-server-setup","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/x-server-setup.md","source":"@site/blog/linux/x-server-setup.md","title":"Run Linux GUI Apps on Windows via SSH","description":"Display remote Linux GUI applications (RViz, Gazebo, VS Code) on Windows using VcXsrv/Xming X Server","date":"2024-06-18T00:00:00.000Z","tags":[{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"},{"inline":false,"label":"Windows","permalink":"/blog/tags/windows","description":"Microsoft Windows operating system"},{"inline":false,"label":"SSH","permalink":"/blog/tags/ssh","description":"Secure Shell protocol"},{"inline":false,"label":"X Server","permalink":"/blog/tags/x-server","description":"X Window System server"},{"inline":false,"label":"Remote Development","permalink":"/blog/tags/remote-development","description":"Remote development environments"},{"inline":false,"label":"GUI","permalink":"/blog/tags/gui","description":"Graphical User Interface"}],"readingTime":7.13,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Run Linux GUI Apps on Windows via SSH","description":"Display remote Linux GUI applications (RViz, Gazebo, VS Code) on Windows using VcXsrv/Xming X Server","slug":"x-server-setup","authors":"youkoutaku","date":"2024-06-18T00:00:00.000Z","tags":["linux","windows","ssh","x-server","remote-development","gui"],"keywords":["x server","wsl","windows","linux","gui","vcxsrv","xming","ssh"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Safely Remove Ubuntu from Windows Dual-Boot - Complete UEFI & GRUB Cleanup","permalink":"/blog/remove-ubuntu-dual-boot"},"nextItem":{"title":"Configure Static IP Address on Ubuntu with Netplan","permalink":"/blog/ubuntu-static-ip-setup"}},"content":"When working on remote development via SSH, you sometimes need a graphical user interface (GUI). This guide explains how to set up and use an X server on Windows to run graphical Linux applications remotely via SSH, perfect for scenarios like using ROS with VS Code on a Windows machine while connecting to a Linux host.\\n\\n![X Server SSH Setup](https://docs.microsoft.com/en-us/windows/wsl/media/x11-architecture.png)\\n\\n## Overview\\n\\nX11 forwarding allows you to run graphical applications on a remote Linux machine and display them on your local Windows desktop. This is particularly useful for:\\n\\n- Remote development with GUI tools\\n- Running ROS applications with visualization (RViz, Gazebo)\\n- Using Linux-specific GUI applications from Windows\\n- Docker containers with GUI applications\\n\\n{/* truncate */}\\n\\n## 1. Install X Server for Windows\\n\\n### Option 1: VcXsrv (Recommended)\\n\\nDownload and install **VcXsrv**, a popular and reliable X Server for Windows:\\n\\n[Download VcXsrv Windows X Server](https://sourceforge.net/projects/vcxsrv/)\\n\\n**Installation steps:**\\n1. Download the installer from SourceForge\\n2. Run the installer with administrator privileges\\n3. Follow the installation wizard with default settings\\n4. VcXsrv will be installed and available in your Start Menu\\n\\n### Option 2: Xming\\n\\nAlternative X Server option:\\n\\n[Download Xming](http://www.straightrunning.com/XmingNotes/)\\n\\n### Option 3: X410 (Microsoft Store)\\n\\nCommercial option available in Microsoft Store with enhanced features and support.\\n\\n## 2. Configure and Start VcXsrv\\n\\n### 2.1 Launch VcXsrv\\n\\n1. Open **VcXsrv** from the Start Menu (search for \\"VcXsrv\\")\\n2. You\'ll see the \\"XLaunch\\" configuration wizard\\n\\n### 2.2 Configuration Steps\\n\\n**Step 1: Display Settings**\\n- Select \\"Multiple windows\\"\\n- Display number: `0` (default)\\n- Click \\"Next\\"\\n\\n**Step 2: Client startup**\\n- Select \\"Start no client\\"\\n- Click \\"Next\\"\\n\\n**Step 3: Extra Settings**\\n- \u2705 Check \\"Clipboard\\" (enables clipboard sharing)\\n- \u2705 Check \\"Primary Selection\\" (additional clipboard support)\\n- \u2705 Check \\"Native opengl\\" (better graphics performance)\\n- \u2705 **Important:** Check \\"Disable access control\\" (allows connections)\\n- Additional Parameters: `-ac -multiwindow`\\n- Click \\"Next\\"\\n\\n**Step 4: Finish Configuration**\\n- Optionally save the configuration for future use\\n- Click \\"Finish\\"\\n\\n### 2.3 Verify VcXsrv is Running\\n\\n- Check the system tray for the VcXsrv icon\\n- The X Server should now be listening on port 6000\\n\\n:::warning[Security Note]\\nDisabling access control allows any machine to connect to your X server. Only use this in trusted network environments. For production environments, consider using specific host access controls.\\n:::\\n\\n## 3. Configure Windows Firewall\\n\\n### 3.1 Allow VcXsrv Through Firewall\\n\\n```powershell\\n# Open PowerShell as Administrator and run:\\nNew-NetFirewallRule -DisplayName \\"VcXsrv\\" -Direction Inbound -Program \\"C:\\\\Program Files\\\\VcXsrv\\\\vcxsrv.exe\\" -Action Allow\\n```\\n\\n### 3.2 Alternative: Manual Firewall Configuration\\n\\n1. Open Windows Defender Firewall\\n2. Click \\"Allow an app or feature through Windows Defender Firewall\\"\\n3. Click \\"Change Settings\\" \u2192 \\"Allow another app\\"\\n4. Browse to `C:\\\\Program Files\\\\VcXsrv\\\\vcxsrv.exe`\\n5. Add and enable for both Private and Public networks\\n\\n## 4. Connect to Linux Host via SSH\\n\\n### 4.1 Basic X11 Forwarding\\n\\nConnect to your Linux machine with X11 forwarding enabled:\\n\\n```bash\\n# Basic X11 forwarding\\nssh -X username@host_ip_address\\n\\n# Trusted X11 forwarding (faster, less secure)\\nssh -Y username@host_ip_address\\n\\n# With compression for better performance over slow connections\\nssh -XC username@host_ip_address\\n```\\n\\n### 4.2 Advanced SSH Configuration\\n\\nCreate or edit `~/.ssh/config` on your Windows machine:\\n\\n```\\nHost mylinuxserver\\n    HostName 192.168.1.100\\n    User myusername\\n    ForwardX11 yes\\n    ForwardX11Trusted yes\\n    Compression yes\\n    CompressionLevel 6\\n```\\n\\nThen connect simply with:\\n```bash\\nssh mylinuxserver\\n```\\n\\n### 4.3 Verify SSH X11 Forwarding\\n\\nAfter connecting, check if X11 forwarding is working:\\n\\n```bash\\n# Check DISPLAY variable\\necho $DISPLAY\\n# Should show something like: localhost:10.0\\n\\n# Test with a simple X application\\nxeyes\\n# or\\nxclock\\n```\\n\\n## 5. Configure Linux Host\\n\\n### 5.1 Set DISPLAY Environment Variable\\n\\nOn the Linux host, set the `DISPLAY` variable to point to your Windows machine:\\n\\n```bash\\n# Get your Windows machine\'s IP address\\nexport DISPLAY=192.168.1.50:0.0\\n\\n# Make it persistent (add to ~/.bashrc)\\necho \\"export DISPLAY=192.168.1.50:0.0\\" >> ~/.bashrc\\n```\\n\\n**Finding your Windows IP address:**\\n```powershell\\n# On Windows Command Prompt or PowerShell\\nipconfig\\n```\\n\\n### 5.2 Configure xhost for Access Control\\n\\n```bash\\n# Allow all connections (less secure)\\nxhost +\\n\\n# Allow specific IP (more secure)\\nxhost +192.168.1.50\\n\\n# Allow specific host\\nxhost +INET:192.168.1.50\\n\\n# Check current access control list\\nxhost\\n```\\n\\n### 5.3 Alternative: Use SSH X11 Forwarding Only\\n\\nIf you prefer not to modify DISPLAY manually, rely on SSH\'s automatic X11 forwarding:\\n\\n```bash\\n# SSH will automatically set DISPLAY variable\\nssh -X username@host\\n\\n# Verify automatic setting\\necho $DISPLAY\\n# Should show: localhost:10.0 or similar\\n```\\n\\n## 6. Test GUI Applications\\n\\n### 6.1 Simple Test Applications\\n\\n```bash\\n# Test with basic X applications\\nxclock &          # Analog clock\\nxeyes &            # Eyes that follow cursor\\nxterm &            # Terminal window\\ngedit &            # Text editor\\n```\\n\\n### 6.2 Advanced Applications\\n\\n```bash\\n# Test with more complex applications\\nfirefox &          # Web browser\\nnautilus &         # File manager\\ngnome-calculator & # Calculator\\n\\n# Development tools\\ncode &             # VS Code (if installed)\\ngeany &            # Code editor\\n```\\n\\n### 6.3 ROS Applications\\n\\n```bash\\n# ROS visualization tools\\nrviz &             # ROS visualization\\nrqt &              # ROS Qt GUI tools\\ngazebo &           # Robot simulation\\n\\n# Check ROS environment\\nroscore &\\nrviz &\\n```\\n\\n## 7. Docker Containers with GUI\\n\\n### 7.1 Basic Docker GUI Setup\\n\\n```bash\\n# Run Docker container with GUI support\\ndocker run -it --rm \\\\\\n  --env DISPLAY=$DISPLAY \\\\\\n  --env QT_X11_NO_MITSHM=1 \\\\\\n  --volume /tmp/.X11-unix:/tmp/.X11-unix:rw \\\\\\n  ubuntu:20.04 \\\\\\n  bash\\n```\\n\\n### 7.2 Full Docker GUI Configuration\\n\\n```bash\\n# Complete Docker run command for GUI applications\\ndocker run -it --rm \\\\\\n  --name gui-container \\\\\\n  --env DISPLAY=$DISPLAY \\\\\\n  --env QT_X11_NO_MITSHM=1 \\\\\\n  --env XAUTHORITY=$XAUTHORITY \\\\\\n  --volume /tmp/.X11-unix:/tmp/.X11-unix:rw \\\\\\n  --volume $XAUTHORITY:$XAUTHORITY:rw \\\\\\n  --net=host \\\\\\n  --device /dev/dri \\\\\\n  your_image_name \\\\\\n  bash\\n```\\n\\n**Parameter explanations:**\\n- `--env DISPLAY=$DISPLAY`: Pass display variable to container\\n- `--env QT_X11_NO_MITSHM=1`: Fix Qt shared memory issues\\n- `--volume /tmp/.X11-unix:/tmp/.X11-unix:rw`: Mount X11 socket\\n- `--net=host`: Use host networking (simplifies connection)\\n- `--device /dev/dri`: GPU device access for hardware acceleration\\n\\n### 7.3 Docker Compose for GUI Applications\\n\\n```yaml\\nversion: \'3.8\'\\n\\nservices:\\n  gui-app:\\n    image: your-gui-image\\n    environment:\\n      - DISPLAY=${DISPLAY}\\n      - QT_X11_NO_MITSHM=1\\n    volumes:\\n      - /tmp/.X11-unix:/tmp/.X11-unix:rw\\n    network_mode: host\\n    stdin_open: true\\n    tty: true\\n```\\n\\n## 8. Troubleshooting\\n\\n### 8.1 Common Issues and Solutions\\n\\n#### Issue: \\"Cannot connect to X server\\"\\n\\n**Solutions:**\\n```bash\\n# Check if X server is running on Windows\\n# Restart VcXsrv if necessary\\n\\n# Verify DISPLAY variable\\necho $DISPLAY\\n\\n# Test xhost permissions\\nxhost +\\n\\n# Check SSH X11 forwarding\\nssh -v -X username@host  # Verbose output\\n```\\n\\n#### Issue: Applications appear but don\'t respond\\n\\n**Solutions:**\\n```bash\\n# Add Qt environment variable\\nexport QT_X11_NO_MITSHM=1\\n\\n# Try different window manager settings\\nexport QT_QPA_PLATFORM=xcb\\n```\\n\\n#### Issue: Clipboard not working\\n\\n**Solutions:**\\n- Ensure clipboard options are enabled in VcXsrv configuration\\n- Restart VcXsrv with clipboard support\\n- Use `xclip` for manual clipboard operations:\\n\\n```bash\\n# Install xclip\\nsudo apt install xclip\\n\\n# Copy to clipboard\\necho \\"Hello\\" | xclip -selection clipboard\\n\\n# Paste from clipboard\\nxclip -o -selection clipboard\\n```\\n\\n#### Issue: Poor performance or slow response\\n\\n**Solutions:**\\n```bash\\n# Use SSH compression\\nssh -XC username@host\\n\\n# Reduce color depth in VcXsrv settings\\n# Enable native OpenGL in VcXsrv\\n# Consider using VNC for better performance with complex GUIs\\n```\\n\\n### 8.2 Network Troubleshooting\\n\\n```bash\\n# Test network connectivity\\nping 192.168.1.50\\n\\n# Check if X server port is open\\ntelnet 192.168.1.50 6000\\n\\n# Verify SSH is working\\nssh -v username@host\\n```\\n\\n### 8.3 Debugging X11 Issues\\n\\n```bash\\n# Enable X11 debug output\\nexport DISPLAY=192.168.1.50:0.0\\nxhost +\\nxclock 2>&1 | tee x11-debug.log\\n\\n# Check X11 authentication\\nxauth list\\n\\n# Test basic X functionality\\nxwininfo\\nxdpyinfo\\n```\\n\\n## 9. Performance Optimization\\n\\n### 9.1 Network Optimization\\n\\n```bash\\n# SSH with optimized settings\\nssh -o Compression=yes -o CompressionLevel=6 -X username@host\\n\\n# Use faster SSH ciphers\\nssh -c aes128-ctr -X username@host\\n```\\n\\n### 9.2 VcXsrv Optimization\\n\\n- Enable \\"Native OpenGL\\" for better graphics performance\\n- Use \\"Multiple windows\\" mode for better window management\\n- Adjust DPI settings if applications appear too small/large\\n\\n### 9.3 Application-Specific Optimizations\\n\\n```bash\\n# For Qt applications\\nexport QT_X11_NO_MITSHM=1\\nexport QT_GRAPHICSSYSTEM=native\\n\\n# For GTK applications\\nexport GDK_SYNCHRONIZE=0\\n\\n# For Java applications\\nexport _JAVA_AWT_WM_NONREPARENTING=1\\n```\\n\\n## 10. Security Considerations\\n\\n### 10.1 Secure X11 Configuration\\n\\nInstead of `xhost +`, use specific permissions:\\n\\n```bash\\n# Allow only specific hosts\\nxhost +inet:192.168.1.50\\n\\n# Use xauth for better security\\nxauth add $(xauth -f ~/.Xauthority list | tail -1)\\n\\n# Restrict to localhost only (with SSH forwarding)\\nexport DISPLAY=localhost:10.0\\n```\\n\\n### 10.2 SSH Security\\n\\n```bash\\n# Use key-based authentication\\nssh-keygen -t rsa -b 4096\\nssh-copy-id username@host\\n\\n# Disable password authentication in SSH config\\n# Edit /etc/ssh/sshd_config:\\n# PasswordAuthentication no\\n```\\n\\n### 10.3 Firewall Configuration\\n\\n```bash\\n# Restrict X11 port access\\nsudo ufw allow from 192.168.1.0/24 to any port 6000\\n\\n# Use SSH tunneling instead of direct X11 connection\\nssh -L 6000:localhost:6000 username@host\\n```\\n\\n## Resources\\n\\n- [VcXsrv Official Documentation](https://sourceforge.net/projects/vcxsrv/)\\n- [SSH X11 Forwarding Guide](https://wiki.archlinux.org/title/X11_forwarding)\\n- [Docker GUI Applications](https://docs.docker.com/desktop/windows/wsl/#gpu-support)\\n- [X Window System Documentation](https://www.x.org/wiki/)\\n\\n:::tip[Pro Tips]\\n- Save your VcXsrv configuration for quick startup\\n- Use SSH config files for easy connection management\\n- Consider using Windows Terminal for better SSH experience\\n- Set up key-based authentication for passwordless connections\\n:::\\n\\n:::note[Performance Note]\\nFor intensive GUI applications, consider using VNC or Remote Desktop solutions instead of X11 forwarding for better performance.\\n:::"},{"id":"ubuntu-static-ip-setup","metadata":{"permalink":"/blog/ubuntu-static-ip-setup","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/ubuntu-static-ip-setup.md","source":"@site/blog/linux/ubuntu-static-ip-setup.md","title":"Configure Static IP Address on Ubuntu with Netplan","description":"Set permanent static IP on Ubuntu using netplan YAML configuration for servers and reliable SSH access","date":"2024-06-05T00:00:00.000Z","tags":[{"inline":false,"label":"Ubuntu","permalink":"/blog/tags/ubuntu","description":"Ubuntu Linux operating system"},{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"},{"inline":false,"label":"Networking","permalink":"/blog/tags/networking","description":"Computer networking and protocols"},{"inline":false,"label":"Static IP","permalink":"/blog/tags/static-ip","description":"Static IP address configuration"}],"readingTime":7.94,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Configure Static IP Address on Ubuntu with Netplan","description":"Set permanent static IP on Ubuntu using netplan YAML configuration for servers and reliable SSH access","slug":"ubuntu-static-ip-setup","authors":"youkoutaku","date":"2024-06-05T00:00:00.000Z","tags":["ubuntu","linux","networking","static-ip"],"keywords":["ubuntu","static ip","netplan","networking","network configuration","linux"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Run Linux GUI Apps on Windows via SSH","permalink":"/blog/x-server-setup"},"nextItem":{"title":"\u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\u306B\u3088\u308B\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-recursive-least-squares"}},"content":"This comprehensive guide explains how to configure a static IP address on Ubuntu using the `netplan` configuration system. Setting a static IP is essential for servers, network devices, or any system that requires a consistent network address for reliable connectivity.\\n\\n## Overview\\n\\nStatic IP addresses provide several advantages over dynamic IP assignment:\\n\\n- **Consistent Network Identity**: Same IP address after reboots and network changes\\n- **Server Applications**: Essential for hosting services that clients need to find\\n- **Network Management**: Easier to manage firewall rules and network policies\\n- **Remote Access**: Reliable SSH and remote desktop connections\\n- **Port Forwarding**: Stable configuration for router port forwarding rules\\n\\n## Prerequisites\\n\\n- Ubuntu system with network connectivity\\n- Administrative (sudo) privileges\\n- Basic understanding of network concepts (IP, subnet, gateway)\\n- Access to your network\'s configuration details\\n\\n## Understanding Netplan\\n\\nUbuntu uses **netplan** as the default network configuration system since Ubuntu 18.04. Netplan:\\n\\n- Uses YAML configuration files for network settings\\n- Supports both NetworkManager and systemd-networkd as backends\\n- Provides a unified configuration approach across Ubuntu systems\\n- Validates configuration before applying changes\\n\\n{/* truncate */}\\n\\n## 1. Gather Network Information\\n\\nBefore configuring static IP, collect necessary network information:\\n\\n### 1.1 Identify Network Interface\\n\\n```bash\\n# List all network interfaces\\nip link show\\n\\n# Alternative method\\nls /sys/class/net/\\n```\\n\\nCommon interface names:\\n- **Ethernet**: `eth0`, `enp0s3`, `enp5s0`\\n- **Wireless**: `wlan0`, `wlp2s0`\\n- **Virtual**: `vboxnet0`, `docker0`\\n\\n### 1.2 Check Current Network Configuration\\n\\n```bash\\n# Display current IP configuration\\nip addr show\\n\\n# Show routing table\\nip route show\\n\\n# Check DNS configuration\\nsystemd-resolve --status\\n```\\n\\n### 1.3 Identify Network Details\\n\\nGather the following information:\\n- **Current IP Address**: Your current dynamic IP\\n- **Subnet Mask**: Typically `/24` (255.255.255.0)\\n- **Gateway IP**: Router\'s IP address\\n- **DNS Servers**: Primary and secondary DNS servers\\n\\n```bash\\n# Find gateway (router IP)\\nip route | grep default\\n\\n# Check DNS servers\\ncat /etc/resolv.conf\\n```\\n\\n## 2. Locate Netplan Configuration\\n\\n### 2.1 Find Configuration Files\\n\\n```bash\\n# Navigate to netplan directory\\ncd /etc/netplan/\\n\\n# List configuration files\\nls -la\\n```\\n\\nCommon filenames:\\n- `01-netcfg.yaml`\\n- `00-installer-config.yaml`\\n- `50-cloud-init.yaml`\\n\\n### 2.2 Backup Existing Configuration\\n\\n```bash\\n# Create backup of current configuration\\nsudo cp /etc/netplan/*.yaml /etc/netplan/backup-$(date +%Y%m%d).yaml\\n\\n# Alternative: backup entire directory\\nsudo cp -r /etc/netplan /etc/netplan-backup-$(date +%Y%m%d)\\n```\\n\\n:::warning[Important Backup Note]\\nAlways backup your network configuration before making changes. A misconfigured network can render your system inaccessible remotely.\\n:::\\n\\n## 3. Configure Static IP\\n\\n### 3.1 Edit Configuration File\\n\\nOpen the netplan configuration file:\\n\\n```bash\\n# Replace <filename> with your actual configuration file\\nsudo nano /etc/netplan/<filename>.yaml\\n\\n# Example for common filename\\nsudo nano /etc/netplan/01-netcfg.yaml\\n```\\n\\n### 3.2 Basic Static IP Configuration\\n\\nReplace the file contents with a static IP configuration:\\n\\n```yaml\\nnetwork:\\n  version: 2\\n  renderer: networkd\\n  ethernets:\\n    enp5s0:  # Replace with your interface name\\n      dhcp4: no\\n      dhcp6: no\\n      addresses: [192.168.1.100/24]  # Static IP with subnet mask\\n      routes:\\n        - to: default\\n          via: 192.168.1.1  # Gateway (router) IP\\n      nameservers:\\n        addresses: [8.8.8.8, 8.8.4.4]  # DNS servers\\n```\\n\\n### 3.3 Advanced Configuration Example\\n\\nFor more complex network setups:\\n\\n```yaml\\nnetwork:\\n  version: 2\\n  renderer: networkd\\n  ethernets:\\n    enp5s0:\\n      dhcp4: no\\n      dhcp6: no\\n      addresses: \\n        - 192.168.1.100/24\\n        - 10.0.0.100/16  # Additional IP address\\n      routes:\\n        - to: default\\n          via: 192.168.1.1\\n        - to: 10.0.0.0/16\\n          via: 192.168.1.254  # Specific route\\n      nameservers:\\n        addresses: [8.8.8.8, 8.8.4.4, 1.1.1.1]\\n        search: [local.domain, company.com]  # DNS search domains\\n      optional: true  # Don\'t wait for this interface during boot\\n```\\n\\n### 3.4 Configuration Parameters Explained\\n\\n| Parameter | Description | Example |\\n|-----------|-------------|---------|\\n| `dhcp4: no` | Disable IPv4 DHCP | Required for static IP |\\n| `dhcp6: no` | Disable IPv6 DHCP | Optional, recommended |\\n| `addresses` | Static IP addresses | `[192.168.1.100/24]` |\\n| `routes` | Network routing rules | Gateway and specific routes |\\n| `nameservers` | DNS server configuration | Public or local DNS servers |\\n| `optional` | Interface is optional for boot | `true` or `false` |\\n\\n## 4. Validate and Apply Configuration\\n\\n### 4.1 Validate Configuration Syntax\\n\\n```bash\\n# Check YAML syntax and netplan configuration\\nsudo netplan try\\n\\n# Alternative: generate configuration without applying\\nsudo netplan generate\\n```\\n\\nThe `netplan try` command:\\n- Applies configuration temporarily\\n- Automatically reverts after 120 seconds if not confirmed\\n- Provides safety against network lockout\\n\\n### 4.2 Apply Configuration Permanently\\n\\n```bash\\n# Apply the configuration permanently\\nsudo netplan apply\\n```\\n\\nIf using `netplan try`, you\'ll be prompted to confirm:\\n```\\nDo you want to keep these settings?\\n\\nPress ENTER before the timeout to accept the new configuration\\n\\nChanges will revert in 120 seconds\\n```\\n\\nPress **ENTER** to confirm and make changes permanent.\\n\\n## 5. Verify Configuration\\n\\n### 5.1 Check IP Address Assignment\\n\\n```bash\\n# Display current IP addresses\\nip addr show\\n\\n# Check specific interface\\nip addr show enp5s0\\n```\\n\\nExpected output should show your static IP:\\n```\\n2: enp5s0: <BROADCAST,MULTICAST,UP,LOWER_UP> mtu 1500 qdisc fq_codel state UP\\n    inet 192.168.1.100/24 brd 192.168.1.255 scope global enp5s0\\n```\\n\\n### 5.2 Test Network Connectivity\\n\\n```bash\\n# Test gateway connectivity\\nping -c 4 192.168.1.1\\n\\n# Test internet connectivity\\nping -c 4 8.8.8.8\\n\\n# Test DNS resolution\\nping -c 4 google.com\\n\\n# Check routing table\\nip route show\\n```\\n\\n### 5.3 Verify DNS Configuration\\n\\n```bash\\n# Check DNS resolution\\nnslookup google.com\\n\\n# Alternative DNS test\\ndig google.com\\n\\n# Check systemd-resolved status\\nsystemd-resolve --status\\n```\\n\\n## 6. Troubleshooting\\n\\n### 6.1 Common Issues and Solutions\\n\\n#### Configuration Not Applied\\n\\n```bash\\n# Check netplan status\\nsudo netplan --debug apply\\n\\n# Check systemd-networkd status\\nsudo systemctl status systemd-networkd\\n\\n# Restart networking service\\nsudo systemctl restart systemd-networkd\\n```\\n\\n#### YAML Syntax Errors\\n\\n```bash\\n# Validate YAML syntax\\nsudo netplan try\\n\\n# Check for common issues:\\n# - Incorrect indentation (use spaces, not tabs)\\n# - Missing colons after keys\\n# - Improper list formatting\\n```\\n\\n#### Network Interface Not Found\\n\\n```bash\\n# List all available interfaces\\nip link show\\n\\n# Check if interface is enabled\\nsudo ip link set enp5s0 up\\n\\n# Check kernel messages for hardware issues\\ndmesg | grep -i network\\n```\\n\\n#### IP Address Conflicts\\n\\n```bash\\n# Scan network for IP conflicts\\nsudo nmap -sn 192.168.1.0/24\\n\\n# Check ARP table for duplicates\\narp -a\\n\\n# Use different IP address in same subnet\\n```\\n\\n### 6.2 Revert to DHCP\\n\\nIf you need to revert to automatic IP assignment:\\n\\n```bash\\n# Edit netplan configuration\\nsudo nano /etc/netplan/01-netcfg.yaml\\n```\\n\\nChange configuration to:\\n```yaml\\nnetwork:\\n  version: 2\\n  renderer: networkd\\n  ethernets:\\n    enp5s0:\\n      dhcp4: yes\\n      dhcp6: yes\\n```\\n\\nApply changes:\\n```bash\\nsudo netplan apply\\n```\\n\\n### 6.3 Emergency Recovery\\n\\nIf you lose network connectivity:\\n\\n1. **Physical Access Method**:\\n   ```bash\\n   # Restore from backup\\n   sudo cp /etc/netplan/backup-*.yaml /etc/netplan/01-netcfg.yaml\\n   sudo netplan apply\\n   ```\\n\\n2. **Single User Mode**:\\n   - Boot into recovery mode\\n   - Mount filesystem as read-write\\n   - Edit netplan configuration\\n   - Restart networking\\n\\n## 7. Advanced Configurations\\n\\n### 7.1 Multiple Network Interfaces\\n\\n```yaml\\nnetwork:\\n  version: 2\\n  renderer: networkd\\n  ethernets:\\n    enp5s0:  # Primary interface\\n      dhcp4: no\\n      addresses: [192.168.1.100/24]\\n      routes:\\n        - to: default\\n          via: 192.168.1.1\\n      nameservers:\\n        addresses: [8.8.8.8, 8.8.4.4]\\n    \\n    enp6s0:  # Secondary interface\\n      dhcp4: no\\n      addresses: [10.0.0.100/24]\\n      routes:\\n        - to: 10.0.0.0/8\\n          via: 10.0.0.1\\n```\\n\\n### 7.2 VLAN Configuration\\n\\n```yaml\\nnetwork:\\n  version: 2\\n  renderer: networkd\\n  ethernets:\\n    enp5s0:\\n      dhcp4: no\\n      dhcp6: no\\n  \\n  vlans:\\n    vlan100:\\n      id: 100\\n      link: enp5s0\\n      addresses: [192.168.100.10/24]\\n      routes:\\n        - to: default\\n          via: 192.168.100.1\\n```\\n\\n### 7.3 Bridge Configuration\\n\\n```yaml\\nnetwork:\\n  version: 2\\n  renderer: networkd\\n  ethernets:\\n    enp5s0:\\n      dhcp4: no\\n      dhcp6: no\\n  \\n  bridges:\\n    br0:\\n      interfaces: [enp5s0]\\n      dhcp4: no\\n      addresses: [192.168.1.100/24]\\n      routes:\\n        - to: default\\n          via: 192.168.1.1\\n      nameservers:\\n        addresses: [8.8.8.8, 8.8.4.4]\\n```\\n\\n## 8. Best Practices\\n\\n### 8.1 IP Address Planning\\n\\n1. **Use Private IP Ranges**:\\n   - `192.168.0.0/16` (192.168.0.1 - 192.168.255.254)\\n   - `10.0.0.0/8` (10.0.0.1 - 10.255.255.254)\\n   - `172.16.0.0/12` (172.16.0.1 - 172.31.255.254)\\n\\n2. **Avoid Conflicts**:\\n   - Check existing DHCP range\\n   - Document assigned static IPs\\n   - Use higher IP ranges for static assignments\\n\\n3. **Network Segmentation**:\\n   - Separate static IPs by function\\n   - Use different subnets for different services\\n\\n### 8.2 Security Considerations\\n\\n```bash\\n# Disable unused network interfaces\\nsudo ip link set down <interface_name>\\n\\n# Configure firewall for static IP\\nsudo ufw allow from 192.168.1.0/24\\nsudo ufw deny from 0.0.0.0/0\\n```\\n\\n### 8.3 Documentation and Monitoring\\n\\n1. **Document Configuration**:\\n   - Keep network diagram updated\\n   - Document IP assignments\\n   - Note configuration changes\\n\\n2. **Monitor Network Status**:\\n   ```bash\\n   # Create monitoring script\\n   #!/bin/bash\\n   echo \\"Network Status Check - $(date)\\"\\n   echo \\"================================\\"\\n   ip addr show\\n   echo \\"================================\\"\\n   ip route show\\n   echo \\"================================\\"\\n   ping -c 1 8.8.8.8 >/dev/null && echo \\"Internet: OK\\" || echo \\"Internet: FAIL\\"\\n   ```\\n\\n## 9. Integration with Other Services\\n\\n### 9.1 SSH Server Configuration\\n\\nFor systems with static IP and SSH:\\n\\n```bash\\n# Edit SSH configuration\\nsudo nano /etc/ssh/sshd_config\\n\\n# Add specific interface binding\\nListenAddress 192.168.1.100\\n\\n# Restart SSH service\\nsudo systemctl restart ssh\\n```\\n\\n### 9.2 Web Server Configuration\\n\\nConfigure web servers to bind to static IP:\\n\\n```bash\\n# Apache virtual host\\n<VirtualHost 192.168.1.100:80>\\n    ServerName myserver.local\\n    DocumentRoot /var/www/html\\n</VirtualHost>\\n\\n# Nginx server block\\nserver {\\n    listen 192.168.1.100:80;\\n    server_name myserver.local;\\n    root /var/www/html;\\n}\\n```\\n\\n## 10. Automation and Scripting\\n\\n### 10.1 Automated Configuration Script\\n\\n```bash\\n#!/bin/bash\\n# Static IP configuration script\\n\\nINTERFACE=\\"enp5s0\\"\\nSTATIC_IP=\\"192.168.1.100/24\\"\\nGATEWAY=\\"192.168.1.1\\"\\nDNS_SERVERS=\\"8.8.8.8,8.8.4.4\\"\\n\\n# Create netplan configuration\\ncat > /etc/netplan/01-static-ip.yaml << EOF\\nnetwork:\\n  version: 2\\n  renderer: networkd\\n  ethernets:\\n    ${INTERFACE}:\\n      dhcp4: no\\n      dhcp6: no\\n      addresses: [${STATIC_IP}]\\n      routes:\\n        - to: default\\n          via: ${GATEWAY}\\n      nameservers:\\n        addresses: [${DNS_SERVERS}]\\nEOF\\n\\n# Apply configuration\\nnetplan apply\\n\\necho \\"Static IP ${STATIC_IP} configured for ${INTERFACE}\\"\\n```\\n\\n### 10.2 Configuration Validation Script\\n\\n```bash\\n#!/bin/bash\\n# Network configuration validation\\n\\necho \\"Validating network configuration...\\"\\n\\n# Check interface status\\nif ip link show $INTERFACE &>/dev/null; then\\n    echo \\"\u2713 Interface $INTERFACE exists\\"\\nelse\\n    echo \\"\u2717 Interface $INTERFACE not found\\"\\n    exit 1\\nfi\\n\\n# Check IP assignment\\nif ip addr show $INTERFACE | grep -q \\"inet $STATIC_IP\\"; then\\n    echo \\"\u2713 Static IP assigned correctly\\"\\nelse\\n    echo \\"\u2717 Static IP not assigned\\"\\nfi\\n\\n# Check gateway connectivity\\nif ping -c 1 $GATEWAY &>/dev/null; then\\n    echo \\"\u2713 Gateway reachable\\"\\nelse\\n    echo \\"\u2717 Gateway unreachable\\"\\nfi\\n\\n# Check internet connectivity\\nif ping -c 1 8.8.8.8 &>/dev/null; then\\n    echo \\"\u2713 Internet connectivity\\"\\nelse\\n    echo \\"\u2717 No internet connectivity\\"\\nfi\\n```\\n\\n## Resources and References\\n\\n- [Ubuntu Netplan Documentation](https://netplan.io/)\\n- [Ubuntu Server Guide - Network Configuration](https://ubuntu.com/server/docs/network-configuration)\\n- [Netplan Examples](https://netplan.io/examples/)\\n- [systemd-networkd Documentation](https://www.freedesktop.org/software/systemd/man/systemd-networkd.service.html)\\n\\n:::tip[Pro Tips]\\n- Always test configuration with `netplan try` before permanent application\\n- Keep backup of working configuration files\\n- Document your network setup for future reference\\n- Use consistent IP addressing scheme across your network\\n- Consider using configuration management tools for multiple servers\\n:::\\n\\n:::warning[Security Note]\\nStatic IP addresses are more visible on the network. Ensure proper firewall configuration and security hardening for systems with static IPs.\\n:::"},{"id":"simulation-recursive-least-squares","metadata":{"permalink":"/blog/simulation-recursive-least-squares","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/matlab/simulation-recursive-least-squares.md","source":"@site/blog/matlab/simulation-recursive-least-squares.md","title":"\u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\u306B\u3088\u308B\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","description":"\u3053\u306E\u6587\u66F8\u3067\u306F\u3001\u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\uFF08Recursive Least Squares, RLS\uFF09\u3092\u7528\u3044\u305F\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u306B\u3064\u3044\u3066\u8A73\u3057\u304F\u8AAC\u660E\u3057\u307E\u3059\u30022\u6B21\u7DDA\u5F62\u30B7\u30B9\u30C6\u30E0\u306E\u30D1\u30E9\u30E1\u30FC\u30BF\u63A8\u5B9A\u3001\u6642\u5909\u30B7\u30B9\u30C6\u30E0\u3001\u304A\u3088\u3073\u88DC\u52A9\u5909\u6570\u6CD5\u3092\u542B\u3080\u5305\u62EC\u7684\u306A\u5206\u6790\u3092\u884C\u3044\u307E\u3059\u3002","date":"2024-06-01T00:00:00.000Z","tags":[{"inline":true,"label":"MATLAB","permalink":"/blog/tags/matlab"},{"inline":true,"label":"simulation","permalink":"/blog/tags/simulation"}],"readingTime":7.05,"hasTruncateMarker":false,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"authors":"youkoutaku","date":"2024-06-01T00:00:00.000Z","slug":"simulation-recursive-least-squares","title":"\u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\u306B\u3088\u308B\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","tags":["MATLAB","simulation"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Configure Static IP Address on Ubuntu with Netplan","permalink":"/blog/ubuntu-static-ip-setup"},"nextItem":{"title":"PID\u5236\u5FA1\u5668\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-pid-control"}},"content":"\u3053\u306E\u6587\u66F8\u3067\u306F\u3001\u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\uFF08Recursive Least Squares, RLS\uFF09\u3092\u7528\u3044\u305F\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u306B\u3064\u3044\u3066\u8A73\u3057\u304F\u8AAC\u660E\u3057\u307E\u3059\u30022\u6B21\u7DDA\u5F62\u30B7\u30B9\u30C6\u30E0\u306E\u30D1\u30E9\u30E1\u30FC\u30BF\u63A8\u5B9A\u3001\u6642\u5909\u30B7\u30B9\u30C6\u30E0\u3001\u304A\u3088\u3073\u88DC\u52A9\u5909\u6570\u6CD5\u3092\u542B\u3080\u5305\u62EC\u7684\u306A\u5206\u6790\u3092\u884C\u3044\u307E\u3059\u3002\\n\\n## 3.5.1 \u540C\u5B9A\u5BFE\u8C61\u30B7\u30B9\u30C6\u30E0\\n\\n2\u6B21\u306E\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u3092\u8003\u3048\u307E\u3059\uFF1A\\n\\n$$\\n\\\\begin{aligned}\\nx_{t} &=-a_1x_{t-1}-a_2x_{t-2}+b_1u_{t-1}+b_2u_{t-2}  \\\\\\\\\\ny_t &=x_t+v_t\\n\\\\end{aligned}\\n$$\\n\\n\u3053\u3053\u3067\u3001\u771F\u306E\u30D1\u30E9\u30E1\u30FC\u30BF\u5024\u306F\uFF1A\\n\\n$$\\na_1=-1.5,\\\\quad a_2=0.7,\\\\quad b_1=1.0, \\\\quad b_2=0.5\\n$$\\n\\n### \u30B7\u30B9\u30C6\u30E0\u7279\u6027\\n\\n- **\u5165\u529B\u4FE1\u53F7**: $[0,1]$ \u306E\u7BC4\u56F2\u3067**\u4E00\u69D8\u5206\u5E03\u3059\u308B\u4E71\u6570**\\n- **\u89B3\u6E2C\u96D1\u97F3**: **\u30BC\u30ED\u5E73\u5747**\u306E\u30AC\u30A6\u30B9\u5206\u5E03\u4E71\u6570\\n- **\u7121\u76F8\u95A2\u6027**: \u96D1\u97F3\u306F**\u5165\u529B\u4FE1\u53F7\u3068\u7121\u76F8\u95A2**\\n\\n:::tip[\u96D1\u97F3\u4FE1\u53F7\u6BD4\uFF08NSR\uFF09]\\n\u96D1\u97F3\u306E\u30EC\u30D9\u30EB\u306F\u96D1\u97F3\u4FE1\u53F7\u6BD4\uFF08Noise Signal Ratio, $NSR$\uFF09\u3067\u8A55\u4FA1\u3055\u308C\u307E\u3059\u3002\\n\\n$$NSR = \\\\frac{\\\\sigma_v}{\\\\sigma_x}$$\\n\\n\u3053\u3053\u3067\u3001$\\\\sigma_v$\u306F\u96D1\u97F3$v_t$\u306E\u6A19\u6E96\u504F\u5DEE\u3001$\\\\sigma_x$\u306F\u771F\u306E\u51FA\u529B\u4FE1\u53F7$x_t$\u306E\u6A19\u6E96\u504F\u5DEE\u3067\u3059\u3002\\n:::\\n\\n## 3.5.2 \u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\u306B\u3088\u308B\u30D1\u30E9\u30E1\u30FC\u30BF\u63A8\u5B9A\\n\\n### \u6570\u5B66\u7684\u5B9A\u5F0F\u5316\\n\\n\u89B3\u6E2C\u65B9\u7A0B\u5F0F\uFF1A\\n$$\\ny_t=-a_1y_{t-1}-a_2y_{t-2}+b_1u_{t-1}+b_2u_{t-2}+r_t\\n$$\\n\\n\u56DE\u5E30\u30D9\u30AF\u30C8\u30EB\uFF1A\\n$$\\nz_t^T=[-y_{t-1},-y_{t-2},u_{t-1},u_{t-2}]\\n$$\\n\\n\u30D1\u30E9\u30E1\u30FC\u30BF\u30D9\u30AF\u30C8\u30EB\uFF1A\\n$$\\n\\\\theta^T=[a_1,a_2,b_1,b_2]\\n$$\\n\\n### \u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u8A2D\u5B9A\\n\\n- **\u30C7\u30FC\u30BF\u9577**: $N = 3000$\uFF08\u5341\u5206\u5927\u304D\u306A\u6574\u6570\uFF09\\n- **NSR \u30EC\u30D9\u30EB**: 0%, 10%, 20%\\n- **\u76EE\u7684**: \u5404NSR\u30EC\u30D9\u30EB\u3067\u306E\u30D1\u30E9\u30E1\u30FC\u30BF\u63A8\u5B9A\u6027\u80FD\u306E\u6BD4\u8F03\\n\\n### MATLAB\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u30B3\u30FC\u30C9\\n\\n```matlab\\nclear\\nclose all\\nset(0,\'DefaultAxesFontName\',\'Times New Roman\')\\nset(0,\'DefaultAxesFontSize\',22)\\n\\n% \u30D1\u30E9\u30E1\u30FC\u30BF\u8A2D\u5B9A\\nN = 3000;\\nrand(\'seed\',1);\\n\\n% \u771F\u306E\u30D1\u30E9\u30E1\u30FC\u30BF\\na1 = -1.5; a2 = 0.7; b1 = 1.0; b2 = 0.5;\\n\\n% \u521D\u671F\u5316\\nt = zeros(1, N+1);\\nu = rand(1, N+1);\\nx = zeros(1, N+1);\\ntheta1_hat = zeros(4,N+1); % NSR=0\\ntheta2_hat = zeros(4,N+1); % NSR=0.1\\ntheta3_hat = zeros(4,N+1); % NSR=0.2\\nalpha = 1000;\\nrho = 0.95*ones(1, N+1);\\n\\n% \u30B7\u30B9\u30C6\u30E0\u5FDC\u7B54\u751F\u6210\\nfor k=3:N+1\\n    t(k) = k-1;\\n    x(k) = -a1*x(k-1)-a2*x(k-2)+b1*u(k-1)+b2*u(k-2);\\nend\\n\\n% \u5404NSR\u30EC\u30D9\u30EB\u3067\u306E\u63A8\u5B9A\\nfor NSR = 0:0.1:0.2\\n    % \u30AC\u30A6\u30B9\u96D1\u97F3\u751F\u6210\\n    mu = 0;\\n    sigma = NSR*std(x);\\n    v = sigma*randn(1,N+1) + mu;\\n    \\n    % \u89B3\u6E2C\u4FE1\u53F7\\n    y = x + v;\\n    \\n    % \u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\\n    for k=3:N+1\\n        z(:,k) = [-y(k-1),-y(k-2),u(k-1),u(k-2)]\';\\n        \\n        % \u5FD8\u5374\u4FC2\u6570\u66F4\u65B0\\n        rho(k) = (1-0.01)*rho(k-1)+0.01;\\n        \\n        % \u5171\u5206\u6563\u884C\u5217\u66F4\u65B0\\n        P(:,:,k) = (P(:,:,k-1) - (P(:,:,k-1)*psi(:,k)*phi(:,k)\'*P(:,:,k-1))/(rho(k) + phi(:,k)\'*P(:,:,k-1)*psi(:,k)))/rho(k);\\n        \\n        % \u30B2\u30A4\u30F3\u30D9\u30AF\u30C8\u30EB\\n        L(:,k) = (P(:,:,k-1)*psi(:,k))/(rho(k) + phi(:,k)\'*P(:,:,k-1)*psi(:,k));\\n        \\n        % \u4E88\u6E2C\u8AA4\u5DEE\\n        E(k) = y(k) - phi(:,k)\'*theta_hat(:,k-1);\\n        \\n        % \u30D1\u30E9\u30E1\u30FC\u30BF\u66F4\u65B0\\n        theta_hat(:,k) = theta_hat(:,k-1) + L(:,k)*E(k);\\n    end\\nend\\n```\\n\\n## 3.5.3 \u6642\u5909\u30B7\u30B9\u30C6\u30E0\u306E\u30D1\u30E9\u30E1\u30FC\u30BF\u63A8\u5B9A\\n\\n### \u6642\u5909\u30B7\u30B9\u30C6\u30E0\u30E2\u30C7\u30EB\\n\\n2\u6B21\u306E\u6642\u5909\u30B7\u30B9\u30C6\u30E0\uFF1A\\n\\n$$\\n\\\\begin{aligned}\\n&x_t = -a_{1,t}x_{t-1}-a_{2,t}x_{t-2}+b_{1,t}u_{t-1}+b_{2,t}u_{t-2}  \\\\\\\\\\n&y_t = x_t+v_t\\n\\\\end{aligned}\\n$$\\n\\n\u6642\u5909\u30D1\u30E9\u30E1\u30FC\u30BF\uFF1A\\n\\n$$\\n\\\\begin{aligned}\\na_{1,t} &= -1.0+0.5\\\\sin(2\\\\pi t/2000)  \\\\\\\\\\na_{2,t} &= 0.7  \\\\\\\\\\nb_{1,t} &= 1.0  \\\\\\\\\\nb_{2,t} &= 0.5+0.4\\\\cos(2\\\\pi t/2000)\\n\\\\end{aligned}\\n$$\\n\\n### \u6642\u5909\u30D1\u30E9\u30E1\u30FC\u30BF\u63A8\u5B9A\u306E\u7279\u5FB4\\n\\n1. **\u8FFD\u5F93\u6027\u80FD**: \u5FD8\u5374\u4FC2\u6570\u306B\u3088\u308A\u904E\u53BB\u306E\u30C7\u30FC\u30BF\u306E\u5F71\u97FF\u3092\u6E1B\u8870\\n2. **\u9069\u5FDC\u80FD\u529B**: \u30D1\u30E9\u30E1\u30FC\u30BF\u5909\u5316\u306B\u5BFE\u3059\u308B\u8FFD\u5F93\u901F\u5EA6\\n3. **\u96D1\u97F3\u611F\u5EA6**: \u6642\u5909\u30B7\u30B9\u30C6\u30E0\u3067\u306F\u96D1\u97F3\u306E\u5F71\u97FF\u304C\u3088\u308A\u9855\u8457\\n\\n### MATLAB\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\uFF08\u6642\u5909\u30B7\u30B9\u30C6\u30E0\uFF09\\n\\n```matlab\\n% \u6642\u5909\u30D1\u30E9\u30E1\u30FC\u30BF\u751F\u6210\\nfor k=1:N+1\\n    a1(k) = -1.0 + 0.5*sin(2*pi*k/2000);\\n    a2(k) = 0.7;\\n    b1(k) = 1.0;\\n    b2(k) = 0.5 + 0.4*cos(2*pi*k/2000);\\nend\\n\\n% \u6642\u5909\u30B7\u30B9\u30C6\u30E0\u5FDC\u7B54\\nfor k=3:N+1\\n    x(k) = -a1(k-1)*x(k-1)-a2(k-2)*x(k-2)+b1(k-1)*u(k-1)+b2(k-2)*u(k-2);\\nend\\n\\n% \u9010\u6B21\u63A8\u5B9A\uFF08\u5FD8\u5374\u4FC2\u6570 = 0.98\uFF09\\nfor k=3:N+1\\n    rho(k) = 0.98; % \u56FA\u5B9A\u5FD8\u5374\u4FC2\u6570\\n    % [\u63A8\u5B9A\u30A2\u30EB\u30B4\u30EA\u30BA\u30E0\u306F\u4E0A\u8A18\u3068\u540C\u69D8]\\nend\\n```\\n\\n## 3.5.4 \u9010\u6B21\u88DC\u52A9\u5909\u6570\u6CD5\u306B\u3088\u308B\u30D1\u30E9\u30E1\u30FC\u30BF\u63A8\u5B9A\\n\\n\u88DC\u52A9\u5909\u6570\u6CD5\u306F\u3001\u96D1\u97F3\u3068\u56DE\u5E30\u30D9\u30AF\u30C8\u30EB\u306E\u76F8\u95A2\u3092\u9664\u53BB\u3059\u308B\u3053\u3068\u3067\u3088\u308A\u6B63\u78BA\u306A\u63A8\u5B9A\u3092\u5B9F\u73FE\u3057\u307E\u3059\u3002\\n\\n### \u65B9\u6CD51: \u9045\u5EF6\u3055\u308C\u305F\u5165\u529B\u3092\u88DC\u52A9\u5909\u6570\u3068\u3059\u308B\\n\\n\u88DC\u52A9\u5909\u6570\u30D9\u30AF\u30C8\u30EB\uFF1A\\n$$\\nm_t = [u_{t-1-d}, u_{t-2-d}, u_{t-1}, u_{t-2}]^T\\n$$\\n\\n\u3053\u3053\u3067\u3001$d \\\\geq n$\uFF08$n$\u306F\u30B7\u30B9\u30C6\u30E0\u6B21\u6570\uFF09\u306E\u9045\u5EF6\u3092\u8A2D\u3051\u307E\u3059\u3002\\n\\n### MATLAB\u30B3\u30FC\u30C9\uFF08\u9045\u5EF6\u5165\u529B\uFF09\\n\\n```matlab\\nd = 2; % \u9045\u5EF6\u30D1\u30E9\u30E1\u30FC\u30BF\\n\\n% \u9045\u5EF6\u3055\u308C\u305F\u5165\u529B\u306E\u8A2D\u5B9A\\nfor k=3+d:N+1\\n    m(:,k) = [u(k-1-d), u(k-2-d), u(k-1), u(k-2)]\';\\nend\\n\\n% \u88DC\u52A9\u5909\u6570\u6CD5\u63A8\u5B9A\\nfor k=3:N+1\\n    phi(:,k) = z(:,k);     % \u56DE\u5E30\u30D9\u30AF\u30C8\u30EB\\n    psi(:,k) = m(:,k);     % \u88DC\u52A9\u5909\u6570\u30D9\u30AF\u30C8\u30EB\\n    \\n    % \u5171\u5206\u6563\u884C\u5217\u66F4\u65B0\\n    P(:,:,k) = (P(:,:,k-1) - (P(:,:,k-1)*psi(:,k)*phi(:,k)\'*P(:,:,k-1))/(rho(k) + phi(:,k)\'*P(:,:,k-1)*psi(:,k)))/rho(k);\\n    \\n    % \u30D1\u30E9\u30E1\u30FC\u30BF\u66F4\u65B0\\n    L(:,k) = (P(:,:,k-1)*psi(:,k))/(rho(k) + phi(:,k)\'*P(:,:,k-1)*psi(:,k));\\n    E(k) = y(k) - phi(:,k)\'*theta_hat(:,k-1);\\n    theta_hat(:,k) = theta_hat(:,k-1) + L(:,k)*E(k);\\nend\\n```\\n\\n### \u65B9\u6CD52: \u9045\u5EF6\u3055\u308C\u305F\u51FA\u529B\u3092\u88DC\u52A9\u5909\u6570\u3068\u3059\u308B\\n\\n\u88DC\u52A9\u5909\u6570\u30D9\u30AF\u30C8\u30EB\uFF1A\\n$$\\nm_t = [y_{t-1-d}, y_{t-2-d}, u_{t-1}, u_{t-2}]^T\\n$$\\n\\n### \u65B9\u6CD53: \u63A8\u5B9A\u3055\u308C\u305F\u51FA\u529B\u3092\u88DC\u52A9\u5909\u6570\u3068\u3059\u308B\\n\\n\u3053\u306E\u65B9\u6CD5\u3067\u306F\u3001\u63A8\u5B9A\u3055\u308C\u305F\u30D1\u30E9\u30E1\u30FC\u30BF\u304B\u3089\u51FA\u529B\u3092\u4E88\u6E2C\u3057\u3001\u305D\u308C\u3092\u88DC\u52A9\u5909\u6570\u3068\u3057\u3066\u4F7F\u7528\u3057\u307E\u3059\u3002\\n\\n```matlab\\n% \u5B89\u5B9A\u6027\u30C1\u30A7\u30C3\u30AF\\np = [1 theta_hat(1,k-1) theta_hat(2,k-1)];\\ns = roots(p);\\n\\nif abs(s(1)) < 1 && abs(s(2)) < 1\\n    % \u5B89\u5B9A\u306A\u5834\u5408\\n    bar_a1(k-1) = theta_hat(1,k-1);\\n    bar_a2(k-1) = theta_hat(2,k-1);\\nelse\\n    % \u4E0D\u5B89\u5B9A\u306A\u5834\u5408\u306F\u8ABF\u6574\\n    bar_a1(k-1) = bar_a1(k-2) + 0.5*(theta_hat(1,k-1) - bar_a1(k-2));\\n    bar_a2(k-1) = bar_a2(k-2) + 0.5*(theta_hat(2,k-1) - bar_a2(k-2));\\nend\\n\\n% \u63A8\u5B9A\u51FA\u529B\u8A08\u7B97\\nhat_x(k) = -bar_a1(k-1)*hat_x(k-1) - bar_a2(k-1)*hat_x(k-2) + theta_hat(3,k-1)*u(k-1) + theta_hat(4,k-1)*u(k-2);\\n\\n% \u88DC\u52A9\u5909\u6570\\nm(:,k) = [-hat_x(k-1), -hat_x(k-2), u(k-1), u(k-2)]\';\\n```\\n\\n## \u6027\u80FD\u6BD4\u8F03\u3068\u8003\u5BDF\\n\\n### \u624B\u6CD5\u6BD4\u8F03\u8868\\n\\n| \u624B\u6CD5 | \u5229\u70B9 | \u6B20\u70B9 | \u9069\u7528\u5834\u9762 |\\n|------|------|------|----------|\\n| \u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5 | \u8A08\u7B97\u304C\u7C21\u5358\u3001\u30EA\u30A2\u30EB\u30BF\u30A4\u30E0\u5B9F\u88C5\u5BB9\u6613 | \u96D1\u97F3\u306B\u5BFE\u3059\u308B\u611F\u5EA6\u304C\u9AD8\u3044 | \u4F4E\u96D1\u97F3\u74B0\u5883 |\\n| \u88DC\u52A9\u5909\u6570\u6CD5\uFF08\u9045\u5EF6\u5165\u529B\uFF09 | \u96D1\u97F3\u306E\u5F71\u97FF\u3092\u8EFD\u6E1B | \u9045\u5EF6\u306B\u3088\u308B\u60C5\u5831\u640D\u5931 | \u5165\u529B\u4FE1\u53F7\u304C\u8C4A\u5BCC |\\n| \u88DC\u52A9\u5909\u6570\u6CD5\uFF08\u9045\u5EF6\u51FA\u529B\uFF09 | \u30D0\u30E9\u30F3\u30B9\u306E\u53D6\u308C\u305F\u6027\u80FD | \u5B9F\u88C5\u304C\u3084\u3084\u8907\u96D1 | \u4E00\u822C\u7684\u306A\u5FDC\u7528 |\\n| \u88DC\u52A9\u5909\u6570\u6CD5\uFF08\u63A8\u5B9A\u51FA\u529B\uFF09 | \u6700\u3082\u9AD8\u3044\u63A8\u5B9A\u7CBE\u5EA6 | \u5B89\u5B9A\u6027\u30C1\u30A7\u30C3\u30AF\u304C\u5FC5\u8981 | \u9AD8\u7CBE\u5EA6\u304C\u8981\u6C42\u3055\u308C\u308B\u5834\u9762 |\\n\\n:::tip[\u63A8\u5968\u4E8B\u9805]\\n- **\u4F4E\u96D1\u97F3\u74B0\u5883**: \u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\u3067\u5341\u5206\\n- **\u4E2D\u7A0B\u5EA6\u96D1\u97F3**: \u88DC\u52A9\u5909\u6570\u6CD5\uFF08\u9045\u5EF6\u51FA\u529B\uFF09\u3092\u63A8\u5968\\n- **\u9AD8\u96D1\u97F3\u74B0\u5883**: \u88DC\u52A9\u5909\u6570\u6CD5\uFF08\u63A8\u5B9A\u51FA\u529B\uFF09\u3092\u4F7F\u7528\\n- **\u6642\u5909\u30B7\u30B9\u30C6\u30E0**: \u5FD8\u5374\u4FC2\u6570\u306E\u9069\u5207\u306A\u8ABF\u6574\u304C\u91CD\u8981\\n:::\\n\\n### \u5FD8\u5374\u4FC2\u6570\u306E\u5F71\u97FF\\n\\n\u5FD8\u5374\u4FC2\u6570$\\\\rho$\u306E\u8A2D\u5B9A\u306F\u63A8\u5B9A\u6027\u80FD\u306B\u5927\u304D\u304F\u5F71\u97FF\u3057\u307E\u3059\uFF1A\\n\\n- **$\\\\rho = 1.0$**: \u7406\u60F3\u7684\u3060\u304C\u6570\u5024\u7684\u306B\u4E0D\u5B89\u5B9A\\n- **$\\\\rho = 0.98$**: \u6642\u5909\u30B7\u30B9\u30C6\u30E0\u306B\u9069\u3057\u3066\u3044\u308B\\n- **$\\\\rho = 0.95$**: \u3088\u308A\u9AD8\u3044\u8FFD\u5F93\u6027\u80FD\u3060\u304C\u96D1\u97F3\u306B\u654F\u611F\\n\\n### \u5B9F\u7528\u7684\u8003\u616E\u4E8B\u9805\\n\\n1. **\u521D\u671F\u5024\u8A2D\u5B9A**: $P(0) = \\\\alpha I$\uFF08$\\\\alpha$\u306F\u5927\u304D\u306A\u6B63\u6570\uFF09\\n2. **\u6570\u5024\u5B89\u5B9A\u6027**: \u5B9A\u671F\u7684\u306A\u884C\u5217\u306E\u6761\u4EF6\u6570\u30C1\u30A7\u30C3\u30AF\\n3. **\u8A08\u7B97\u91CF**: \u30EA\u30A2\u30EB\u30BF\u30A4\u30E0\u5B9F\u88C5\u6642\u306ECPU\u8CA0\u8377\u8003\u616E\\n4. **\u30E1\u30E2\u30EA\u4F7F\u7528\u91CF**: \u9577\u6642\u9593\u904B\u8EE2\u6642\u306E\u30E1\u30E2\u30EA\u7BA1\u7406\\n\\n## \u307E\u3068\u3081\\n\\n\u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\u3068\u305D\u306E\u62E1\u5F35\u3067\u3042\u308B\u88DC\u52A9\u5909\u6570\u6CD5\u306F\u3001\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u306B\u304A\u3044\u3066\u5F37\u529B\u306A\u624B\u6CD5\u3067\u3059\u3002\u96D1\u97F3\u30EC\u30D9\u30EB\u3001\u30B7\u30B9\u30C6\u30E0\u306E\u6642\u5909\u6027\u3001\u8A08\u7B97\u8CC7\u6E90\u306A\u3069\u3092\u7DCF\u5408\u7684\u306B\u8003\u616E\u3057\u3066\u6700\u9069\u306A\u624B\u6CD5\u3092\u9078\u629E\u3059\u308B\u3053\u3068\u304C\u91CD\u8981\u3067\u3059\u3002\\n\\n\u5B9F\u969B\u306E\u5FDC\u7528\u3067\u306F\u3001\u8907\u6570\u306E\u624B\u6CD5\u3092\u7D44\u307F\u5408\u308F\u305B\u305F\u30CF\u30A4\u30D6\u30EA\u30C3\u30C9\u30A2\u30D7\u30ED\u30FC\u30C1\u3084\u3001\u9069\u5FDC\u7684\u306B\u624B\u6CD5\u3092\u5207\u308A\u66FF\u3048\u308B\u6226\u7565\u3082\u6709\u52B9\u3067\u3059\u3002"},{"id":"simulation-pid-control","metadata":{"permalink":"/blog/simulation-pid-control","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/matlab/simulation-pid-control.md","source":"@site/blog/matlab/simulation-pid-control.md","title":"PID\u5236\u5FA1\u5668\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","description":"\u524D\u9032\u5DEE\u5206\u3001\u5F8C\u9000\u5DEE\u5206\u3001\u53CC\u4E00\u6B21\u5909\u63DB\u3092\u7528\u3044\u305FPID\u5236\u5FA1\u5668\u306E\u96E2\u6563\u5316\u3068MATLAB\u306B\u3088\u308B\u6570\u5024\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","date":"2024-05-26T00:00:00.000Z","tags":[{"inline":true,"label":"PID\u5236\u5FA1","permalink":"/blog/tags/pid\u5236\u5FA1"},{"inline":true,"label":"MATLAB","permalink":"/blog/tags/matlab"},{"inline":true,"label":"\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/tags/\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3"},{"inline":true,"label":"\u524D\u9032\u5DEE\u5206","permalink":"/blog/tags/\u524D\u9032\u5DEE\u5206"},{"inline":true,"label":"\u5F8C\u9000\u5DEE\u5206","permalink":"/blog/tags/\u5F8C\u9000\u5DEE\u5206"},{"inline":true,"label":"\u53CC\u4E00\u6B21\u5909\u63DB","permalink":"/blog/tags/\u53CC\u4E00\u6B21\u5909\u63DB"},{"inline":true,"label":"\u72B6\u614B\u7A7A\u9593\u8868\u73FE","permalink":"/blog/tags/\u72B6\u614B\u7A7A\u9593\u8868\u73FE"}],"readingTime":8.35,"hasTruncateMarker":false,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"authors":"youkoutaku","date":"2024-05-26T00:00:00.000Z","slug":"simulation-pid-control","title":"PID\u5236\u5FA1\u5668\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","description":"\u524D\u9032\u5DEE\u5206\u3001\u5F8C\u9000\u5DEE\u5206\u3001\u53CC\u4E00\u6B21\u5909\u63DB\u3092\u7528\u3044\u305FPID\u5236\u5FA1\u5668\u306E\u96E2\u6563\u5316\u3068MATLAB\u306B\u3088\u308B\u6570\u5024\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","tags":["PID\u5236\u5FA1","MATLAB","\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","\u524D\u9032\u5DEE\u5206","\u5F8C\u9000\u5DEE\u5206","\u53CC\u4E00\u6B21\u5909\u63DB","\u72B6\u614B\u7A7A\u9593\u8868\u73FE"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"\u9010\u6B21\u6700\u5C0F\u4E8C\u4E57\u6CD5\u306B\u3088\u308B\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-recursive-least-squares"},"nextItem":{"title":"VS Code Remote SSH Setup for Ubuntu Server","permalink":"/blog/ubuntu-ssh-setup"}},"content":"## \u5236\u5FA1\u5BFE\u8C61\\n\\n4\u6B21\u306E\u4F1D\u9054\u95A2\u6570\u3067\u8868\u3055\u308C\u308B\u5236\u5FA1\u5BFE\u8C61\u3092\u8003\u3048\u308B\uFF1A\\n\\n$$\\nG(s)=\\\\frac{12s+8}{20s^4+112s^3+147s^2+62s+8}\\n$$\\n\\n### \u72B6\u614B\u7A7A\u9593\u8868\u73FE\u3078\u306E\u5909\u63DB\\n\\n```matlab\\nnum = [0 0 12 8];\\nden = [20 113 147 62 8];\\nsysg = tf(num, den);                    % \u4F1D\u9054\u95A2\u6570\\n[Ao,Bo,Co,Do] = tf2ss(num,den);        % \u72B6\u614B\u7A7A\u9593\u8868\u73FE\u3078\u306E\u5909\u63DB\\n```\\n\\n## PID\u5236\u5FA1\u5668\\n\\n![PID\u5236\u5FA1\u30D6\u30ED\u30C3\u30AF\u56F3](https://controlabo.com/wp-content/uploads/2022/11/pid_block_blue.png)\\n\\n\u96E2\u6563\u6642\u9593\u3067\u306E\u8868\u73FE\uFF08$k \\\\to n$\uFF09\uFF1A\\n\\n$$\\ne(n)=r(n)-y(n-1)\\n$$\\n\\n:::note[\u504F\u5DEE\u306E\u5B9A\u7FA9]\\n\u504F\u5DEE = \u76EE\u6A19\u5024 - **\u4E00\u500B\u524D\u306E\u5236\u5FA1\u91CF**\\n:::\\n\\n$$\\nU(z)=E(z)C(z)\\n$$\\n\\n### PID\u5236\u5FA1\u5668\u4F1D\u9054\u95A2\u6570\\n\\n$$\\nC(s)=c_p+c_i\\\\frac{1}{s}+c_d\\\\frac{s}{\\\\gamma s+1}, \\\\quad \\\\gamma=4\\\\times T\\n$$\\n\\n```matlab\\ngamma = 4*T;  % \u03B3\uFF08\u5FAE\u5206\u9805\u306E\u30D5\u30A3\u30EB\u30BF\u6642\u5B9A\u6570\uFF09\\ncp = 6;       % \u6BD4\u4F8B\u30B2\u30A4\u30F3\\nci = 1;       % \u7A4D\u5206\u30B2\u30A4\u30F3  \\ncd = 7;       % \u5FAE\u5206\u30B2\u30A4\u30F3\\n```\\n\\n## \u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306B\u3088\u308B\u96E2\u6563\u5316\\n\\n### 1. \u524D\u9032\u5DEE\u5206\\n\\n#### PID\u5236\u5FA1\u5668\u306EZ\u5909\u63DB\u8868\u73FE\\n\\n$$\\nC(z)=c_p+c_i\\\\frac{Tz^{-1}}{1-z^{-1}}+c_d\\\\frac{1-z^{-1}}{\\\\gamma+(T-\\\\gamma)z^{-1}}\\n$$\\n\\n#### P-I-D\u5206\u89E3\u5B9F\u88C5\uFF08\u63A8\u5968\u65B9\u6CD5\uFF09\\n\\n**\u6BD4\u4F8B\u5236\u5FA1\uFF08P\uFF09\uFF1A**\\n$$\\nu_p(n)=c_pe(n)\\n$$\\n\\n**\u7A4D\u5206\u5236\u5FA1\uFF08I\uFF09\uFF1A**\\n$$\\nu_i(n)-u_i(n-1)=c_iTe(n-1) \\\\Rightarrow u_i(n)=u_i(n-1)+c_iTe(n-1)\\n$$\\n\\n:::note[\u7A4D\u5206\u5236\u5FA1\u306E\u610F\u5473]\\n\u504F\u5DEE\u306E\u7D2F\u7A4D\u3067\u5236\u5FA1\u3059\u308B\\n:::\\n\\n**\u5FAE\u5206\u5236\u5FA1\uFF08D\uFF09\uFF1A**\\n$$\\n\\\\gamma u_d(n)+(T-\\\\gamma)u_d(n-1)=c_d(e(n)-e(n-1))\\n$$\\n\\n$$\\n\\\\Rightarrow u_d(n)=\\\\frac{c_d}{\\\\gamma}\\\\left(e(n)-e(n-1)-\\\\frac{T-\\\\gamma}{\\\\gamma}u_d(n-1)\\\\right)\\n$$\\n\\n:::note[\u5FAE\u5206\u5236\u5FA1\u306E\u610F\u5473]\\n\u504F\u5DEE\u306E\u5909\u5316\u3067\u5236\u5FA1\u3059\u308B\u3064\u3082\u308A\u3060\u304C\u3001\u521D\u671F\u72B6\u614B\u306B\u306F\u5909\u5316\u304C\u306A\u3044\u3002\u5FAE\u5206\u306E$s$ \xd7 \u30ED\u30FC\u30D1\u30B9\u30D5\u30A3\u30EB\u30BF$\\\\frac{1}{\\\\gamma s+1}$\\n:::\\n\\n#### \u72B6\u614B\u7A7A\u9593\u8868\u73FE\uFF08\u524D\u9032\u5DEE\u5206\uFF09\\n\\n$$\\nx(n+1)=x(n)+T(Ax(n)+bu(n))\\n$$\\n\\n$$\\ny(n)=Cx(n)+Du(n)\\n$$\\n\\n### 2. \u5F8C\u9000\u5DEE\u5206\\n\\n#### PID\u5236\u5FA1\u5668\u306EZ\u5909\u63DB\u8868\u73FE\\n\\n$$\\nC(z)=c_p+c_i\\\\frac{T}{1-z^{-1}}+c_d\\\\frac{1-z^{-1}}{\\\\gamma(1-z^{-1})+T}\\n$$\\n\\n#### P-I-D\u5206\u89E3\u5B9F\u88C5\\n\\n**\u6BD4\u4F8B\u5236\u5FA1\uFF08P\uFF09\uFF1A**\\n$$\\nu_p(n)=c_pe(n)\\n$$\\n\\n**\u7A4D\u5206\u5236\u5FA1\uFF08I\uFF09\uFF1A**\\n$$\\nu_i(n)-u_i(n-1)=c_iTe(n) \\\\Rightarrow u_i(n)=c_iTe(n)+u_i(n-1)\\n$$\\n\\n**\u5FAE\u5206\u5236\u5FA1\uFF08D\uFF09\uFF1A**\\n$$\\n(\\\\gamma+T)u_d(n)-\\\\gamma u_d(n-1)=c_d(e(n)-e(n-1))\\n$$\\n\\n$$\\n\\\\Rightarrow u_d(n)=\\\\frac{c_d(e(n)-e(n-1)) +\\\\gamma u_d(n-1)}{(\\\\gamma+T)}\\n$$\\n\\n#### \u72B6\u614B\u7A7A\u9593\u8868\u73FE\uFF08\u5F8C\u9000\u5DEE\u5206\uFF09\\n\\n$$\\nx(n)-x(n-1)=T(Ax(n)+bu(n)) \\\\Rightarrow x(n)=(I-TA)^{-1}(x(n-1)+Tbu(n))\\n$$\\n\\n$$\\ny(n)=Cx(n)+Du(n)\\n$$\\n\\n### 3. \u53CC\u4E00\u6B21\u5909\u63DB\u6CD5\\n\\n#### PID\u5236\u5FA1\u5668\u306EZ\u5909\u63DB\u8868\u73FE\\n\\n$$\\n\\n\\\\begin{aligned}\\nC(z)&=c_p+c_i\\\\frac{T}{2}\\\\frac{1+z^{-1}}{1-z^{-1}}+c_d\\\\frac{1}{\\\\gamma+\\\\frac{T(1+z^{-1})}{2(1-z^{-1})}}\\\\\\\\\\n&=c_p+\\\\frac{Tc_i}{2}\\\\frac{1+z^{-1}}{1-z^{-1}}+2c_d\\\\frac{1-z^{-1}}{2\\\\gamma+T+(T-2\\\\gamma)z^{-1}}\\n\\\\end{aligned}\\n\\n$$\\n\\n#### P-I-D\u5206\u89E3\u5B9F\u88C5\\n\\n**\u6BD4\u4F8B\u5236\u5FA1\uFF08P\uFF09\uFF1A**\\n$$\\nu_p(n)=c_pe(n)\\n$$\\n\\n**\u7A4D\u5206\u5236\u5FA1\uFF08I\uFF09\uFF1A**\\n$$\\nu_i(n)-u_i(n-1)=\\\\frac{c_iT}{2}(e(n)+e(n-1)) \\\\Rightarrow u_i(n)=\\\\frac{c_iT}{2}(e(n)+e(n-1))+u_i(n-1)\\n$$\\n\\n**\u5FAE\u5206\u5236\u5FA1\uFF08D\uFF09\uFF1A**\\n$$\\n(2\\\\gamma+T)u_d(n)+(T-2\\\\gamma)u_d(n-1)=2c_d(e(n)-e(n-1))\\n$$\\n\\n$$\\n\\\\Rightarrow u_d(n)= \\\\frac{2c_d(e(n)-e(n-1))+(2\\\\gamma-T)u_d(n-1)}{2\\\\gamma+T}\\n$$\\n\\n#### \u72B6\u614B\u7A7A\u9593\u8868\u73FE\uFF08\u53CC\u4E00\u6B21\u5909\u63DB\uFF09\\n\\n$$\\n\\\\frac{2}{T}(x(n)-x(n-1))=A(x(n)+x(n-1))+b(u(n)+u(n-1))\\n$$\\n\\n$$\\n\\\\Rightarrow x(n)=(2I-TA)^{-1}[(2I+AT)x(n-1)+bT(u(n)+u(n-1))]\\n$$\\n\\n$$\\ny(n)=Cx(n)+Du(n)\\n$$\\n\\n## MATLAB\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u30B3\u30FC\u30C9\\n\\n### \u30D7\u30ED\u30B0\u30E9\u30DF\u30F3\u30B0\u4E0A\u306E\u6CE8\u610F\u70B9\\n\\n:::warning[\u884C\u5217\u8A08\u7B97\u306E\u6CE8\u610F\u4E8B\u9805]\\n\u884C\u5217\u8A08\u7B97\u3059\u308B\u6642\u3001\u884C\u5217\u306E\u6B21\u5143\u306B\u6CE8\u610F\\n\\n```matlab\\ninv()  % \u9006\u884C\u5217\\neye()  % \u5358\u4F4D\u884C\u5217I\\n./     % \u884C\u5217\u9664\u7B97\\n.*     % \u884C\u5217\u8981\u7D20\u3054\u3068\u306E\u4E57\u7B97\\n```\\n\\n\u6700\u3082\u6CE8\u610F\u3059\u3079\u304D\u306A\u306E\u306F\u3001\u62EC\u5F27\u3068\u6B63\u8CA0\u306E\u7B26\u53F7\u3067\u3042\u308B\u3002\u7406\u7531\u306F\u3001\u30B3\u30FC\u30C9\u306E\u6570\u5F0F\u304C\u8AAD\u307F\u3065\u3089\u3044\u3002\\n\\n**\u89E3\u6C7A\u7B56\uFF1A**\\n1. \u30B3\u30FC\u30C9\u3092LaTeX\u516C\u5F0F\u306B\u5165\u308C\u3066\u3001\u78BA\u8A8D\u3059\u308B\\n2. \u76EE\u3068\u624B\u3067\u3082\u3046\u4E00\u56DE\u8A08\u7B97\u3057\u3066\u78BA\u8A8D\u3059\u308B\\n:::\\n\\n### \u5236\u5FA1\u30EB\u30FC\u30D7\u306E\u5B9F\u88C5\\n\\n```matlab\\nfor k=1:N+1\\n    y(k) = C*x(k) + D*u(k)     % \u51FA\u529B\u8A08\u7B97\\n    e(k) = r(k) - y(k)         % \u504F\u5DEE\u8A08\u7B97\\n    \\n    % \u96E2\u6563\u65B9\u6CD5\\n    up(k) = ...                % \u6BD4\u4F8B\u5236\u5FA1\\n    ui(k) = ...                % \u7A4D\u5206\u5236\u5FA1  \\n    ud(k) = ...                % \u5FAE\u5206\u5236\u5FA1\\n    u(k) = up(k) + ui(k) + ud(k)\\n    \\n    % \u524D\u9032\u5DEE\u5206\u3067\u72B6\u614B\u66F4\u65B0\\n    x(k+1) = x(k) + T*(A*x(k) + B*u(k))\\nend\\n```\\n\\n:::note[\u5236\u5FA1\u9806\u5E8F\u306E\u91CD\u8981\u6027]\\n1. \u5B9F\u969B\u306E\u5834\u5408\u3001\u30BB\u30F3\u30B5\u304B\u3089\u306E\u89B3\u6E2C\u5024\u3092\u3082\u3089\u3046\u306E\u3067\u3001$y(t)$\u304C\u5148\u306E\u65B9\u3067\u3042\u308B\\n2. \u3057\u304B\u3057\u3001$y(t)$\u3092\u5148\u306B\u3059\u308B\u3068\u3001$y=Cx+Du$\u306B\u304A\u3051\u308B$u$\u304C\u305A\u3063\u30680\u3067\u8A08\u7B97\u3057\u3066\u3044\u308B\u3002\u666E\u901A\u306B$D=0$\u306A\u306E\u3067\u5F71\u97FF\u304C\u306A\u3044\\n3. \u307E\u305F\u3001\u73FE\u5728\u306E\u5165\u529B$u(t)$\u3092\u6C42\u3081\u305F\u3044\u3002$u(t)$\u3092\u6C42\u3081\u308B\u305F\u3081\u306B\u3001\u73FE\u5728\u306E\u51FA\u529B\uFF08\u89B3\u5BDF\u5024\uFF09$y(t)$\u304C\u5FC5\u8981\u3067\u3042\u308B\u3002\u51FA\u529B\u3092\u5F97\u308B\u305F\u3081\u306B\u3001\u73FE\u5728\u307E\u3060\u6C42\u3081\u3066\u3044\u306A\u3044\u5165\u529B\u3092\u4F7F\u3046\u3079\u304D\u3067\u306F\u306A\u3044\\n:::\\n\\n### \u5B8C\u5168\u306A\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u30B3\u30FC\u30C9\\n\\n#### PID\u5236\u5FA1\u5668\u6BD4\u8F03\\n\\n```matlab\\nclear\\nclose all\\nset(0,\'DefaultAxesFontName\',\'Times New Roman\')\\nset(0,\'DefaultAxesFontSize\',22)\\n\\n%--------------------------------------------------------------------\\n%  \u540C\u5B9A\u30BC\u30DF\u5BBF\u984C PID\u5236\u5FA1\u5668\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\\n%                                                5/26 by YANG\\n%---------------------------------------------------------------------\\n\\nTmax = 30;    % \u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u6642\u9593\\nT = 0.05;     % \u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\\nn = Tmax/T;   % \u30B5\u30F3\u30D7\u30EB\u6570\\ngamma = 4*T;  % \u30D5\u30A3\u30EB\u30BF\u6642\u5B9A\u6570\\n\\n% PID\u30D1\u30E9\u30E1\u30FC\u30BF\\ncp = 6;       % \u6BD4\u4F8B\u30B2\u30A4\u30F3\\nci = 1;       % \u7A4D\u5206\u30B2\u30A4\u30F3\\ncd = 7;       % \u5FAE\u5206\u30B2\u30A4\u30F3\\n\\n% \u5236\u5FA1\u5BFE\u8C61\\nnum = [0 0 12 8];\\nden = [20 113 147 62 8];\\nsysg = tf(num, den);\\n[Ao,Bo,Co,Do] = tf2ss(num,den);\\n\\n% \u914D\u5217\u521D\u671F\u5316\\nt = zeros(1, n+1);\\nr = ones(1, n+1);      % \u76EE\u6A19\u5024\uFF08\u30B9\u30C6\u30C3\u30D7\u5165\u529B\uFF09\\n\\n% \u524D\u9032\u5DEE\u5206\u7528\u914D\u5217\\nupF = zeros(1, n+1);   % P\u5236\u5FA1\u5165\u529B\\nuiF = zeros(1, n+1);   % I\u5236\u5FA1\u5165\u529B\\nudF = zeros(1, n+1);   % D\u5236\u5FA1\u5165\u529B\\nuF = zeros(1, n+1);    % \u7DCF\u5236\u5FA1\u5165\u529B\\nxF = zeros(4, n+1);    % \u72B6\u614B\u5909\u6570\\nyF = zeros(1, n+1);    % \u51FA\u529B\\neF = zeros(1, n+1);    % \u504F\u5DEE\\n\\n% \u524D\u9032\u5DEE\u5206\u306B\u3088\u308BPID\u5236\u5FA1\\nfor k = 2:n+1\\n    t(k) = (k-1)*T;\\n    yF(k) = Co*xF(:,k) + Do*uF(k);\\n    eF(k) = r(k) - yF(k);\\n    \\n    % PID\u5236\u5FA1\u8A08\u7B97\\n    upF(k) = cp*eF(k);\\n    uiF(k) = uiF(k-1) + ci*T*eF(k-1);\\n    udF(k) = (cd*(eF(k)-eF(k-1)) - (T-gamma)*udF(k-1))/gamma;\\n    uF(k) = upF(k) + uiF(k) + udF(k);\\n    \\n    % \u72B6\u614B\u66F4\u65B0\\n    xF(:,k+1) = xF(:,k) + T*(Ao*xF(:,k) + Bo*uF(k));\\nend\\n\\n% \u4ED6\u306E\u624B\u6CD5\uFF08\u5F8C\u9000\u5DEE\u5206\u3001\u53CC\u4E00\u6B21\u5909\u63DB\uFF09\u3082\u540C\u69D8\u306B\u5B9F\u88C5...\\n```\\n\\n#### P-I-D\u500B\u5225\u52B9\u679C\u6BD4\u8F03\\n\\n```matlab\\n% P, I, D\u5236\u5FA1\u306E\u500B\u5225\u52B9\u679C\u3092\u6BD4\u8F03\u3059\u308B\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\\nfor k = 2:n+1\\n    t(k) = (k-1)*T;\\n    \\n    % P\u5236\u5FA1\u306E\u307F\\n    ypF(k) = Co*xpF(:,k) + Do*up(k);\\n    epF(k) = r(k) - ypF(k);\\n    up(k) = cp*epF(k);\\n    xpF(:,k+1) = xpF(:,k) + T*(Ao*xpF(:,k) + Bo*up(k));\\n    \\n    % I\u5236\u5FA1\u306E\u307F\\n    yiF(k) = Co*xiF(:,k) + Do*ui(k);\\n    eiF(k) = r(k) - yiF(k);\\n    ui(k) = ui(k-1) + ci*T*eiF(k-1);\\n    xiF(:,k+1) = xiF(:,k) + T*(Ao*xiF(:,k) + Bo*ui(k));\\n    \\n    % D\u5236\u5FA1\u306E\u307F\\n    ydF(k) = Co*xdF(:,k) + Do*ud(k);\\n    edF(k) = r(k) - ydF(k);\\n    ud(k) = (cd*(edF(k)-edF(k-1)) - (T-gamma)*ud(k-1))/gamma;\\n    xdF(:,k+1) = xdF(:,k) + T*(Ao*xdF(:,k) + Bo*ud(k));\\nend\\n```\\n\\n### \u7D50\u679C\u53EF\u8996\u5316\\n\\n```matlab\\n% \u5236\u5FA1\u5165\u529B\u306E\u6BD4\u8F03\\nsubplot(2,1,1); \\nplot(t,uF,t,uB,t,uD); \\ntitle(\'\u5236\u5FA1\u5165\u529B u(t)\');\\nlegend(\'\u524D\u9032\u5DEE\u5206\',\'\u5F8C\u9000\u5DEE\u5206\',\'\u53CC\u4E00\u6B21\u5909\u63DB\'); \\nylabel(\'u(t)\'); \\nxlabel(\'Time[sec]\'); \\ngrid on\\n\\n% \u51FA\u529B\u5FDC\u7B54\u306E\u6BD4\u8F03\\nsubplot(2,1,2);\\nplot(t,yF,t,yB,t,yD,t,r,\'--\'); \\ntitle(\'\u76EE\u6A19\u5024r(t)\u3068\u51FA\u529By(t)\');\\nlegend(\'\u524D\u9032\u5DEE\u5206\',\'\u5F8C\u9000\u5DEE\u5206\',\'\u53CC\u4E00\u6B21\u5909\u63DB\',\'\u76EE\u6A19\u5024\'); \\nylabel(\'y(t)\'); \\nxlabel(\'Time[sec]\'); \\ngrid on\\n```\\n\\n## \u6027\u80FD\u6BD4\u8F03\u3068\u8003\u5BDF\\n\\n### \u5404\u624B\u6CD5\u306E\u7279\u6027\\n\\n| \u624B\u6CD5 | \u5B89\u5B9A\u6027 | \u7CBE\u5EA6 | \u8A08\u7B97\u8CA0\u8377 | \u5B9F\u88C5\u5BB9\u6613\u3055 |\\n|------|--------|------|----------|------------|\\n| \u524D\u9032\u5DEE\u5206 | \u6761\u4EF6\u4ED8\u304D | \u4F4E | \u4F4E | \u9AD8 |\\n| \u5F8C\u9000\u5DEE\u5206 | \u826F\u597D | \u4E2D | \u4E2D | \u4E2D |\\n| \u53CC\u4E00\u6B21\u5909\u63DB | \u512A\u79C0 | \u9AD8 | \u4E2D | \u4E2D |\\n\\n### PID\u5236\u5FA1\u306E\u5404\u8981\u7D20\u306E\u5F79\u5272\\n\\n#### P\u5236\u5FA1\uFF08\u6BD4\u4F8B\u5236\u5FA1\uFF09\\n- **\u52B9\u679C**: \u504F\u5DEE\u306B\u6BD4\u4F8B\u3057\u305F\u5236\u5FA1\\n- **\u7279\u5FB4**: \u5FDC\u7B54\u901F\u5EA6\u306E\u5411\u4E0A\u3001\u5B9A\u5E38\u504F\u5DEE\u306E\u6B8B\u5B58\\n- **\u8ABF\u6574**: \u30B2\u30A4\u30F3\u3092\u5927\u304D\u304F\u3059\u308B\u3068\u5FDC\u7B54\u304C\u901F\u304F\u306A\u308B\u304C\u3001\u632F\u52D5\u3057\u3084\u3059\u304F\u306A\u308B\\n\\n#### I\u5236\u5FA1\uFF08\u7A4D\u5206\u5236\u5FA1\uFF09  \\n- **\u52B9\u679C**: \u504F\u5DEE\u306E\u7D2F\u7A4D\u3092\u89E3\u6D88\\n- **\u7279\u5FB4**: \u5B9A\u5E38\u504F\u5DEE\u306E\u9664\u53BB\u3001\u5FDC\u7B54\u306E\u9045\u308C\\n- **\u8ABF\u6574**: \u30B2\u30A4\u30F3\u3092\u5927\u304D\u304F\u3059\u308B\u3068\u5B9A\u5E38\u504F\u5DEE\u306F\u65E9\u304F\u9664\u53BB\u3055\u308C\u308B\u304C\u3001\u30AA\u30FC\u30D0\u30FC\u30B7\u30E5\u30FC\u30C8\u304C\u5897\u52A0\\n\\n#### D\u5236\u5FA1\uFF08\u5FAE\u5206\u5236\u5FA1\uFF09\\n- **\u52B9\u679C**: \u504F\u5DEE\u306E\u5909\u5316\u7387\u306B\u57FA\u3065\u304F\u5236\u5FA1\\n- **\u7279\u5FB4**: \u5FDC\u7B54\u306E\u6539\u5584\u3001\u96D1\u97F3\u306E\u5897\u5E45\\n- **\u8ABF\u6574**: \u30B2\u30A4\u30F3\u3092\u5927\u304D\u304F\u3059\u308B\u3068\u5B89\u5B9A\u6027\u306F\u5411\u4E0A\u3059\u308B\u304C\u3001\u96D1\u97F3\u306B\u654F\u611F\u306B\u306A\u308B\\n\\n### \u5B9F\u88C5\u4E0A\u306E\u30DD\u30A4\u30F3\u30C8\\n\\n1. **\u30BC\u30ED\u30AA\u30FC\u30C0\u30FC\u30DB\u30FC\u30EB\u30C9\u306E\u9069\u7528**: \u56E0\u679C\u95A2\u4FC2\u306E\u4FDD\u6301\\n2. **\u30D5\u30A9\u30F3\u30C8\u8A2D\u5B9A**: \u53EF\u8AAD\u6027\u306E\u5411\u4E0A\\n3. **\u8EF8\u30E9\u30D9\u30EB\u3068\u5358\u4F4D**: \u30B0\u30E9\u30D5\u306E\u660E\u78BA\u5316\\n4. **\u521D\u671F\u5024\u8A2D\u5B9A**: \u9069\u5207\u306A\u521D\u671F\u6761\u4EF6\u306E\u8A2D\u5B9A\\n\\n## \u307E\u3068\u3081\\n\\n\u672C\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u3067\u306F\uFF1A\\n\\n1. **\u96E2\u6563\u5316\u624B\u6CD5**: 3\u3064\u306E\u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306B\u3088\u308B\u6BD4\u8F03\\n2. **PID\u5236\u5FA1**: \u5404\u5236\u5FA1\u8981\u7D20\u306E\u500B\u5225\u52B9\u679C\u3068\u7D71\u5408\u52B9\u679C\\n3. **\u5B9F\u88C5\u6280\u6CD5**: MATLAB\u306B\u3088\u308B\u52B9\u7387\u7684\u306A\u30D7\u30ED\u30B0\u30E9\u30DF\u30F3\u30B0\u624B\u6CD5\\n4. **\u6027\u80FD\u8A55\u4FA1**: \u5B89\u5B9A\u6027\u3001\u7CBE\u5EA6\u3001\u5B9F\u7528\u6027\u306E\u89B3\u70B9\u304B\u3089\u306E\u8A55\u4FA1\\n\\n\u3053\u308C\u3089\u306E\u77E5\u8B58\u306F\u3001\u5B9F\u969B\u306E\u5236\u5FA1\u7CFB\u8A2D\u8A08\u306B\u304A\u3051\u308B\u91CD\u8981\u306A\u57FA\u76E4\u3068\u306A\u308B\u3002\u7279\u306B\u3001\u96E2\u6563\u5316\u624B\u6CD5\u306E\u9078\u629E\u306F\u5236\u5FA1\u6027\u80FD\u306B\u5927\u304D\u304F\u5F71\u97FF\u3059\u308B\u305F\u3081\u3001\u30B7\u30B9\u30C6\u30E0\u306E\u7279\u6027\u3068\u8981\u6C42\u6027\u80FD\u306B\u5FDC\u3058\u305F\u9069\u5207\u306A\u9078\u629E\u304C\u91CD\u8981\u3067\u3042\u308B\u3002"},{"id":"ubuntu-ssh-setup","metadata":{"permalink":"/blog/ubuntu-ssh-setup","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/ubuntu-ssh-setup.md","source":"@site/blog/linux/ubuntu-ssh-setup.md","title":"VS Code Remote SSH Setup for Ubuntu Server","description":"Configure VS Code Remote-SSH extension for Ubuntu with OpenSSH server setup and key authentication","date":"2024-05-20T00:00:00.000Z","tags":[{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"},{"inline":false,"label":"SSH","permalink":"/blog/tags/ssh","description":"Secure Shell protocol"},{"inline":false,"label":"Ubuntu","permalink":"/blog/tags/ubuntu","description":"Ubuntu Linux operating system"},{"inline":false,"label":"VS Code","permalink":"/blog/tags/vscode","description":"Visual Studio Code editor"},{"inline":false,"label":"Remote Development","permalink":"/blog/tags/remote-development","description":"Remote development environments"}],"readingTime":7.88,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"VS Code Remote SSH Setup for Ubuntu Server","description":"Configure VS Code Remote-SSH extension for Ubuntu with OpenSSH server setup and key authentication","slug":"ubuntu-ssh-setup","authors":"youkoutaku","date":"2024-05-20T00:00:00.000Z","tags":["linux","ssh","ubuntu","vscode","remote-development"],"keywords":["ssh","ubuntu","openssh","remote access","vscode","remote development"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"PID\u5236\u5FA1\u5668\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-pid-control"},"nextItem":{"title":"Ubuntu Development Environment Setup - PyCharm, ROS, CUDA & PyTorch Guide","permalink":"/blog/ubuntu-setup"}},"content":"This comprehensive guide explains how to set up Visual Studio Code (VS Code) for remote development on an Ubuntu machine using SSH. This setup enables you to develop directly on remote servers while maintaining the comfort of your local VS Code environment.\\n\\n![VS Code Remote SSH](https://code.visualstudio.com/assets/docs/remote/ssh/architecture-ssh.png)\\n\\n## Overview\\n\\nRemote development with VS Code over SSH provides several benefits:\\n\\n- **Direct server development**: Edit files directly on the remote machine\\n- **Consistent environment**: Use your local VS Code setup with remote resources\\n- **Security**: Encrypted SSH connection protects your work\\n- **Flexibility**: Access powerful remote machines from any local device\\n\\n## Prerequisites\\n\\n- VS Code installed on your local machine\\n- Ubuntu machine with network access\\n- Administrator privileges on both machines\\n\\n{/* truncate */}\\n\\n## 1. Install VS Code and Extensions\\n\\n### 1.1 Install VS Code\\n\\nDownload and install VS Code from the [official website](https://code.visualstudio.com/).\\n\\n### 1.2 Install Remote Development Extensions\\n\\nInstall the **Remote Development** extension pack which includes:\\n- Remote - SSH\\n- Remote - Containers\\n- Remote - WSL\\n\\n**Installation steps:**\\n1. Open VS Code\\n2. Click the **Extensions** view icon (Ctrl+Shift+X)\\n3. Search for \\"Remote Development\\"\\n4. Install the extension pack by Microsoft\\n\\n### 1.3 Alternative: Install Individual Extensions\\n\\nIf you only need SSH functionality:\\n1. Search for \\"Remote - SSH\\"\\n2. Install the extension by Microsoft\\n\\n## 2. Configure SSH Server on Ubuntu\\n\\n### 2.1 Install OpenSSH Server\\n\\n```bash\\n# Update package lists\\nsudo apt update\\n\\n# Install OpenSSH server\\nsudo apt install openssh-server\\n\\n# Verify installation\\nsudo systemctl status ssh\\n```\\n\\n### 2.2 Configure SSH Service\\n\\n```bash\\n# Enable SSH service to start on boot\\nsudo systemctl enable ssh\\n\\n# Start SSH service\\nsudo systemctl start ssh\\n\\n# Check if SSH is listening on port 22\\nsudo ss -tlnp | grep :22\\n```\\n\\n### 2.3 Configure SSH Security (Recommended)\\n\\nEdit the SSH configuration file:\\n\\n```bash\\nsudo nano /etc/ssh/sshd_config\\n```\\n\\n**Recommended security settings:**\\n```bash\\n# Change default port (optional, for better security)\\n# Port 2222\\n\\n# Disable root login\\nPermitRootLogin no\\n\\n# Enable public key authentication\\nPubkeyAuthentication yes\\n\\n# Disable password authentication (after setting up keys)\\n# PasswordAuthentication no\\n\\n# Keep connections alive\\nClientAliveInterval 60\\nClientAliveCountMax 3\\n\\n# Limit login attempts\\nMaxAuthTries 3\\n```\\n\\n**Apply configuration changes:**\\n```bash\\nsudo systemctl restart sshd\\n```\\n\\n## 3. Network Configuration\\n\\n### 3.1 Find Ubuntu IP Address\\n\\n```bash\\n# Method 1: Using ip command (preferred)\\nip addr show\\n\\n# Method 2: Using hostname command\\nhostname -I\\n\\n# Method 3: Using ifconfig (if available)\\nifconfig\\n```\\n\\nNote the IP address (typically 192.168.x.x for local networks).\\n\\n### 3.2 Configure Firewall (If Enabled)\\n\\n```bash\\n# Check firewall status\\nsudo ufw status\\n\\n# Allow SSH through firewall\\nsudo ufw allow ssh\\n# or for custom port\\nsudo ufw allow 2222/tcp\\n\\n# Enable firewall (if not already enabled)\\nsudo ufw enable\\n```\\n\\n### 3.3 Set Static IP (Optional)\\n\\nFor consistent connections, consider setting a static IP:\\n\\n```bash\\n# Edit netplan configuration\\nsudo nano /etc/netplan/00-installer-config.yaml\\n```\\n\\nExample static IP configuration:\\n```yaml\\nnetwork:\\n  ethernets:\\n    enp0s3:  # Replace with your interface name\\n      dhcp4: false\\n      addresses:\\n        - 192.168.1.100/24\\n      gateway4: 192.168.1.1\\n      nameservers:\\n        addresses: [8.8.8.8, 8.8.4.4]\\n  version: 2\\n```\\n\\nApply configuration:\\n```bash\\nsudo netplan apply\\n```\\n\\n## 4. SSH Key Setup\\n\\n### 4.1 Generate SSH Key Pair (Local Machine)\\n\\n**On Linux/macOS:**\\n```bash\\n# Generate SSH key pair\\nssh-keygen -t rsa -b 4096 -C \\"your_email@example.com\\"\\n\\n# Follow prompts:\\n# - Press Enter for default file location (~/.ssh/id_rsa)\\n# - Enter passphrase (optional but recommended)\\n# - Confirm passphrase\\n```\\n\\n**On Windows:**\\n```powershell\\n# Generate SSH key pair\\nssh-keygen -t rsa -b 4096 -C \\"your_email@example.com\\"\\n\\n# Default location: C:\\\\Users\\\\<username>\\\\.ssh\\\\id_rsa\\n```\\n\\n### 4.2 Copy Public Key to Ubuntu\\n\\n**Method 1: Using ssh-copy-id (Linux/macOS)**\\n```bash\\nssh-copy-id username@ubuntu_ip_address\\n```\\n\\n**Method 2: Manual copy (All platforms)**\\n\\n**Display your public key:**\\n```bash\\n# Linux/macOS\\ncat ~/.ssh/id_rsa.pub\\n\\n# Windows\\ntype C:\\\\Users\\\\<username>\\\\.ssh\\\\id_rsa.pub\\n```\\n\\n**Copy key to Ubuntu:**\\n```bash\\n# Connect to Ubuntu\\nssh username@ubuntu_ip_address\\n\\n# Create .ssh directory (if it doesn\'t exist)\\nmkdir -p ~/.ssh\\n\\n# Create/edit authorized_keys file\\nnano ~/.ssh/authorized_keys\\n\\n# Paste your public key into this file\\n# Save and exit (Ctrl+X, Y, Enter)\\n\\n# Set proper permissions\\nchmod 700 ~/.ssh\\nchmod 600 ~/.ssh/authorized_keys\\n```\\n\\n### 4.3 Test SSH Connection\\n\\n```bash\\n# Test connection (should not require password)\\nssh username@ubuntu_ip_address\\n\\n# Exit remote session\\nexit\\n```\\n\\n:::tip[SSH Key Security]\\n- Use a passphrase for your private key\\n- Store your private key securely\\n- Never share your private key\\n- Regularly rotate SSH keys\\n:::\\n\\n## 5. Configure VS Code SSH Connection\\n\\n### 5.1 Connect via Command Palette\\n\\n1. Open VS Code\\n2. Press `Ctrl+Shift+P` (Cmd+Shift+P on macOS)\\n3. Type \\"Remote-SSH: Connect to Host\\"\\n4. Enter: `username@ubuntu_ip_address`\\n5. Select the platform (Linux)\\n6. VS Code will install the server components automatically\\n\\n### 5.2 Create SSH Config File\\n\\nFor easier connection management, create an SSH config file:\\n\\n**Location:**\\n- Linux/macOS: `~/.ssh/config`\\n- Windows: `C:\\\\Users\\\\<username>\\\\.ssh\\\\config`\\n\\n**Example configuration:**\\n```bash\\n# Ubuntu Development Server\\nHost ubuntu-dev\\n    HostName 192.168.1.100\\n    User your_username\\n    Port 22\\n    IdentityFile ~/.ssh/id_rsa\\n    ServerAliveInterval 60\\n    ServerAliveCountMax 3\\n\\n# Multiple servers example\\nHost production-server\\n    HostName 10.0.0.50\\n    User deploy\\n    Port 2222\\n    IdentityFile ~/.ssh/production_key\\n\\nHost staging-server\\n    HostName staging.example.com\\n    User developer\\n    ProxyJump bastion-host\\n```\\n\\n**Using SSH config:**\\n1. Open Command Palette (`Ctrl+Shift+P`)\\n2. Type \\"Remote-SSH: Connect to Host\\"\\n3. Select \\"ubuntu-dev\\" from the list\\n\\n### 5.3 Advanced SSH Configuration\\n\\n**For improved performance and reliability:**\\n```bash\\nHost *\\n    # Keep connections alive\\n    ServerAliveInterval 60\\n    ServerAliveCountMax 3\\n    \\n    # Enable connection sharing\\n    ControlMaster auto\\n    ControlPath ~/.ssh/control-%r@%h:%p\\n    ControlPersist 600\\n    \\n    # Enable compression\\n    Compression yes\\n    \\n    # Speed up connections\\n    TCPKeepAlive yes\\n```\\n\\n## 6. VS Code Remote Development\\n\\n### 6.1 First Connection\\n\\n1. Connect to your remote host\\n2. VS Code will automatically install the VS Code Server\\n3. Wait for the installation to complete\\n4. You\'ll see \\"SSH: hostname\\" in the bottom-left corner\\n\\n### 6.2 Working with Remote Files\\n\\n```bash\\n# Open a folder\\nCtrl+K Ctrl+O\\n\\n# Open terminal on remote machine\\nCtrl+` (backtick)\\n\\n# File explorer shows remote files\\n# All extensions run on the remote machine\\n```\\n\\n### 6.3 Install Extensions on Remote\\n\\nExtensions need to be installed separately for remote development:\\n\\n1. Go to Extensions view (Ctrl+Shift+X)\\n2. You\'ll see separate sections:\\n   - **Local - Installed**: Extensions on your local machine\\n   - **SSH: hostname - Installed**: Extensions on remote machine\\n3. Install needed extensions in the remote section\\n\\n**Recommended remote extensions:**\\n- Language support for your stack (Python, Node.js, etc.)\\n- GitLens\\n- Bracket Pair Colorizer\\n- File icons\\n\\n### 6.4 Port Forwarding\\n\\nForward ports from remote machine to local:\\n\\n1. Open Command Palette (`Ctrl+Shift+P`)\\n2. Type \\"Remote-SSH: Forward Port from Active Host\\"\\n3. Enter remote port number\\n4. Access via `localhost:port` on your local machine\\n\\n**Example: Forward web server on port 8000:**\\n- Remote server runs on port 8000\\n- Forward to local port 8000\\n- Access via `http://localhost:8000`\\n\\n## 7. Troubleshooting\\n\\n### 7.1 Connection Issues\\n\\n#### \\"Connection Refused\\" Error\\n\\n```bash\\n# Check SSH service status\\nsudo systemctl status ssh\\n\\n# Restart SSH service\\nsudo systemctl restart ssh\\n\\n# Check if port is open\\nsudo ss -tlnp | grep :22\\n\\n# Check firewall\\nsudo ufw status\\n```\\n\\n#### \\"Permission Denied\\" Error\\n\\n```bash\\n# Check SSH key permissions\\nls -la ~/.ssh/\\n\\n# Fix permissions\\nchmod 700 ~/.ssh\\nchmod 600 ~/.ssh/authorized_keys\\nchmod 600 ~/.ssh/id_rsa\\nchmod 644 ~/.ssh/id_rsa.pub\\n```\\n\\n#### \\"Host Key Verification Failed\\"\\n\\n```bash\\n# Remove old host key\\nssh-keygen -R ubuntu_ip_address\\n\\n# Connect again to add new host key\\nssh username@ubuntu_ip_address\\n```\\n\\n### 7.2 Performance Issues\\n\\n#### Slow Connection\\n\\n```bash\\n# Enable compression in SSH config\\nHost your-host\\n    Compression yes\\n    TCPKeepAlive yes\\n    ServerAliveInterval 60\\n```\\n\\n#### High CPU Usage\\n\\n- Disable unnecessary extensions on remote\\n- Use lightweight themes\\n- Limit file watchers for large projects\\n\\n### 7.3 VS Code Server Issues\\n\\n#### Reset VS Code Server\\n\\n```bash\\n# On remote machine, remove VS Code Server\\nrm -rf ~/.vscode-server\\n\\n# Reconnect from VS Code to reinstall\\n```\\n\\n#### Update VS Code Server\\n\\nVS Code Server updates automatically, but you can force update:\\n\\n1. Disconnect from remote\\n2. Update VS Code locally\\n3. Reconnect to remote\\n\\n### 7.4 Debug Connection Issues\\n\\n```bash\\n# Verbose SSH connection\\nssh -v username@ubuntu_ip_address\\n\\n# Check SSH logs on Ubuntu\\nsudo tail -f /var/log/auth.log\\n\\n# Test SSH config\\nssh -F ~/.ssh/config -T ubuntu-dev\\n```\\n\\n## 8. Best Practices\\n\\n### 8.1 Security Best Practices\\n\\n1. **Use SSH keys instead of passwords**\\n2. **Change default SSH port**\\n3. **Disable root login**\\n4. **Use fail2ban for intrusion prevention**\\n5. **Keep systems updated**\\n\\n```bash\\n# Install fail2ban\\nsudo apt install fail2ban\\n\\n# Basic fail2ban configuration\\nsudo nano /etc/fail2ban/jail.local\\n```\\n\\nExample fail2ban configuration:\\n```ini\\n[sshd]\\nenabled = true\\nport = ssh\\nfilter = sshd\\nlogpath = /var/log/auth.log\\nmaxretry = 3\\nbantime = 3600\\n```\\n\\n### 8.2 Development Workflow\\n\\n1. **Use version control**: Always use Git for your projects\\n2. **Backup regularly**: Set up automated backups\\n3. **Environment consistency**: Use containers or virtual environments\\n4. **Documentation**: Document your setup and configurations\\n\\n### 8.3 Performance Optimization\\n\\n```bash\\n# Optimize SSH connection\\nHost *\\n    ControlMaster auto\\n    ControlPath ~/.ssh/control-%r@%h:%p\\n    ControlPersist 600\\n    Compression yes\\n```\\n\\n## 9. Advanced Features\\n\\n### 9.1 Multi-hop SSH Connections\\n\\n```bash\\n# Connect through a bastion host\\nHost production-server\\n    HostName 10.0.0.100\\n    User developer\\n    ProxyJump bastion-host\\n\\nHost bastion-host\\n    HostName bastion.example.com\\n    User admin\\n```\\n\\n### 9.2 SSH Agent Forwarding\\n\\n```bash\\n# Enable agent forwarding\\nHost ubuntu-dev\\n    HostName 192.168.1.100\\n    User developer\\n    ForwardAgent yes\\n```\\n\\n### 9.3 X11 Forwarding for GUI Apps\\n\\n```bash\\n# Enable X11 forwarding\\nHost ubuntu-dev\\n    HostName 192.168.1.100\\n    User developer\\n    ForwardX11 yes\\n    ForwardX11Trusted yes\\n```\\n\\n## Resources\\n\\n- [VS Code Remote Development](https://code.visualstudio.com/docs/remote/remote-overview)\\n- [SSH Configuration Guide](https://www.ssh.com/academy/ssh/config)\\n- [OpenSSH Manual](https://man.openbsd.org/ssh_config)\\n- [VS Code Remote SSH Tips](https://code.visualstudio.com/docs/remote/troubleshooting)\\n\\n:::tip[Pro Tips]\\n- Use SSH config files for managing multiple connections\\n- Set up SSH agent for password-less key access\\n- Use VS Code settings sync to maintain consistent configuration\\n- Consider using tmux or screen for persistent sessions\\n:::\\n\\n:::note[Security Reminder]\\nAlways follow security best practices when setting up remote access. Use strong authentication, keep systems updated, and monitor access logs regularly.\\n:::"},{"id":"ubuntu-setup","metadata":{"permalink":"/blog/ubuntu-setup","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/ubuntu-setup.md","source":"@site/blog/linux/ubuntu-setup.md","title":"Ubuntu Development Environment Setup - PyCharm, ROS, CUDA & PyTorch Guide","description":"Configure complete Ubuntu dev environment with GPU support, deep learning frameworks, and robotics tools","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Ubuntu","permalink":"/blog/tags/ubuntu","description":"Ubuntu Linux operating system"},{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"},{"inline":false,"label":"Development Setup","permalink":"/blog/tags/development-setup","description":"Setting up development environments"},{"inline":false,"label":"PyCharm","permalink":"/blog/tags/pycharm","description":"PyCharm IDE"},{"inline":false,"label":"ROS","permalink":"/blog/tags/ros","description":"Robot Operating System"},{"inline":false,"label":"CUDA","permalink":"/blog/tags/cuda","description":"NVIDIA CUDA parallel computing platform"},{"inline":false,"label":"PyTorch","permalink":"/blog/tags/pytorch","description":"PyTorch deep learning framework"},{"inline":false,"label":"Deep Learning","permalink":"/blog/tags/deep-learning","description":"Deep learning and neural networks"}],"readingTime":9.51,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Ubuntu Development Environment Setup - PyCharm, ROS, CUDA & PyTorch Guide","description":"Configure complete Ubuntu dev environment with GPU support, deep learning frameworks, and robotics tools","slug":"ubuntu-setup","authors":"youkoutaku","date":"2024-05-15T00:00:00.000Z","tags":["ubuntu","linux","development-setup","pycharm","ros","cuda","pytorch","deep-learning"],"keywords":["ubuntu","linux","development environment","pycharm","ros","cuda","pytorch","deep learning","setup"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"VS Code Remote SSH Setup for Ubuntu Server","permalink":"/blog/ubuntu-ssh-setup"},"nextItem":{"title":"Create Portable Ubuntu USB with GRUB - Full Installation Guide (Not Live USB)","permalink":"/blog/ubuntu-usb-installation"}},"content":"This comprehensive guide covers setting up a complete Ubuntu development environment, including package managers, development tools, GPU support, and machine learning frameworks.\\n\\n{/* truncate */}\\n\\n## 0. Pre-installation: Remove Existing Ubuntu (If Needed)\\n\\n### 0.1 Remove Ubuntu from Dual Boot System\\n\\nIf you need to remove an existing Ubuntu installation from a dual boot system:\\n\\n#### Open Diskpart (Windows)\\n\\n1. Press `Win + R` and type `diskpart`\\n2. Press Enter to open Diskpart with administrator privileges\\n\\n#### Commands in Diskpart\\n\\n**Check available disks:**\\n```bash\\nlist disk\\n```\\n\\n**Select the disk where Ubuntu is installed:**\\n```bash\\nselect disk <disk_number>\\n```\\n\\n**Check partitions on the selected disk:**\\n```bash\\nlist partition\\n```\\n\\n**Select the partition containing Ubuntu system files:**\\n```bash\\nselect partition 1\\n```\\n\\n**Assign a drive letter for access:**\\n```bash\\nassign letter=P\\n```\\n\\n#### Delete Ubuntu System Files\\n\\n1. Run Notepad as Administrator\\n2. Navigate to `P:` in File Explorer\\n3. Delete the Ubuntu folder in the EFI directory\\n\\n#### Remove Assigned Drive Letter\\n\\nReturn to Diskpart and remove the temporary drive letter:\\n```bash\\nremove letter=P\\n```\\n\\n#### Delete Ubuntu Partition Using Disk Management\\n\\n1. Open Disk Management (`Win + X` \u2192 `Disk Management`)\\n2. Locate the partition containing Ubuntu\\n3. Right-click and select \\"Delete Volume\\"\\n4. **Optional:** Extend another partition into the unallocated space\\n\\n:::warning[Important]\\nAlways backup important data before modifying disk partitions. Incorrect operations can result in data loss.\\n:::\\n\\n## 1. Install Ubuntu\\n\\n### 1.1 Download Ubuntu\\n\\n- Download [Ubuntu Desktop](https://ubuntu.com/download/desktop)\\n- Choose the latest LTS version for stability\\n\\n### 1.2 Create Installation Media\\n\\nUse [Rufus](https://github.com/pbatard/rufus) to create a bootable USB drive:\\n\\n1. Download and run Rufus\\n2. Select your USB drive\\n3. Select the Ubuntu ISO file\\n4. Use default settings and click \\"START\\"\\n\\n### 1.3 Installation Tips\\n\\n- Choose \\"Install Ubuntu alongside Windows\\" for dual boot\\n- Allocate at least 50GB for Ubuntu partition\\n- Create a separate home partition if desired\\n\\n## 2. Initial System Setup\\n\\n### 2.1 Update System Packages\\n\\n```bash\\n# Update package lists\\nsudo apt update\\n\\n# Upgrade all packages\\nsudo apt upgrade -y\\n\\n# Install essential packages\\nsudo apt install -y curl wget git vim build-essential software-properties-common apt-transport-https ca-certificates gnupg lsb-release\\n```\\n\\n### 2.2 Install Additional Codecs and Media Support\\n\\n```bash\\n# Install multimedia codecs\\nsudo apt install -y ubuntu-restricted-extras\\n\\n# Install additional media codecs\\nsudo apt install -y ffmpeg\\n```\\n\\n## 3. Install Anaconda3\\n\\n### 3.1 Download and Install\\n\\n```bash\\n# Navigate to Downloads directory\\ncd ~/Downloads\\n\\n# Download Anaconda (replace with latest version)\\nwget https://repo.anaconda.com/archive/Anaconda3-2023.09-0-Linux-x86_64.sh\\n\\n# Make the installer executable\\nchmod +x Anaconda3-*.sh\\n\\n# Run the installer\\nbash Anaconda3-*.sh\\n```\\n\\nFollow the installation prompts:\\n- Press Enter to review the license\\n- Type \\"yes\\" to accept the license terms\\n- Press Enter to confirm the installation location\\n- Type \\"yes\\" when asked to initialize Anaconda3\\n\\n### 3.2 Configure Environment\\n\\n```bash\\n# Edit bashrc to add Anaconda to PATH\\nnano ~/.bashrc\\n```\\n\\nAdd the following line (replace `username` with your actual username):\\n```bash\\nexport PATH=\\"/home/username/anaconda3/bin:$PATH\\"\\n```\\n\\nReload the bashrc:\\n```bash\\nsource ~/.bashrc\\n```\\n\\n### 3.3 Essential Conda Commands\\n\\n```bash\\n# Create a new environment\\nconda create -n your_env_name python=3.9\\n\\n# Activate environment\\nconda activate your_env_name\\n\\n# Deactivate environment\\nconda deactivate\\n\\n# Remove environment\\nconda remove -n your_env_name --all\\n\\n# List all environments\\nconda env list\\n# or\\nconda info --envs\\n\\n# List installed packages\\nconda list\\n\\n# Install packages\\nconda install package_name\\nconda install scrapy==1.3\\nconda install -n env_name package_name\\n\\n# Update conda\\nconda update conda\\n\\n# Update all packages\\nconda update --all\\n\\n# Update Anaconda\\nconda update anaconda\\n\\n# Update Python\\nconda update python\\n```\\n\\n### 3.4 Set Up Conda Channels\\n\\n```bash\\n# Add conda-forge channel (recommended)\\nconda config --add channels conda-forge\\n\\n# Set conda-forge as priority\\nconda config --set channel_priority strict\\n```\\n\\n## 4. Install PyCharm\\n\\n### 4.1 Download PyCharm\\n\\nDownload [PyCharm](https://www.jetbrains.com/pycharm/download/) (Community or Professional):\\n\\n```bash\\n# Navigate to Downloads\\ncd ~/Downloads\\n\\n# Extract PyCharm\\ntar -xzf pycharm-*.tar.gz\\n\\n# Move to /opt directory\\nsudo mv pycharm-* /opt/pycharm\\n\\n# Create desktop shortcut\\nsudo ln -s /opt/pycharm/bin/pycharm.sh /usr/local/bin/pycharm\\n```\\n\\n### 4.2 Alternative: Install via Snap\\n\\n```bash\\n# Install PyCharm Community Edition\\nsudo snap install pycharm-community --classic\\n\\n# Install PyCharm Professional Edition\\nsudo snap install pycharm-professional --classic\\n```\\n\\n### 4.3 Configure PyCharm with Conda\\n\\n1. Open PyCharm\\n2. Go to File \u2192 Settings \u2192 Project \u2192 Python Interpreter\\n3. Click gear icon \u2192 Add \u2192 Conda Environment\\n4. Select existing environment or create new one\\n\\n## 5. Install ROS (Robot Operating System)\\n\\n### ROS2 Humble (Ubuntu 22.04)\\n\\n```bash\\n# Add ROS2 repository\\nsudo apt update && sudo apt install curl gnupg lsb-release\\nsudo curl -sSL https://raw.githubusercontent.com/ros/rosdistro/master/ros.key -o /usr/share/keyrings/ros-archive-keyring.gpg\\n\\necho \\"deb [arch=$(dpkg --print-architecture) signed-by=/usr/share/keyrings/ros-archive-keyring.gpg] http://packages.ros.org/ros2/ubuntu $(source /etc/os-release && echo $UBUNTU_CODENAME) main\\" | sudo tee /etc/apt/sources.list.d/ros2.list > /dev/null\\n\\n# Install ROS2 Humble\\nsudo apt update\\nsudo apt install -y ros-humble-desktop-full\\n\\n# Install development tools\\nsudo apt install -y python3-colcon-common-extensions python3-rosdep\\n\\n# Initialize rosdep\\nsudo rosdep init\\nrosdep update\\n\\n# Source ROS2 setup\\necho \\"source /opt/ros/humble/setup.bash\\" >> ~/.bashrc\\nsource ~/.bashrc\\n```\\n\\n### ROS1 Noetic (Ubuntu 20.04)\\n\\n```bash\\n# Add ROS repository\\nsudo sh -c \'echo \\"deb http://packages.ros.org/ros/ubuntu $(lsb_release -sc) main\\" > /etc/apt/sources.list.d/ros-latest.list\'\\n\\n# Add ROS keys\\nsudo apt-key adv --keyserver \'hkp://keyserver.ubuntu.com:80\' --recv-key C1CF6E31E6BADE8868B172B4F42ED6FBAB17C654\\n\\n# Install ROS Noetic\\nsudo apt update\\nsudo apt install -y ros-noetic-desktop-full\\n\\n# Install rosdep\\nsudo apt install -y python3-rosdep python3-rosinstall python3-rosinstall-generator python3-wstool build-essential\\n\\n# Initialize rosdep\\nsudo rosdep init\\nrosdep update\\n\\n# Source ROS setup\\necho \\"source /opt/ros/noetic/setup.bash\\" >> ~/.bashrc\\nsource ~/.bashrc\\n```\\n\\n## 6. Install NVIDIA Driver\\n\\n### 6.1 Check Available Drivers\\n\\n```bash\\n# Check available NVIDIA drivers\\nubuntu-drivers devices\\n```\\n\\n### 6.2 Install Recommended Driver\\n\\n```bash\\n# Install the recommended driver (replace with your version)\\nsudo apt install nvidia-driver-535\\n\\n# Alternative: Install automatically recommended driver\\nsudo ubuntu-drivers autoinstall\\n```\\n\\n### 6.3 Handle MOK (Machine Owner Key)\\n\\nIf you see \\"Enroll MOK\\" during boot:\\n1. Select \\"Enroll MOK\\"\\n2. Select \\"Continue\\"\\n3. Enter the password you set during driver installation\\n4. Reboot\\n\\n### 6.4 Verify Installation\\n\\n```bash\\n# Check NVIDIA driver installation\\nnvidia-smi\\n```\\n\\nExpected output should show your GPU information and driver version.\\n\\n## 7. Install CUDA Toolkit\\n\\n### 7.1 Download and Install CUDA\\n\\nVisit [NVIDIA CUDA Toolkit Archive](https://developer.nvidia.com/cuda-toolkit-archive) and download the appropriate version.\\n\\n```bash\\n# Example for CUDA 12.3 (adjust URL for your version)\\nwget https://developer.download.nvidia.com/compute/cuda/12.3.0/local_installers/cuda_12.3.0_545.23.06_linux.run\\n\\n# Make executable\\nchmod +x cuda_12.3.0_*.run\\n\\n# Install CUDA\\nsudo sh cuda_12.3.0_*.run\\n```\\n\\nDuring installation:\\n- Deselect \\"Driver\\" (since we already installed it)\\n- Select \\"CUDA Toolkit\\"\\n\\n### 7.2 Configure Environment Variables\\n\\n```bash\\n# Edit bashrc\\nnano ~/.bashrc\\n```\\n\\nAdd these lines (adjust version number as needed):\\n```bash\\nexport PATH=/usr/local/cuda-12.3/bin${PATH:+:${PATH}}\\nexport LD_LIBRARY_PATH=/usr/local/cuda-12.3/lib64${LD_LIBRARY_PATH:+:${LD_LIBRARY_PATH}}\\n```\\n\\nReload configuration:\\n```bash\\nsource ~/.bashrc\\n```\\n\\n### 7.3 Verify CUDA Installation\\n\\n```bash\\n# Check CUDA version\\nnvcc --version\\n\\n# Check CUDA samples (if installed)\\ncd /usr/local/cuda/samples/1_Utilities/deviceQuery\\nsudo make\\n./deviceQuery\\n```\\n\\n## 8. Install cuDNN\\n\\n### 8.1 Download cuDNN\\n\\n1. Visit [cuDNN Archive](https://developer.nvidia.com/rdp/cudnn-archive)\\n2. Create NVIDIA Developer account if needed\\n3. Download cuDNN for your CUDA version\\n\\n### 8.2 Install cuDNN\\n\\n```bash\\n# Navigate to Downloads\\ncd ~/Downloads\\n\\n# Extract cuDNN\\ntar -xzf cudnn-*.tar.xz\\n\\n# Navigate to extracted directory\\ncd cudnn-*\\n\\n# Copy files to CUDA installation\\nsudo cp include/cudnn*.h /usr/local/cuda/include \\nsudo cp -P lib/libcudnn* /usr/local/cuda/lib64 \\nsudo chmod a+r /usr/local/cuda/include/cudnn*.h /usr/local/cuda/lib64/libcudnn*\\n```\\n\\n### 8.3 Verify cuDNN Installation\\n\\n```bash\\n# Check cuDNN version\\ncat /usr/local/cuda/include/cudnn_version.h | grep CUDNN_MAJOR -A 2\\n```\\n\\n## 9. Install PyTorch\\n\\n### 9.1 Install PyTorch with CUDA Support\\n\\nVisit [PyTorch Previous Versions](https://pytorch.org/get-started/previous-versions/) for specific versions.\\n\\n```bash\\n# Activate your conda environment\\nconda activate your_env_name\\n\\n# Install PyTorch with CUDA support (example for CUDA 12.1)\\nconda install pytorch torchvision torchaudio pytorch-cuda=12.1 -c pytorch -c nvidia\\n\\n# Alternative: pip installation\\npip3 install torch torchvision torchaudio --index-url https://download.pytorch.org/whl/cu121\\n```\\n\\n### 9.2 Verify PyTorch Installation\\n\\nCreate a test script:\\n```python\\nimport torch\\n\\nprint(f\\"PyTorch version: {torch.__version__}\\")\\nprint(f\\"CUDA version: {torch.version.cuda}\\")\\nprint(f\\"cuDNN version: {torch.backends.cudnn.version()}\\")\\nprint(f\\"CUDA available: {torch.cuda.is_available()}\\")\\nprint(f\\"CUDA device count: {torch.cuda.device_count()}\\")\\n\\nif torch.cuda.is_available():\\n    print(f\\"CUDA device name: {torch.cuda.get_device_name(0)}\\")\\n    print(f\\"Current CUDA device: {torch.cuda.current_device()}\\")\\n```\\n\\nRun the script:\\n```bash\\npython test_pytorch.py\\n```\\n\\n## 10. Install Docker\\n\\n### 10.1 Install Docker Engine\\n\\n```bash\\n# Remove old versions\\nsudo apt-get remove docker docker-engine docker.io containerd runc\\n\\n# Add Docker\'s official GPG key\\nsudo apt-get update\\nsudo apt-get install ca-certificates curl gnupg\\nsudo install -m 0755 -d /etc/apt/keyrings\\ncurl -fsSL https://download.docker.com/linux/ubuntu/gpg | sudo gpg --dearmor -o /etc/apt/keyrings/docker.gpg\\nsudo chmod a+r /etc/apt/keyrings/docker.gpg\\n\\n# Add repository\\necho \\\\\\n  \\"deb [arch=\\"$(dpkg --print-architecture)\\" signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu \\\\\\n  \\"$(. /etc/os-release && echo \\"$VERSION_CODENAME\\")\\" stable\\" | \\\\\\n  sudo tee /etc/apt/sources.list.d/docker.list > /dev/null\\n\\n# Install Docker Engine\\nsudo apt-get update\\nsudo apt-get install docker-ce docker-ce-cli containerd.io docker-buildx-plugin docker-compose-plugin\\n```\\n\\n### 10.2 Configure Docker for Non-root User\\n\\n```bash\\n# Add user to docker group\\nsudo groupadd docker\\nsudo usermod -aG docker $USER\\n\\n# Apply changes\\nnewgrp docker\\n\\n# Test installation\\ndocker run hello-world\\n```\\n\\n:::warning[Docker Desktop]\\nDo not install Docker Desktop on Ubuntu. Docker Engine is sufficient and more lightweight.\\n:::\\n\\n## 11. Additional Development Tools\\n\\n### 11.1 Install VS Code\\n\\n```bash\\n# Download and install VS Code\\nwget -qO- https://packages.microsoft.com/keys/microsoft.asc | gpg --dearmor > packages.microsoft.gpg\\nsudo install -o root -g root -m 644 packages.microsoft.gpg /etc/apt/trusted.gpg.d/\\necho \\"deb [arch=amd64,arm64,armhf signed-by=/etc/apt/trusted.gpg.d/packages.microsoft.gpg] https://packages.microsoft.com/repos/code stable main\\" | sudo tee /etc/apt/sources.list.d/vscode.list\\n\\nsudo apt update\\nsudo apt install code\\n```\\n\\n### 11.2 Install Node.js and npm\\n\\n```bash\\n# Install Node.js LTS\\ncurl -fsSL https://deb.nodesource.com/setup_lts.x | sudo -E bash -\\nsudo apt-get install -y nodejs\\n\\n# Verify installation\\nnode --version\\nnpm --version\\n```\\n\\n### 11.3 Install Additional Programming Languages\\n\\n#### Java Development Kit\\n\\n```bash\\n# Install OpenJDK\\nsudo apt install default-jdk\\n\\n# Verify installation\\njava --version\\njavac --version\\n```\\n\\n#### Go Programming Language\\n\\n```bash\\n# Install Go\\nsudo apt install golang-go\\n\\n# Verify installation\\ngo version\\n```\\n\\n## 12. System Optimization\\n\\n### 12.1 Install System Monitoring Tools\\n\\n```bash\\n# Install htop, neofetch, and other useful tools\\nsudo apt install htop neofetch tree tmux screen\\n```\\n\\n### 12.2 Enable Firewall\\n\\n```bash\\n# Enable UFW firewall\\nsudo ufw enable\\n\\n# Check status\\nsudo ufw status\\n```\\n\\n### 12.3 Set Up Automatic Updates\\n\\n```bash\\n# Install unattended-upgrades\\nsudo apt install unattended-upgrades\\n\\n# Configure automatic updates\\nsudo dpkg-reconfigure unattended-upgrades\\n```\\n\\n## 13. Backup and Recovery\\n\\n### 13.1 Create System Backup\\n\\n```bash\\n# Install timeshift for system snapshots\\nsudo apt install timeshift\\n\\n# Create backup via GUI\\nsudo timeshift-gtk\\n```\\n\\n### 13.2 Backup Configuration Files\\n\\n```bash\\n# Backup important configuration files\\nmkdir ~/config-backup\\ncp ~/.bashrc ~/config-backup/\\ncp ~/.profile ~/config-backup/\\n# Add other important configs as needed\\n```\\n\\n## Troubleshooting\\n\\n### Common Issues and Solutions\\n\\n#### NVIDIA Driver Issues\\n\\n```bash\\n# Purge and reinstall NVIDIA drivers\\nsudo apt purge nvidia-* \\nsudo ubuntu-drivers autoinstall\\nsudo reboot\\n```\\n\\n#### CUDA Path Issues\\n\\n```bash\\n# Check CUDA installation path\\nls /usr/local/cuda*\\n\\n# Update paths in ~/.bashrc accordingly\\n```\\n\\n#### Python Environment Conflicts\\n\\n```bash\\n# Reset conda environment\\nconda remove --name myenv --all\\nconda create --name myenv python=3.9\\n```\\n\\n:::tip[System Maintenance]\\n- Regularly update your system with `sudo apt update && sudo apt upgrade`\\n- Keep your conda environments clean and organized\\n- Use virtual environments for different projects\\n- Monitor system resources with `htop` and `nvidia-smi`\\n:::\\n\\n## Resources\\n\\n- [Ubuntu Official Documentation](https://help.ubuntu.com/)\\n- [Anaconda Documentation](https://docs.anaconda.com/)\\n- [NVIDIA CUDA Documentation](https://docs.nvidia.com/cuda/)\\n- [PyTorch Documentation](https://pytorch.org/docs/)\\n- [Docker Documentation](https://docs.docker.com/)"},{"id":"ubuntu-usb-installation","metadata":{"permalink":"/blog/ubuntu-usb-installation","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/linux/ubuntu-usb-installation.md","source":"@site/blog/linux/ubuntu-usb-installation.md","title":"Create Portable Ubuntu USB with GRUB - Full Installation Guide (Not Live USB)","description":"Install complete Ubuntu OS on USB drive with persistent GRUB bootloader - run anywhere","date":"2024-05-10T00:00:00.000Z","tags":[{"inline":false,"label":"Ubuntu","permalink":"/blog/tags/ubuntu","description":"Ubuntu Linux operating system"},{"inline":false,"label":"Linux","permalink":"/blog/tags/linux","description":"Linux operating system and administration"},{"inline":false,"label":"USB Installation","permalink":"/blog/tags/usb-installation","description":"Installing operating systems from USB"},{"inline":false,"label":"GRUB","permalink":"/blog/tags/grub","description":"GRUB bootloader"},{"inline":false,"label":"Dual Boot","permalink":"/blog/tags/dual-boot","description":"Dual-boot system configuration"}],"readingTime":11.25,"hasTruncateMarker":true,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"title":"Create Portable Ubuntu USB with GRUB - Full Installation Guide (Not Live USB)","description":"Install complete Ubuntu OS on USB drive with persistent GRUB bootloader - run anywhere","slug":"ubuntu-usb-installation","authors":"youkoutaku","date":"2024-05-10T00:00:00.000Z","tags":["ubuntu","linux","usb-installation","grub","dual-boot"],"keywords":["ubuntu","usb","bootable usb","installation","grub","dual boot","portable os"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Ubuntu Development Environment Setup - PyCharm, ROS, CUDA & PyTorch Guide","permalink":"/blog/ubuntu-setup"},"nextItem":{"title":"\u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306E\u6BD4\u8F03\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-numerical-integration-methods"}},"content":"This comprehensive guide explains how to install Ubuntu on a USB drive with a portable GRUB bootloader configuration. This setup allows you to run Ubuntu from any computer while keeping the host system\'s bootloader intact.\\n\\n![Ubuntu on USB](https://res.cloudinary.com/canonical/image/fetch/f_auto,q_auto,fl_sanitize,w_1920,h_1080/https://assets.ubuntu.com/v1/d4ea8bb8-ubuntu-budgie-2410.png)\\n\\n## Overview\\n\\nInstalling Ubuntu on a USB drive provides several advantages:\\n\\n- **Portability**: Run your Ubuntu environment on any compatible computer\\n- **Non-invasive**: No changes to the host computer\'s internal storage\\n- **Isolation**: Complete separation from host operating system\\n- **Development Environment**: Portable development setup for embedded systems\\n- **Recovery Tool**: Bootable Ubuntu system for system recovery tasks\\n\\n## Understanding the Boot Process\\n\\n### Traditional Installation vs USB Installation\\n\\n**Traditional Installation:**\\n- GRUB installed on internal disk\\n- EFI files stored in host system\'s ESP (EFI System Partition)\\n- GRUB menu appears even without USB drive\\n\\n**USB Installation (This Guide):**\\n- GRUB installed entirely on USB drive\\n- EFI files contained within USB drive\\n- Host system remains unchanged\\n- GRUB only appears when USB is connected\\n\\n### Boot Flow Diagram\\n\\n```mermaid\\ngraph TD\\n    A[Computer Power On] --\x3e B{USB Drive Connected?}\\n    B --\x3e|Yes| C[BIOS Boot Menu]\\n    B --\x3e|No| D[Windows Boot Manager]\\n    C --\x3e E{Select Boot Device}\\n    E --\x3e|USB Drive| F[Ubuntu GRUB]\\n    E --\x3e|Internal Disk| D\\n    F --\x3e G[Ubuntu OS]\\n    D --\x3e H[Windows OS]\\n```\\n\\n{/* truncate */}\\n\\n## Prerequisites\\n\\n### Hardware Requirements\\n\\n- **USB Drive**: Minimum 16GB (32GB+ recommended)\\n- **USB 3.0+**: For better performance\\n- **UEFI System**: Modern computers with UEFI firmware\\n- **Free USB Port**: For installation process\\n\\n### Software Requirements\\n\\n- **Ubuntu ISO**: Download from [Ubuntu official website](https://ubuntu.com/download/desktop)\\n- **Bootable USB Creator**: Such as Rufus, Etcher, or dd command\\n- **Administrative Access**: To both Windows and Ubuntu systems\\n\\n### System Preparation\\n\\n1. **Backup Important Data**: Always backup before modifying boot configurations\\n2. **BIOS/UEFI Access**: Ensure you can access BIOS/UEFI settings\\n3. **Secure Boot**: May need to disable for custom installations\\n4. **Fast Boot**: Disable Windows Fast Boot for dual-boot compatibility\\n\\n## 1. Initial Ubuntu Installation\\n\\n### 1.1 Create Installation Media\\n\\nFirst, create a bootable Ubuntu installer:\\n\\n**Using Rufus (Windows):**\\n1. Download [Rufus](https://rufus.ie/)\\n2. Select Ubuntu ISO file\\n3. Choose GPT partition scheme for UEFI\\n4. Select FAT32 file system\\n5. Create bootable drive\\n\\n**Using dd (Linux):**\\n```bash\\n# Identify USB device\\nlsblk\\n\\n# Create bootable USB (replace /dev/sdX with your USB device)\\nsudo dd if=ubuntu-22.04-desktop-amd64.iso of=/dev/sdX bs=4M status=progress\\nsudo sync\\n```\\n\\n### 1.2 Boot from Installation Media\\n\\n1. Insert installation USB into target computer\\n2. Enter BIOS/UEFI settings (usually F2, F12, or DEL key)\\n3. Set USB drive as first boot priority\\n4. Save settings and restart\\n\\n### 1.3 Install Ubuntu to USB Drive\\n\\n:::warning[Critical Step]\\nDuring installation, carefully select the target USB drive as the installation destination. Installing to the internal disk will overwrite your existing system.\\n:::\\n\\n**Installation Steps:**\\n1. Boot from Ubuntu installation media\\n2. Select \\"Install Ubuntu\\"\\n3. Choose language and keyboard layout\\n4. Select \\"Minimal installation\\" for faster setup\\n5. **Important**: Choose \\"Something else\\" for installation type\\n6. **Select USB drive** as installation target:\\n   - Create EFI partition (512MB, FAT32)\\n   - Create root partition (remaining space, ext4)\\n   - Set bootloader installation location to USB drive\\n\\n**Partition Layout Example:**\\n```\\nUSB Drive (/dev/sdb):\\n\u251C\u2500\u2500 /dev/sdb1 - 512MB - EFI System Partition (FAT32)\\n\u2514\u2500\u2500 /dev/sdb2 - Remaining - Ubuntu Root (ext4)\\n```\\n\\n### 1.4 Post-Installation BIOS Configuration\\n\\nAfter installation:\\n1. Access BIOS/UEFI settings\\n2. Set boot priority to \\"Ubuntu GRUB\\"\\n3. Save and restart\\n\\nAt this point, you\'ll have Ubuntu running, but GRUB is likely installed on the internal disk\'s EFI partition.\\n\\n## 2. Remove Ubuntu EFI from Internal Disk\\n\\nTo make the installation truly portable, remove Ubuntu\'s EFI files from the internal disk.\\n\\n### 2.1 Boot into Windows\\n\\n1. Restart computer\\n2. Select Windows from GRUB menu\\n3. Boot into Windows normally\\n\\n### 2.2 Access EFI Partition\\n\\n**Method 1: Using Diskpart (Command Line)**\\n\\n1. Open Command Prompt as Administrator\\n2. Run diskpart utility:\\n\\n```cmd\\n# Start diskpart\\ndiskpart\\n\\n# List all disks\\nlist disk\\n\\n# Select internal disk (usually disk 0)\\nselect disk 0\\n\\n# List partitions\\nlist partition\\n\\n# Select EFI system partition (usually partition 1)\\nselect partition 1\\n\\n# Assign a drive letter to access EFI partition\\nassign letter=P\\n```\\n\\n### 2.3 Delete Ubuntu EFI Files\\n\\n1. Open File Explorer as Administrator\\n2. Navigate to drive P: (the EFI partition)\\n3. Go to `P:\\\\EFI\\\\`\\n4. Delete the `ubuntu` folder\\n\\n**Alternative: Command Line Method**\\n```cmd\\n# Navigate to EFI partition\\nP:\\ncd EFI\\n\\n# List contents\\ndir\\n\\n# Remove Ubuntu folder\\nrmdir /s ubuntu\\n```\\n\\n### 2.4 Remove Drive Letter Assignment\\n\\nReturn to diskpart and clean up:\\n```cmd\\n# Remove the assigned drive letter\\nremove letter=P\\n\\n# Exit diskpart\\nexit\\n```\\n\\n### 2.5 Verify EFI Removal\\n\\nRestart the computer. You should now boot directly into Windows without seeing the GRUB menu, confirming that Ubuntu\'s EFI files have been removed from the internal disk.\\n\\n## 3. Configure Portable GRUB on USB\\n\\nNow we\'ll configure GRUB to be entirely self-contained on the USB drive.\\n\\n### 3.1 Boot Ubuntu from USB\\n\\n1. Insert USB drive\\n2. Access BIOS boot menu (usually F12)\\n3. Select USB drive to boot\\n4. You may get a GRUB prompt instead of automatic boot\\n\\n### 3.2 Manual GRUB Boot (If Needed)\\n\\nIf Ubuntu doesn\'t boot automatically, use GRUB commands:\\n\\n```bash\\n# List available devices and partitions\\ngrub> ls\\n\\n# Expected output: (hd0) (hd0,gpt1) (hd0,gpt2) (hd1) (hd1,gpt1) (hd1,gpt2)\\n# USB drive is typically hd0, internal drive is hd1\\n\\n# Check for Ubuntu boot files\\ngrub> ls (hd0,gpt2)/boot\\n\\n# You should see vmlinuz and initrd files\\n```\\n\\n**Boot Ubuntu manually:**\\n```bash\\n# Set root partition (Ubuntu installation)\\ngrub> set root=(hd0,gpt2)\\n\\n# Load kernel (replace with actual kernel version)\\ngrub> linux /boot/vmlinuz-6.2.0-39-generic root=/dev/sda2\\n\\n# Load initial ramdisk (replace with actual version)\\ngrub> initrd /boot/initrd.img-6.2.0-39-generic\\n\\n# Boot the system\\ngrub> boot\\n```\\n\\n:::info[Device Naming]\\n- GRUB uses `(hd0,gpt2)` format\\n- Linux uses `/dev/sda2` format\\n- These refer to the same partition but in different naming schemes\\n:::\\n\\n### 3.3 Install GRUB to USB Drive\\n\\nOnce Ubuntu is running, install GRUB properly to the USB drive:\\n\\n```bash\\n# Identify USB drive device\\nlsblk\\n\\n# Typically shows:\\n# sda    USB drive\\n# \u251C\u2500sda1 EFI partition\\n# \u2514\u2500sda2 Ubuntu root\\n# sdb    Internal disk\\n\\n# Update package lists\\nsudo apt update\\n\\n# Install GRUB tools if not present\\nsudo apt install grub-efi-amd64\\n\\n# Mount EFI partition\\nsudo mkdir -p /mnt/efi\\nsudo mount /dev/sda1 /mnt/efi\\n\\n# Install GRUB to USB drive\\nsudo grub-install --target=x86_64-efi --efi-directory=/mnt/efi --boot-directory=/mnt/efi/boot --removable --recheck\\n\\n# Update GRUB configuration\\nsudo update-grub\\n\\n# Copy GRUB configuration to USB\\nsudo cp /boot/grub/grub.cfg /mnt/efi/boot/grub/grub.cfg\\n```\\n\\n### 3.4 Alternative Installation Method\\n\\nIf the above method doesn\'t work, try this approach:\\n\\n```bash\\n# Mount USB EFI partition\\nsudo mount /dev/sda1 /mnt\\n\\n# Install GRUB with removable flag\\nsudo grub-install --boot-directory=/mnt/boot --efi-directory=/mnt --removable /dev/sda\\n\\n# Update GRUB configuration\\nsudo update-grub\\n\\n# Unmount\\nsudo umount /mnt\\n```\\n\\n## 4. Verification and Testing\\n\\n### 4.1 Test USB Boot\\n\\n1. Restart the computer\\n2. Access BIOS boot menu\\n3. Check if \\"Ubuntu\\" or \\"UEFI: USB Drive\\" appears as boot option\\n4. Select USB boot option\\n5. Verify GRUB menu appears with Ubuntu option\\n\\n### 4.2 Test Without USB\\n\\n1. Shutdown computer\\n2. Remove USB drive\\n3. Power on computer\\n4. Verify it boots directly to Windows (no GRUB menu)\\n\\n### 4.3 Verify Portable Operation\\n\\n1. Test USB drive on different computer\\n2. Boot from USB drive\\n3. Confirm Ubuntu works on different hardware\\n\\n## 5. Advanced Configuration\\n\\n### 5.1 GRUB Customization\\n\\nCreate custom GRUB configuration for better experience:\\n\\n```bash\\n# Edit GRUB configuration\\nsudo nano /etc/default/grub\\n\\n# Useful settings for USB installation:\\nGRUB_DEFAULT=0\\nGRUB_TIMEOUT=10\\nGRUB_TIMEOUT_STYLE=menu\\nGRUB_DISTRIBUTOR=\\"Ubuntu USB\\"\\nGRUB_CMDLINE_LINUX_DEFAULT=\\"quiet splash\\"\\nGRUB_CMDLINE_LINUX=\\"\\"\\n\\n# Update GRUB after changes\\nsudo update-grub\\n```\\n\\n### 5.2 Persistence and Storage\\n\\n**Optimize for USB usage:**\\n```bash\\n# Reduce writes to USB drive\\nsudo nano /etc/fstab\\n\\n# Add these lines for reduced USB wear:\\ntmpfs /tmp tmpfs defaults,noatime,mode=1777 0 0\\ntmpfs /var/log tmpfs defaults,noatime,mode=0755 0 0\\n```\\n\\n### 5.3 Performance Optimization\\n\\n**Enable USB 3.0 optimizations:**\\n```bash\\n# Add to /etc/rc.local for USB performance\\necho \'deadline\' | sudo tee /sys/block/sda/queue/scheduler\\n\\n# Reduce swappiness for USB drives\\necho \'vm.swappiness=10\' | sudo tee -a /etc/sysctl.conf\\n```\\n\\n## 6. Troubleshooting\\n\\n### 6.1 Common Boot Issues\\n\\n#### GRUB Not Appearing\\n\\n**Problem**: USB doesn\'t show in BIOS boot menu\\n**Solutions**:\\n1. Check BIOS settings for USB boot support\\n2. Enable \\"USB Boot\\" in BIOS\\n3. Disable Secure Boot temporarily\\n4. Try different USB port (use USB 2.0 port if USB 3.0 fails)\\n\\n#### GRUB Error Messages\\n\\n**Problem**: GRUB rescue prompt appears\\n**Solutions**:\\n```bash\\n# At grub rescue prompt\\ngrub rescue> ls\\ngrub rescue> set prefix=(hd0,gpt2)/boot/grub\\ngrub rescue> set root=(hd0,gpt2)\\ngrub rescue> insmod normal\\ngrub rescue> normal\\n```\\n\\n#### Ubuntu Won\'t Boot\\n\\n**Problem**: Kernel panic or boot failure\\n**Solutions**:\\n1. Check kernel parameters in GRUB\\n2. Try different kernel version\\n3. Boot in recovery mode\\n4. Check USB drive for errors\\n\\n### 6.2 Hardware Compatibility\\n\\n#### Different Computer Boot Issues\\n\\n**Problem**: USB Ubuntu won\'t boot on different hardware\\n**Solutions**:\\n1. Install additional drivers:\\n   ```bash\\n   sudo apt install linux-generic linux-headers-generic\\n   sudo apt install firmware-linux-nonfree\\n   ```\\n2. Enable proprietary drivers in Software & Updates\\n3. Create fallback kernel options in GRUB\\n\\n#### Graphics Issues\\n\\n**Problem**: Display problems on different hardware\\n**Solutions**:\\n```bash\\n# Install additional graphics drivers\\nsudo apt install mesa-utils\\nsudo ubuntu-drivers autoinstall\\n\\n# Add safe graphics option to GRUB\\nGRUB_CMDLINE_LINUX_DEFAULT=\\"quiet splash nomodeset\\"\\n```\\n\\n### 6.3 USB Drive Issues\\n\\n#### Drive Not Recognized\\n\\n**Problem**: System doesn\'t detect USB drive\\n**Solutions**:\\n1. Check USB drive health with:\\n   ```bash\\n   sudo fsck /dev/sda1\\n   sudo fsck /dev/sda2\\n   ```\\n2. Test USB drive on different computers\\n3. Check USB port functionality\\n4. Try reformatting USB drive\\n\\n#### Slow Performance\\n\\n**Problem**: Ubuntu runs slowly from USB\\n**Solutions**:\\n1. Use USB 3.0+ drive and port\\n2. Enable write caching (with caution)\\n3. Increase system memory if possible\\n4. Use SSD-based USB drive for better performance\\n\\n## 7. Maintenance and Updates\\n\\n### 7.1 System Updates\\n\\n```bash\\n# Regular system updates\\nsudo apt update && sudo apt upgrade\\n\\n# Kernel updates require GRUB update\\nsudo update-grub\\n\\n# After kernel updates, verify boot process\\n```\\n\\n### 7.2 GRUB Maintenance\\n\\n```bash\\n# Reinstall GRUB if issues occur\\nsudo mount /dev/sda1 /mnt/efi\\nsudo grub-install --target=x86_64-efi --efi-directory=/mnt/efi --removable\\n\\n# Update GRUB configuration\\nsudo update-grub\\n```\\n\\n### 7.3 Backup Strategies\\n\\n**Backup USB Drive:**\\n```bash\\n# Create full drive image\\nsudo dd if=/dev/sda of=ubuntu-usb-backup.img bs=4M status=progress\\n\\n# Compress backup\\ngzip ubuntu-usb-backup.img\\n```\\n\\n**Restore from Backup:**\\n```bash\\n# Restore drive image\\ngunzip ubuntu-usb-backup.img.gz\\nsudo dd if=ubuntu-usb-backup.img of=/dev/sda bs=4M status=progress\\n```\\n\\n## 8. Security Considerations\\n\\n### 8.1 Encryption Setup\\n\\nFor sensitive data, consider encrypting the USB drive:\\n\\n```bash\\n# During installation, select \\"Encrypt the new Ubuntu installation\\"\\n# Or set up LUKS encryption post-installation\\n\\n# Install cryptsetup\\nsudo apt install cryptsetup\\n\\n# Encrypt USB partition (destroys data)\\nsudo cryptsetup luksFormat /dev/sda2\\n\\n# Open encrypted partition\\nsudo cryptsetup luksOpen /dev/sda2 ubuntu_encrypted\\n```\\n\\n### 8.2 Secure Boot Considerations\\n\\n**With Secure Boot Enabled:**\\n1. Sign GRUB bootloader with trusted keys\\n2. Use signed kernel modules only\\n3. Consider using Ubuntu\'s signed GRUB\\n\\n**Disable Secure Boot (Simpler):**\\n1. Access UEFI settings\\n2. Find Secure Boot option\\n3. Disable Secure Boot\\n4. Save settings\\n\\n### 8.3 Physical Security\\n\\n1. **Use strong user passwords**\\n2. **Enable automatic screen lock**\\n3. **Consider full disk encryption**\\n4. **Secure USB drive when not in use**\\n\\n## 9. Use Cases and Applications\\n\\n### 9.1 Development Environment\\n\\nPortable development setup:\\n```bash\\n# Install development tools\\nsudo apt install build-essential git vim code\\n\\n# Install specific development environments\\nsudo apt install python3-dev nodejs npm docker.io\\n\\n# Configure Git\\ngit config --global user.name \\"Your Name\\"\\ngit config --global user.email \\"your.email@example.com\\"\\n```\\n\\n### 9.2 System Recovery\\n\\nEmergency system recovery toolkit:\\n```bash\\n# Install recovery tools\\nsudo apt install gparted testdisk photorec ntfs-3g\\n\\n# Network tools for remote recovery\\nsudo apt install openssh-server wget curl\\n```\\n\\n### 9.3 Educational Use\\n\\nClassroom or training environment:\\n```bash\\n# Install educational software\\nsudo apt install scratch libreoffice gimp\\n\\n# Install programming environments\\nsudo apt install python3-idle thonny\\n```\\n\\n## 10. Performance Optimization\\n\\n### 10.1 USB Drive Selection\\n\\n**Recommended USB Drive Specifications:**\\n- **Interface**: USB 3.0+ (preferably USB 3.1 or 3.2)\\n- **Storage**: 32GB minimum, 64GB+ recommended\\n- **Type**: SSD-based USB drives for best performance\\n- **Brand**: Reputable manufacturers with good controllers\\n\\n### 10.2 System Optimization\\n\\n**Reduce USB wear:**\\n```bash\\n# Optimize mount options in /etc/fstab\\n/dev/sda2 / ext4 defaults,noatime,errors=remount-ro 0 1\\n\\n# Disable swap file (use swap partition if needed)\\nsudo swapoff -a\\nsudo rm /swapfile\\n\\n# Configure log rotation for reduced writes\\nsudo nano /etc/logrotate.conf\\n```\\n\\n### 10.3 Memory Management\\n\\n```bash\\n# Optimize memory usage\\necho \'vm.dirty_ratio = 5\' | sudo tee -a /etc/sysctl.conf\\necho \'vm.dirty_background_ratio = 2\' | sudo tee -a /etc/sysctl.conf\\n\\n# Reduce journal size for systemd\\nsudo nano /etc/systemd/journald.conf\\n# Set: SystemMaxUse=50M\\n```\\n\\n## Resources and References\\n\\n- [Ubuntu Installation Guide](https://ubuntu.com/tutorials/install-ubuntu-desktop)\\n- [GRUB Manual](https://www.gnu.org/software/grub/manual/)\\n- [UEFI Boot Process](https://uefi.org/specifications)\\n- [Linux Disk Management](https://www.kernel.org/doc/html/latest/admin-guide/devices.html)\\n\\n:::tip[Pro Tips]\\n- Use high-quality USB 3.0+ drives for better performance\\n- Test USB installation on multiple computers before relying on it\\n- Keep multiple backup copies of working USB installations\\n- Document hardware-specific configurations for different computers\\n- Consider using multiple USB drives for different purposes (development, recovery, etc.)\\n:::\\n\\n:::warning[Important Notes]\\n- Always backup important data before modifying boot configurations\\n- USB drives have limited write cycles - avoid excessive logging\\n- Some computers may not support booting from USB without BIOS modifications\\n- Secure Boot may prevent USB Ubuntu from booting on some systems\\n- Performance will be slower than internal SSD installations\\n:::"},{"id":"simulation-numerical-integration-methods","metadata":{"permalink":"/blog/simulation-numerical-integration-methods","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/matlab/simulation-numerical-integration-methods.md","source":"@site/blog/matlab/simulation-numerical-integration-methods.md","title":"\u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306E\u6BD4\u8F03\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","description":"\u524D\u9032\u5DEE\u5206\u3001\u5F8C\u9000\u5DEE\u5206\u3001\u53CC\u4E00\u6B21\u5909\u63DB\u3092\u7528\u3044\u305FRL\u56DE\u8DEF\u306E\u30B9\u30C6\u30C3\u30D7\u5FDC\u7B54\u6570\u5024\u8A08\u7B97\u3068\u305D\u306E\u6BD4\u8F03","date":"2024-04-21T00:00:00.000Z","tags":[{"inline":true,"label":"MATLAB","permalink":"/blog/tags/matlab"},{"inline":true,"label":"\u6570\u5024\u7A4D\u5206","permalink":"/blog/tags/\u6570\u5024\u7A4D\u5206"},{"inline":true,"label":"\u524D\u9032\u5DEE\u5206","permalink":"/blog/tags/\u524D\u9032\u5DEE\u5206"},{"inline":true,"label":"\u5F8C\u9000\u5DEE\u5206","permalink":"/blog/tags/\u5F8C\u9000\u5DEE\u5206"},{"inline":true,"label":"\u53CC\u4E00\u6B21\u5909\u63DB","permalink":"/blog/tags/\u53CC\u4E00\u6B21\u5909\u63DB"},{"inline":true,"label":"\u96FB\u6C17\u56DE\u8DEF","permalink":"/blog/tags/\u96FB\u6C17\u56DE\u8DEF"}],"readingTime":4.43,"hasTruncateMarker":false,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"authors":"youkoutaku","date":"2024-04-21T00:00:00.000Z","slug":"simulation-numerical-integration-methods","title":"\u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306E\u6BD4\u8F03\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","description":"\u524D\u9032\u5DEE\u5206\u3001\u5F8C\u9000\u5DEE\u5206\u3001\u53CC\u4E00\u6B21\u5909\u63DB\u3092\u7528\u3044\u305FRL\u56DE\u8DEF\u306E\u30B9\u30C6\u30C3\u30D7\u5FDC\u7B54\u6570\u5024\u8A08\u7B97\u3068\u305D\u306E\u6BD4\u8F03","tags":["MATLAB","\u6570\u5024\u7A4D\u5206","\u524D\u9032\u5DEE\u5206","\u5F8C\u9000\u5DEE\u5206","\u53CC\u4E00\u6B21\u5909\u63DB","\u96FB\u6C17\u56DE\u8DEF"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"Create Portable Ubuntu USB with GRUB - Full Installation Guide (Not Live USB)","permalink":"/blog/ubuntu-usb-installation"},"nextItem":{"title":"\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u30E2\u30C7\u30EB\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-linear-discrete-time-system"}},"content":"\u524D\u9032\u5DEE\u5206\u3001\u5F8C\u9000\u5DEE\u5206\u3001\u53CC\u4E00\u6B21\u5909\u63DB\u3092\u305D\u308C\u305E\u308C\u7528\u3044\u3066\u3001\u4F8B\u984C1.2.1\u306E\u96FB\u6C17\u56DE\u8DEF\u306E\u30B9\u30C6\u30C3\u30D7\u5FDC\u7B54\u3092\u6570\u5024\u8A08\u7B97\u3067\u6C42\u3081\u3001\u6570\u5024\u8A08\u7B97\u306E\u7D50\u679C\u3068\u771F\u306E\u5FDC\u7B54\u3092\u30D7\u30ED\u30C3\u30C8\u3057\u3001\u6BD4\u8F03\u3059\u308B\u3002\\n\\n## \u96FB\u6C17\u56DE\u8DEF\u30E2\u30C7\u30EB\\n\\nRL\u56DE\u8DEF\u306E\u5FAE\u5206\u65B9\u7A0B\u5F0F\uFF1A\\n$$\\nL\\\\frac{di(t)}{dt} + Ri(t) = u(t)\\n$$\\n\\n\u771F\u306E\u89E3\uFF08\u30B9\u30C6\u30C3\u30D7\u5FDC\u7B54\uFF09\uFF1A\\n$$\\ni(t) = \\\\frac{1}{R}(1 - e^{-\\\\frac{R}{L}t})\\n$$\\n\\n## \u6570\u5024\u7A4D\u5206\u624B\u6CD5\\n\\n### 1. \u524D\u9032\u5DEE\u5206\uFF08Forward Difference\uFF09\\n\\n\u5FAE\u5206\u306E\u8FD1\u4F3C\uFF1A\\n$$\\nsf(n) = \\\\frac{f(n+1)-f(n)}{T}\\n$$\\n\\n\u3088\u3063\u3066\uFF1A\\n$$\\nL\\\\frac{i(n+1)-i(n)}{T} + Ri(n) = u(n)\\n$$\\n\\n\u6574\u7406\u3059\u308B\u3068\uFF1A\\n$$\\ni(n+1) = \\\\frac{1}{L}(Tu(n) + (L-RT)i(n))\\n$$\\n\\n\u6642\u9593\u3092\u30B7\u30D5\u30C8\u3057\u3066\uFF1A\\n$$\\ni(n) = \\\\frac{1}{L}(Tu(n-1) + (L-RT)i(n-1))\\n$$\\n\\n### 2. \u5F8C\u9000\u5DEE\u5206\uFF08Backward Difference\uFF09\\n\\n\u5FAE\u5206\u306E\u8FD1\u4F3C\uFF1A\\n$$\\nsf(n) = \\\\frac{f(n)-f(n-1)}{T}\\n$$\\n\\n\u3088\u3063\u3066\uFF1A\\n$$\\nL\\\\frac{i(n)-i(n-1)}{T} + Ri(n) = u(n)\\n$$\\n\\n\u6574\u7406\u3059\u308B\u3068\uFF1A\\n$$\\ni(n) = \\\\frac{1}{RT+L}(Tu(n) + Li(n-1))\\n$$\\n\\n### 3. \u53CC\u4E00\u6B21\u5909\u63DB\uFF08Bilinear Transform\uFF09\\n\\n\u53F0\u5F62\u7A4D\u5206\u306B\u3088\u308B\u8FD1\u4F3C\uFF1A\\n$$\\nsf(n) = \\\\frac{2}{T}\\\\frac{1-z^{-1}}{1+z^{-1}}f(n)\\n$$\\n\\n\u5FAE\u5206\u65B9\u7A0B\u5F0F\u306B\u9069\u7528\uFF1A\\n$$\\nL\\\\frac{2}{T}(i(n)-i(n-1)) + R(i(n)+i(n-1)) = u(n)+u(n-1)\\n$$\\n\\n\u6574\u7406\u3059\u308B\u3068\uFF1A\\n$$\\ni(n) = \\\\frac{1}{2L+RT} \\\\left( Tu(n)+Tu(n-1) + (2L-RT)i(n-1) \\\\right)\\n$$\\n\\n## MATLAB\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u30B3\u30FC\u30C9\\n\\n### \u521D\u671F\u8A2D\u5B9A\\n\\n```matlab\\nclear\\nclose all\\nset(0,\'DefaultAxesFontName\',\'Times New Roman\')\\nset(0,\'DefaultAxesFontSize\',12)\\n\\n%--------------------------------------------------------------------\\n%  \u540C\u5B9A\u30BC\u30DF\u5BBF\u984C \u96FB\u6C17\u56DE\u8DEF\u5FDC\u7B54\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\\n%                                                4/21 by YANG\\n%---------------------------------------------------------------------\\n```\\n\\n### \u30D1\u30E9\u30E1\u30FC\u30BF\u8A2D\u5B9A\\n\\n```matlab\\nTmax = 10;           % \u6700\u5927\u6642\u9593\\nsamp = 0.5;          % \u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\\nT = samp;\\nn = Tmax/samp;       % \u30B5\u30F3\u30D7\u30EB\u6570\\nu = ones(1,n+1);     % \u30B9\u30C6\u30C3\u30D7\u5165\u529B\\n\\n% \u56DE\u8DEF\u30D1\u30E9\u30E1\u30FC\u30BF\\nR = 1;               % \u62B5\u6297\u5024\\nL = 1;               % \u30A4\u30F3\u30C0\u30AF\u30BF\u30F3\u30B9\u5024\\n```\\n\\n### \u914D\u5217\u521D\u671F\u5316\\n\\n```matlab\\n% \u6570\u5217\\nt  = zeros(1, n+1);  % \u6642\u9593\u914D\u5217\\ni  = zeros(1, n+1);  % \u771F\u306E\u4FE1\u53F7\\ni1 = zeros(1, n+1);  % \u524D\u9032\u5DEE\u5206\\ni2 = zeros(1, n+1);  % \u5F8C\u9000\u5DEE\u5206\\ni3 = zeros(1, n+1);  % \u53CC\u4E00\u6B21\u5909\u63DB\\n```\\n\\n### \u5404\u624B\u6CD5\u306B\u3088\u308B\u6570\u5024\u8A08\u7B97\\n\\n#### \u771F\u306E\u89E3\u6790\u89E3\\n\\n```matlab\\n% \u771F\u306E\u4FE1\u53F7\\nfor k = 2:n+1\\n    t(k) = (k-1) * samp;\\n    i(k) = (1 - exp((-t(k)*R)/L)) / R;\\nend\\n```\\n\\n#### \u524D\u9032\u5DEE\u5206\\n\\n```matlab\\n% \u524D\u9032\u5DEE\u5206\\nfor k = 2:n+1\\n    t(k) = (k-1) * samp;\\n    i1(k) = (samp*u(k-1) + (L-R*samp)*i1(k-1)) / L;\\nend\\n```\\n\\n#### \u5F8C\u9000\u5DEE\u5206\\n\\n```matlab\\n% \u5F8C\u9000\u5DEE\u5206\\nfor k = 2:n+1\\n    t(k) = (k-1) * samp;\\n    i2(k) = (T*u(k) + L*i2(k-1)) / (R*samp+L);\\nend\\n```\\n\\n#### \u53CC\u4E00\u6B21\u5909\u63DB\\n\\n```matlab\\n% \u53CC\u4E00\u6B21\u5909\u63DB\\nfor k = 2:n+1\\n    t(k) = (k-1) * samp;\\n    i3(k) = (T*u(k) + T*u(k-1) + (2*L-R*T)*i3(k-1)) / (2*L+R*samp);\\nend\\n```\\n\\n### \u7D50\u679C\u306E\u30D7\u30ED\u30C3\u30C8\\n\\n```matlab\\n% \u6BD4\u8F03\u30D7\u30ED\u30C3\u30C8\\nsubplot(3,1,1); \\nplot(t,i,t,i1); \\ntitle(\'\u524D\u9032\u5DEE\u5206\');\\nlegend(\'\u771F\u306E\u89E3\',\'\u524D\u9032\u5DEE\u5206\');  \\nxlabel(\'t\'); \\nylabel(\'i(t)\');\\ngrid on\\n\\nsubplot(3,1,2); \\nplot(t,i,t,i2); \\ntitle(\'\u5F8C\u9000\u5DEE\u5206\');\\nlegend(\'\u771F\u306E\u89E3\',\'\u5F8C\u9000\u5DEE\u5206\');      \\nxlabel(\'t\'); \\nylabel(\'i(t)\');\\ngrid on\\n\\nsubplot(3,1,3); \\nplot(t,i,t,i3); \\ntitle(\'\u53CC\u4E00\u6B21\u5909\u63DB\');\\nlegend(\'\u771F\u306E\u89E3\',\'\u53CC\u4E00\u6B21\u5909\u63DB\');  \\nxlabel(\'t\'); \\nylabel(\'i(t)\');\\ngrid on\\n```\\n\\n## \u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306E\u7279\u6027\u6BD4\u8F03\\n\\n### 1. \u524D\u9032\u5DEE\u5206\u306E\u7279\u6027\\n\\n**\u7279\u5FB4\uFF1A**\\n- \u660E\u793A\u7684\uFF08explicit\uFF09\u624B\u6CD5\\n- \u8A08\u7B97\u304C\u7C21\u5358\\n- \u5B89\u5B9A\u6027\u306B\u5236\u9650\u304C\u3042\u308B\\n\\n**\u5B89\u5B9A\u6027\u6761\u4EF6\uFF1A**\\n$$|1 - \\\\frac{RT}{L}| \\\\leq 1$$\\n\\n\u3053\u308C\u3088\u308A\uFF1A\\n$$T \\\\leq \\\\frac{2L}{R}$$\\n\\n:::warning[\u5B89\u5B9A\u6027\u306E\u5236\u9650]\\n\u524D\u9032\u5DEE\u5206\u306F\u5927\u304D\u306A\u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\u3067\u4E0D\u5B89\u5B9A\u306B\u306A\u308B\u53EF\u80FD\u6027\u304C\u3042\u308B\u3002\\n:::\\n\\n### 2. \u5F8C\u9000\u5DEE\u5206\u306E\u7279\u6027\\n\\n**\u7279\u5FB4\uFF1A**\\n- \u6697\u793A\u7684\uFF08implicit\uFF09\u624B\u6CD5\\n- \u7121\u6761\u4EF6\u5B89\u5B9A\\n- \u8A08\u7B97\u304C\u3084\u3084\u8907\u96D1\\n\\n**\u5B89\u5B9A\u6027\uFF1A**\\n\u5206\u6BCD\u304C$RT + L > 0$\u3067\u5E38\u306B\u6B63\u306E\u305F\u3081\u3001\u7121\u6761\u4EF6\u5B89\u5B9A\u3002\\n\\n:::tip[\u5B89\u5B9A\u6027\u306E\u512A\u4F4D\u6027]\\n\u5F8C\u9000\u5DEE\u5206\u306F\u5927\u304D\u306A\u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\u3067\u3082\u5B89\u5B9A\u3067\u3042\u308B\u3002\\n:::\\n\\n### 3. \u53CC\u4E00\u6B21\u5909\u63DB\u306E\u7279\u6027\\n\\n**\u7279\u5FB4\uFF1A**\\n- \u53F0\u5F62\u7A4D\u5206\u306B\u3088\u308B\u8FD1\u4F3C\\n- \u512A\u308C\u305F\u5468\u6CE2\u6570\u7279\u6027\\n- \u30D0\u30E9\u30F3\u30B9\u306E\u53D6\u308C\u305F\u7CBE\u5EA6\\n\\n**\u5B89\u5B9A\u6027\uFF1A**\\n\u9023\u7D9A\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u304C\u5B89\u5B9A\u306A\u3089\u3001\u96E2\u6563\u5316\u5F8C\u3082\u5B89\u5B9A\u6027\u304C\u4FDD\u6301\u3055\u308C\u308B\u3002\\n\\n:::note[\u5468\u6CE2\u6570\u7279\u6027\u306E\u4FDD\u6301]\\n\u53CC\u4E00\u6B21\u5909\u63DB\u306F\u5468\u6CE2\u6570\u5FDC\u7B54\u7279\u6027\u3092\u6700\u3082\u3088\u304F\u4FDD\u6301\u3059\u308B\u3002\\n:::\\n\\n## \u7CBE\u5EA6\u3068\u5B89\u5B9A\u6027\u306E\u8A55\u4FA1\\n\\n### \u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\u306E\u5F71\u97FF\\n\\n| \u624B\u6CD5 | \u7CBE\u5EA6 | \u5B89\u5B9A\u6027 | \u8A08\u7B97\u30B3\u30B9\u30C8 |\\n|------|------|--------|------------|\\n| \u524D\u9032\u5DEE\u5206 | \u4F4E\u301C\u4E2D | \u6761\u4EF6\u4ED8\u304D | \u4F4E |\\n| \u5F8C\u9000\u5DEE\u5206 | \u4E2D | \u7121\u6761\u4EF6 | \u4E2D |\\n| \u53CC\u4E00\u6B21\u5909\u63DB | \u9AD8 | \u7121\u6761\u4EF6 | \u4E2D |\\n\\n### \u9069\u7528\u5834\u9762\\n\\n#### \u524D\u9032\u5DEE\u5206\\n- \u9AD8\u901F\u306A\u8A08\u7B97\u304C\u5FC5\u8981\\n- \u5C0F\u3055\u306A\u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\\n- \u30EA\u30A2\u30EB\u30BF\u30A4\u30E0\u51E6\u7406\\n\\n#### \u5F8C\u9000\u5DEE\u5206\\n- \u5B89\u5B9A\u6027\u304C\u91CD\u8981\\n- \u5927\u304D\u306A\u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\\n- \u30ED\u30D0\u30B9\u30C8\u6027\u304C\u8981\u6C42\u3055\u308C\u308B\u5834\u5408\\n\\n#### \u53CC\u4E00\u6B21\u5909\u63DB\\n- \u9AD8\u7CBE\u5EA6\u304C\u5FC5\u8981\\n- \u5468\u6CE2\u6570\u7279\u6027\u306E\u4FDD\u6301\u304C\u91CD\u8981\\n- \u5236\u5FA1\u7CFB\u8A2D\u8A08\\n\\n## \u307E\u3068\u3081\\n\\n\u672C\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u306B\u3088\u308A\u4EE5\u4E0B\u306E\u3053\u3068\u304C\u78BA\u8A8D\u3067\u304D\u308B\uFF1A\\n\\n1. **\u7CBE\u5EA6\u6BD4\u8F03**: \u53CC\u4E00\u6B21\u5909\u63DB\u304C\u6700\u3082\u9AD8\u7CBE\u5EA6\\n2. **\u5B89\u5B9A\u6027**: \u5F8C\u9000\u5DEE\u5206\u3068\u53CC\u4E00\u6B21\u5909\u63DB\u304C\u512A\u79C0\\n3. **\u8A08\u7B97\u52B9\u7387**: \u524D\u9032\u5DEE\u5206\u304C\u6700\u3082\u7C21\u5358\\n4. **\u5B9F\u7528\u6027**: \u53CC\u4E00\u6B21\u5909\u63DB\u304C\u7DCF\u5408\u7684\u306B\u512A\u308C\u3066\u3044\u308B\\n\\n:::tip[\u624B\u6CD5\u9078\u629E\u306E\u6307\u91DD]\\n- **\u9AD8\u7CBE\u5EA6\u304C\u5FC5\u8981** \u2192 \u53CC\u4E00\u6B21\u5909\u63DB\\n- **\u5B89\u5B9A\u6027\u91CD\u8996** \u2192 \u5F8C\u9000\u5DEE\u5206\\n- **\u9AD8\u901F\u8A08\u7B97** \u2192 \u524D\u9032\u5DEE\u5206\uFF08\u5B89\u5B9A\u6027\u6761\u4EF6\u4E0B\uFF09\\n:::\\n\\n\u3053\u308C\u3089\u306E\u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306E\u7406\u89E3\u306F\u3001\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u3084\u5236\u5FA1\u7CFB\u8A2D\u8A08\u306B\u304A\u3044\u3066\u91CD\u8981\u306A\u57FA\u790E\u77E5\u8B58\u3068\u306A\u308B\u3002"},{"id":"simulation-linear-discrete-time-system","metadata":{"permalink":"/blog/simulation-linear-discrete-time-system","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/matlab/simulation-linear-discrete-time-system.md","source":"@site/blog/matlab/simulation-linear-discrete-time-system.md","title":"\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u30E2\u30C7\u30EB\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","description":"MATLAB\u3092\u7528\u3044\u305F\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u306E\u6570\u5024\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u5B9F\u88C5\u4F8B","date":"2024-04-13T00:00:00.000Z","tags":[{"inline":true,"label":"MATLAB","permalink":"/blog/tags/matlab"},{"inline":true,"label":"\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/tags/\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3"},{"inline":true,"label":"\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0","permalink":"/blog/tags/\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0"},{"inline":true,"label":"\u7DDA\u5F62\u30B7\u30B9\u30C6\u30E0","permalink":"/blog/tags/\u7DDA\u5F62\u30B7\u30B9\u30C6\u30E0"},{"inline":true,"label":"Z\u5909\u63DB","permalink":"/blog/tags/z\u5909\u63DB"}],"readingTime":3.41,"hasTruncateMarker":false,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"authors":"youkoutaku","date":"2024-04-13T00:00:00.000Z","slug":"simulation-linear-discrete-time-system","title":"\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u30E2\u30C7\u30EB\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","description":"MATLAB\u3092\u7528\u3044\u305F\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u306E\u6570\u5024\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u5B9F\u88C5\u4F8B","tags":["MATLAB","\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0","\u7DDA\u5F62\u30B7\u30B9\u30C6\u30E0","Z\u5909\u63DB"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"\u6570\u5024\u7A4D\u5206\u624B\u6CD5\u306E\u6BD4\u8F03\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-numerical-integration-methods"},"nextItem":{"title":"VSCode\u306B\u3088\u308BMATLAB\u306E\u4F7F\u7528","permalink":"/blog/vscode-matlab-setup"}},"content":"## \u30B7\u30B9\u30C6\u30E0\u30E2\u30C7\u30EB\\n\\n2\u6B21\u306E\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u3092\u8003\u3048\u308B\uFF1A\\n\\n$$\\nx_t=-a_1x_{t-1}-a_2x_{t-2}+b_1u_{t-1}+b_2u_{t-2}\\n$$\\n\\n### Z\u5909\u63DB\u306B\u3088\u308B\u8868\u73FE\\n\\n$$\\n(1+a_1z^{-1}+a_2z^{-2})X(z)=(b_1z^{-1}+b_2z^{-2})U(z)\\n$$\\n\\n### \u4F1D\u9054\u95A2\u6570\\n\\n$$\\nH(z)=\\\\frac{X(z)}{U(z)}=\\\\frac{b_1z^{-1}+b_2z^{-2}}{1+a_1z^{-1}+a_2z^{-2}}=\\\\frac{z^{-1}+0.5z^{-2}}{1-1.5z^{-1}+0.7z^{-2}}=\\\\frac{z+0.5}{z^2-1.5z+0.7}\\n$$\\n\\n### \u90E8\u5206\u5206\u6570\u5C55\u958B\\n\\n$$\\nH(z)=\\\\frac{ z^{-1}(1+0.5z^{-1}) }{ (1-\\\\frac{1.5+j\\\\sqrt{0.55}}{2}z^{-1})(1-\\\\frac{1.5-j\\\\sqrt{0.55}}{2}z^{-1})}\\n$$\\n\\n:::tip[MATLAB\u3067\u306E\u6570\u5024\u8A08\u7B97]\\nMATLAB\u3067\u30C7\u30A3\u30B8\u30BF\u30EB\u4FE1\u53F7\u3092\u6271\u3046\u6642\u306B\u3001\u305D\u306E\u307E\u307E\u5DEE\u5206\u65B9\u7A0B\u5F0F\u3092\u4F7F\u3048\u308B\u3002Z\u5909\u63DB\u306A\u3069\u304C\u8981\u3089\u306A\u3044\u3002\\n:::\\n\\n## MATLAB\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u30B3\u30FC\u30C9\\n\\n### \u521D\u671F\u8A2D\u5B9A\\n\\n```matlab\\nclear\\nclose all\\nset(0,\'DefaultAxesFontName\',\'Times New Roman\')\\nset(0,\'DefaultAxesFontSize\',12)\\n\\n%--------------------------------------------------------------------\\n%  \u540C\u5B9A\u30BC\u30DF\u5BBF\u984Cpdf p.13 \u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u30E2\u30C7\u30EB\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\\n%                                                       4/13 by YANG\\n%---------------------------------------------------------------------\\n```\\n\\n### \u30D1\u30E9\u30E1\u30FC\u30BF\u8A2D\u5B9A\\n\\n```matlab\\n% \u521D\u671F\u30D1\u30E9\u30E1\u30FC\u30BF\\nTmax = 10;           % \u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u6642\u9593\\nsamp = 0.01;         % \u30B5\u30F3\u30D7\u30EA\u30F3\u30B0\u5468\u671F\\nn = Tmax/samp;       % \u30B5\u30F3\u30D7\u30EB\u6570\\nu = rand(1,n+1);     % \u5165\u529B\uFF08\u4E00\u69D8\u4E71\u6570\uFF09\\n\\nNSR = 0.0;           % \u96D1\u97F3\u4FE1\u53F7\u6BD4\uFF08Noise Signal Ratio\uFF09\\n% NSR 0, 0.1, 0.2\u3067\u6BD4\u8F03\u53EF\u80FD\\n\\n% \u30B7\u30B9\u30C6\u30E0\u30D1\u30E9\u30E1\u30FC\u30BF\\na1 = -1.5;\\na2 = 0.7;\\nb1 = 1.0;\\nb2 = 0.5;\\n```\\n\\n### \u914D\u5217\u521D\u671F\u5316\\n\\n```matlab\\nt = zeros(1, n+1);   % \u6642\u9593\u914D\u5217\\nx = zeros(1, n+1);   % \u771F\u306E\u51FA\u529B\\ny = zeros(1, n+1);   % \u89B3\u6E2C\u5024\uFF08\u96D1\u97F3\u4ED8\u304D\uFF09\\n```\\n\\n### \u30B7\u30B9\u30C6\u30E0\u5FDC\u7B54\u8A08\u7B97\\n\\n```matlab\\n% \u771F\u306E\u51FA\u529B\u306E\u8A08\u7B97\\nfor k = 3:n+1\\n    t(k) = (k-1) * samp;\\n    x(k) = -a1*x(k-1) - a2*x(k-2) + b1*u(k-1) + b2*u(k-2);\\nend\\n```\\n\\n### \u89B3\u6E2C\u96D1\u97F3\u306E\u8FFD\u52A0\\n\\n```matlab\\n% \u30BC\u30ED\u5E73\u5747\u306E\u30AC\u30A6\u30B9\u5206\u5E03\u4E71\u6570\uFF08\u6B63\u898F\u5206\u5E03\uFF09\\nmu = 0;                    % \u5E73\u5747\u5024\\nsigma = NSR * std(x);      % \u6A19\u6E96\u504F\u5DEE NSR = sigma/std(x)\\nv = sigma * randn(1,n+1) + mu;\\n\\n% \u89B3\u6E2C\u5024\u306E\u8A08\u7B97\\nfor k = 3:n+1\\n    y(k) = x(k) + v(k);\\nend\\n```\\n\\n### \u7D50\u679C\u306E\u30D7\u30ED\u30C3\u30C8\\n\\n```matlab\\nsubplot(2,2,1); plot(t,u); title(\'\u5165\u529B\u4FE1\u53F7 u(t)\');\\nsubplot(2,2,2); plot(t,x); title(\'\u771F\u306E\u51FA\u529B x(t)\');\\nsubplot(2,2,3); plot(t,y); title(\'\u89B3\u6E2C\u51FA\u529B y(t)\');\\nsubplot(2,2,4); plot(t,v); title(\'\u89B3\u6E2C\u96D1\u97F3 v(t)\');\\n```\\n\\n## \u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u7D50\u679C\u306E\u89E3\u6790\\n\\n### \u96D1\u97F3\u4FE1\u53F7\u6BD4\uFF08NSR\uFF09\u306E\u5F71\u97FF\\n\\n- **NSR = 0.0**: \u96D1\u97F3\u306A\u3057\u3001\u7406\u60F3\u7684\u306A\u6761\u4EF6\\n- **NSR = 0.1**: 10%\u306E\u96D1\u97F3\u30EC\u30D9\u30EB\\n- **NSR = 0.2**: 20%\u306E\u96D1\u97F3\u30EC\u30D9\u30EB\\n\\n:::info[\u96D1\u97F3\u4FE1\u53F7\u6BD4\u3068\u306F]\\nNSR\uFF08Noise Signal Ratio\uFF09\u306F\u89B3\u6E2C\u96D1\u97F3\u306E\u6A19\u6E96\u504F\u5DEE\u3068\u771F\u306E\u51FA\u529B\u4FE1\u53F7\u306E\u6A19\u6E96\u504F\u5DEE\u3068\u306E\u6BD4\u3067\u3042\u308B\uFF1A\\n$$NSR = \\\\frac{\\\\sigma_v}{\\\\sigma_x}$$\\n:::\\n\\n### \u30B7\u30B9\u30C6\u30E0\u306E\u5B89\u5B9A\u6027\\n\\n\u30B7\u30B9\u30C6\u30E0\u306E\u6975\u306F\u6B21\u306E\u65B9\u7A0B\u5F0F\u306E\u89E3\uFF1A\\n$$z^2 - 1.5z + 0.7 = 0$$\\n\\n\u8907\u7D20\u5171\u5F79\u6975\uFF1A\\n$$z = \\\\frac{1.5 \\\\pm j\\\\sqrt{0.55}}{2}$$\\n\\n\u6975\u306E\u5927\u304D\u3055\uFF1A\\n$$|z| = \\\\sqrt{0.7} \\\\approx 0.837 < 1$$\\n\\n:::tip[\u5B89\u5B9A\u6027\u306E\u78BA\u8A8D]\\n\u3059\u3079\u3066\u306E\u6975\u304C\u5358\u4F4D\u5186\u5185\u306B\u3042\u308B\u305F\u3081\u3001\u30B7\u30B9\u30C6\u30E0\u306F\u5B89\u5B9A\u3067\u3042\u308B\u3002\\n:::\\n\\n## \u5FDC\u7528\u4F8B\\n\\n\u3053\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u306F\u4EE5\u4E0B\u306E\u7528\u9014\u306B\u5FDC\u7528\u3067\u304D\u308B\uFF1A\\n\\n1. **\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A**: \u30D1\u30E9\u30E1\u30FC\u30BF$a_1, a_2, b_1, b_2$\u306E\u63A8\u5B9A\\n2. **\u96D1\u97F3\u306E\u5F71\u97FF\u8A55\u4FA1**: \u7570\u306A\u308BNSR\u30EC\u30D9\u30EB\u3067\u306E\u6027\u80FD\u6BD4\u8F03\\n3. **\u5236\u5FA1\u5668\u8A2D\u8A08**: \u30B7\u30B9\u30C6\u30E0\u7279\u6027\u306E\u7406\u89E3\\n4. **\u30D5\u30A3\u30EB\u30BF\u8A2D\u8A08**: \u96D1\u97F3\u9664\u53BB\u624B\u6CD5\u306E\u691C\u8A0E\\n\\n## \u5B9F\u88C5\u306E\u30DD\u30A4\u30F3\u30C8\\n\\n### \u521D\u671F\u5024\u306E\u8A2D\u5B9A\\n- \u914D\u5217\u306E\u521D\u671F\u5316\u3067`zeros`\u3092\u4F7F\u7528\\n- \u30EB\u30FC\u30D7\u306F`k=3`\u304B\u3089\u958B\u59CB\uFF08\u904E\u53BB2\u30B5\u30F3\u30D7\u30EB\u304C\u5FC5\u8981\uFF09\\n\\n### \u96D1\u97F3\u751F\u6210\\n- `randn`\u3067\u30AC\u30A6\u30B9\u5206\u5E03\u4E71\u6570\u751F\u6210\\n- `std(x)`\u3067\u771F\u306E\u51FA\u529B\u306E\u6A19\u6E96\u504F\u5DEE\u3092\u8A08\u7B97\\n- NSR\u306B\u3088\u3063\u3066\u96D1\u97F3\u30EC\u30D9\u30EB\u3092\u8ABF\u6574\\n\\n### \u30D7\u30ED\u30C3\u30C8\u8A2D\u5B9A\\n- `subplot`\u3067\u8907\u6570\u306E\u30B0\u30E9\u30D5\u3092\u540C\u6642\u8868\u793A\\n- \u30D5\u30A9\u30F3\u30C8\u8A2D\u5B9A\u3067\u53EF\u8AAD\u6027\u3092\u5411\u4E0A\\n- \u65E5\u672C\u8A9E\u30BF\u30A4\u30C8\u30EB\u3067\u7406\u89E3\u3057\u3084\u3059\u3055\u3092\u5411\u4E0A\\n\\n## \u307E\u3068\u3081\\n\\n\u672C\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\u3067\u306F\uFF1A\\n\\n1. **\u5DEE\u5206\u65B9\u7A0B\u5F0F**: \u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u306E\u76F4\u63A5\u5B9F\u88C5\\n2. **\u96D1\u97F3\u30E2\u30C7\u30EB**: \u5B9F\u969B\u7684\u306A\u89B3\u6E2C\u6761\u4EF6\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3\\n3. **\u53EF\u8996\u5316**: \u5165\u529B\u3001\u51FA\u529B\u3001\u96D1\u97F3\u306E\u95A2\u4FC2\u306E\u7406\u89E3\\n4. **\u30D1\u30E9\u30E1\u30FC\u30BF\u5F71\u97FF**: NSR\u306B\u3088\u308B\u6027\u80FD\u8A55\u4FA1\\n\\n\u3053\u308C\u3089\u306E\u8981\u7D20\u306F\u3001\u30B7\u30B9\u30C6\u30E0\u540C\u5B9A\u3084\u5236\u5FA1\u7CFB\u8A2D\u8A08\u306B\u304A\u3051\u308B\u57FA\u672C\u7684\u306A\u6570\u5024\u5B9F\u9A13\u306E\u57FA\u76E4\u3068\u306A\u308B\u3002"},{"id":"vscode-matlab-setup","metadata":{"permalink":"/blog/vscode-matlab-setup","editUrl":"https://github.com/youkoutaku/docusaurus-youkoutaku/tree/main/blog/matlab/vscode-matlab-setup.md","source":"@site/blog/matlab/vscode-matlab-setup.md","title":"VSCode\u306B\u3088\u308BMATLAB\u306E\u4F7F\u7528","description":"Visual Studio Code\u3067MATLAB\u30B3\u30FC\u30C9\u3092\u7DE8\u96C6\u30FB\u5B9F\u884C\u3059\u308B\u65B9\u6CD5","date":"2024-01-01T00:00:00.000Z","tags":[{"inline":true,"label":"MATLAB","permalink":"/blog/tags/matlab"},{"inline":true,"label":"VSCode","permalink":"/blog/tags/vs-code"},{"inline":true,"label":"\u958B\u767A\u74B0\u5883","permalink":"/blog/tags/\u958B\u767A\u74B0\u5883"}],"readingTime":3.34,"hasTruncateMarker":false,"authors":[{"name":"Guangze Yang","title":"R&D Researcher, Control & Robotics","url":"https://linkedin.com/in/youkoutaku","page":{"permalink":"/blog/authors/youkoutaku"},"socials":{"github":"https://github.com/youkoutaku","linkedin":"https://www.linkedin.com/in/youkoutaku/","x":"https://x.com/You_Koutaku"},"bio":"R&D Researcher specializing in Control Systems and Robotics. Passionate about automation, robotics, and sharing knowledge through blogging.\\n","imageURL":"https://github.com/youkoutaku.png","key":"youkoutaku"}],"frontMatter":{"authors":"youkoutaku","date":"2024-01-01T00:00:00.000Z","slug":"vscode-matlab-setup","title":"VSCode\u306B\u3088\u308BMATLAB\u306E\u4F7F\u7528","description":"Visual Studio Code\u3067MATLAB\u30B3\u30FC\u30C9\u3092\u7DE8\u96C6\u30FB\u5B9F\u884C\u3059\u308B\u65B9\u6CD5","tags":["MATLAB","VSCode","\u958B\u767A\u74B0\u5883"]},"unlisted":false,"lastUpdatedAt":1784484852000,"lastUpdatedBy":"Guang-Ze Yang","prevItem":{"title":"\u7DDA\u5F62\u96E2\u6563\u6642\u9593\u30B7\u30B9\u30C6\u30E0\u30E2\u30C7\u30EB\u306E\u30B7\u30DF\u30E5\u30EC\u30FC\u30B7\u30E7\u30F3","permalink":"/blog/simulation-linear-discrete-time-system"}},"content":"MATLAB\u306F\u3001\u79D1\u5B66\u6280\u8853\u8A08\u7B97\u3084\u30C7\u30FC\u30BF\u5206\u6790\u3001\u30A2\u30EB\u30B4\u30EA\u30BA\u30E0\u958B\u767A\u306A\u3069\u306B\u5229\u7528\u3055\u308C\u308B\u5F37\u529B\u306A\u30C4\u30FC\u30EB\u3067\u3059\u304C\u3001\u5C02\u7528\u306EMATLAB\u30A8\u30C7\u30A3\u30BF\u4EE5\u5916\u3067\u4F5C\u696D\u3057\u305F\u3044\u5834\u5408\u3082\u3042\u308A\u307E\u3059\u3002VSCode\u306F\u3001\u3068\u3066\u3082\u4EBA\u6C17\u306A\u30A8\u30C7\u30A3\u30BF\u3067\u3042\u308A\u3001\u305F\u304F\u3055\u3093\u306E\u958B\u767A\u74B0\u5883\u306B\u9069\u7528\u3067\u304D\u307E\u3059\u3002\u4F8B\u3048\u3001MATLAB\u3001LaTex, Python, C\u306A\u3069\u304C\u3042\u308A\u307E\u3059\u3002VSCode (Visual Studio Code) \u3092\u4F7F\u7528\u3057\u3066MATLAB\u30B3\u30FC\u30C9\u3092\u7DE8\u96C6\u3001\u5B9F\u884C\u3059\u308B\u65B9\u6CD5\u306B\u3064\u3044\u3066\u89E3\u8AAC\u3057\u307E\u3059\u3002\\n\\n## 1. \u5FC5\u8981\u306A\u6E96\u5099\\n\\nVSCode\u3067MATLAB\u3092\u4F7F\u7528\u3059\u308B\u305F\u3081\u306B\u306F\u3001\u4EE5\u4E0B\u306E\u624B\u9806\u3092\u884C\u3046\u5FC5\u8981\u304C\u3042\u308A\u307E\u3059\u3002\\n\\n### \u5FC5\u8981\u306A\u30BD\u30D5\u30C8\u30A6\u30A7\u30A2\\n\\n1. **[MATLAB](https://matlab.mathworks.com)**: MATLAB\u304C\u30A4\u30F3\u30B9\u30C8\u30FC\u30EB\u3055\u308C\u3066\u3044\u308B\u5FC5\u8981\u304C\u3042\u308A\u307E\u3059\u3002\\n2. **[VSCode](https://code.visualstudio.com)**: \u6700\u65B0\u30D0\u30FC\u30B8\u30E7\u30F3\u306EVisual Studio Code\u3092\u30A4\u30F3\u30B9\u30C8\u30FC\u30EB\u3057\u3066\u304F\u3060\u3055\u3044\u3002\\n3. **[MATLAB Extension](https://marketplace.visualstudio.com/items?itemName=MathWorks.language-matlab)**: VSCode\u3067MATLAB\u30B3\u30FC\u30C9\u3092\u30B5\u30DD\u30FC\u30C8\u3059\u308B\u305F\u3081\u306E\u62E1\u5F35\u6A5F\u80FD\u3002\\n4. **\u63A8\u5968\u62E1\u5F35\u6A5F\u80FD**:\\n   - **Code Runner**: \u30EF\u30F3\u30AF\u30EA\u30C3\u30AF\u3067\u30B3\u30FC\u30C9\u3092\u5B9F\u884C\u3002\\n   - **Bracket Pair Colorizer**: \u62EC\u5F27\u306E\u5BFE\u5FDC\u3092\u8272\u5206\u3051\u3002\\n\\n## 2. VSCode\u306E\u30BB\u30C3\u30C8\u30A2\u30C3\u30D7\\n\\n### 2.1 MATLAB\u62E1\u5F35\u6A5F\u80FD\u306E\u30A4\u30F3\u30B9\u30C8\u30FC\u30EB\\n\\n1. VSCode\u3092\u8D77\u52D5\u3057\u307E\u3059\u3002\\n2. \u30B5\u30A4\u30C9\u30D0\u30FC\u306E\u300CExtensions(\u62E1\u5F35\u6A5F\u80FD)\u300D\u30A2\u30A4\u30B3\u30F3\u3092\u30AF\u30EA\u30C3\u30AF\u3057\u307E\u3059\uFF08\u30B7\u30E7\u30FC\u30C8\u30AB\u30C3\u30C8\u30AD\u30FC: `Ctrl+Shift+X`\uFF09\u3002\\n3. \u691C\u7D22\u30D0\u30FC\u306B\u300CMATLAB\u300D\u3068\u5165\u529B\u3057\u3001MathWorks\u304C\u63D0\u4F9B\u3059\u308B\u516C\u5F0F\u306EMATLAB\u62E1\u5F35\u6A5F\u80FD\u3092\u30A4\u30F3\u30B9\u30C8\u30FC\u30EB\u3057\u307E\u3059\u3002\\n\\n![MATLAB Extension](https://preview.redd.it/matlab-via-vscode-v0-me0ex76f02oe1.png?width=1064&format=png&auto=webp&s=9b4d93a1b862f0f3762c4b5c0a140301b31eddf4)\\n\\n### 2.2 MATLAB CLI\u30D1\u30B9\u306E\u8A2D\u5B9A\\n\\nMATLAB\u30B3\u30FC\u30C9\u3092\u5B9F\u884C\u3059\u308B\u306B\u306F\u3001MATLAB\u306E\u30B3\u30DE\u30F3\u30C9\u30E9\u30A4\u30F3\u30A4\u30F3\u30BF\u30FC\u30D5\u30A7\u30A4\u30B9 (CLI) \u3078\u306E\u30D1\u30B9\u3092\u6307\u5B9A\u3059\u308B\u5FC5\u8981\u304C\u3042\u308A\u307E\u3059\u3002\\n\\n1. **MATLAB\u304C\u30A4\u30F3\u30B9\u30C8\u30FC\u30EB\u3055\u308C\u3066\u3044\u308B\u30C7\u30A3\u30EC\u30AF\u30C8\u30EA\u3092\u78BA\u8A8D\u3057\u307E\u3059**:\\n   - **Windows\u306E\u5834\u5408**: `C:\\\\Program Files\\\\MATLAB\\\\R202Xx\\\\bin\\\\matlab.exe`\\n   - **macOS\u306E\u5834\u5408**: `/Applications/MATLAB_R202Xx.app/bin/matlab`\\n   - **Linux\u306E\u5834\u5408**: `/usr/local/MATLAB/R202Xx/bin/matlab`\\n\\n2. VSCode\u306E\u8A2D\u5B9A\u3092\u958B\u304D\u307E\u3059\uFF08`Ctrl+,`\uFF09\u3002\\n3. \u691C\u7D22\u30D0\u30FC\u306B`MATLAB Path`\u3068\u5165\u529B\u3057\u3001MATLAB CLI\u306E\u30D5\u30EB\u30D1\u30B9\u3092\u8A2D\u5B9A\u3057\u307E\u3059\u3002\\n\\n![MATLAB Path Setting](https://preview.redd.it/matlab-via-vscode-v0-71htg76f02oe1.png?width=1058&format=png&auto=webp&s=b4c47eebaa87892c389699792fd242fffbd7c64c)\\n\\n## 3. MATLAB\u30B3\u30FC\u30C9\u306E\u7DE8\u96C6\u3068\u5B9F\u884C\\n\\n### 3.1 \u65B0\u3057\u3044MATLAB\u30B9\u30AF\u30EA\u30D7\u30C8\u306E\u4F5C\u6210\\n\\n1. VSCode\u3067\u65B0\u3057\u3044\u30D5\u30A1\u30A4\u30EB\u3092\u4F5C\u6210\u3057\u307E\u3059\uFF08`Ctrl+N`\uFF09\u3002\\n2. \u30D5\u30A1\u30A4\u30EB\u3092`example.m`\u3068\u3057\u3066\u4FDD\u5B58\u3057\u307E\u3059\u3002\\n3. MATLAB\u30B3\u30FC\u30C9\u3092\u66F8\u304D\u307E\u3059\u3002\u4EE5\u4E0B\u306F\u7C21\u5358\u306A\u4F8B\u3067\u3059\uFF1A\\n\\n```matlab\\nx = 0:0.1:10;\\ny = sin(x);\\nplot(x, y);\\ntitle(\'Sine Wave\');\\nxlabel(\'x\');\\nylabel(\'sin(x)\');\\n```\\n\\n### 3.2 MATLAB\u30B3\u30FC\u30C9\u306E\u5B9F\u884C\\n\\n1. \u30BF\u30FC\u30DF\u30CA\u30EB\u3092\u958B\u304D\u307E\u3059\uFF08`Ctrl+``\uFF09\u3002\\n2. MATLAB CLI\u3092\u4F7F\u7528\u3057\u3066\u30B9\u30AF\u30EA\u30D7\u30C8\u3092\u5B9F\u884C\u3057\u307E\u3059\uFF1A\\n\\n```bash\\nmatlab -r \\"example\\"\\n```\\n\\nMATLAB\u306E\u30C7\u30B9\u30AF\u30C8\u30C3\u30D7\u74B0\u5883\u304C\u8D77\u52D5\u3057\u3001\u30D7\u30ED\u30C3\u30C8\u304C\u8868\u793A\u3055\u308C\u307E\u3059\u3002\\n\\n### 3.3 \u62E1\u5F35\u6A5F\u80FD **Code Runner** \u306B\u3088\u308B\u5B9F\u884C\\n\\n1. VSCode\u3067\u300CCode Runner\u300D\u62E1\u5F35\u6A5F\u80FD\u3092\u30A4\u30F3\u30B9\u30C8\u30FC\u30EB\u3057\u307E\u3059\u3002\\n   - \u62E1\u5F35\u6A5F\u80FD\u306E\u691C\u7D22\u30D0\u30FC\u306B\u300CCode Runner\u300D\u3068\u5165\u529B\u3057\u3001\u30A4\u30F3\u30B9\u30C8\u30FC\u30EB\u3092\u30AF\u30EA\u30C3\u30AF\u3002\\n\\n2. MATLAB\u30B9\u30AF\u30EA\u30D7\u30C8\u3092\u958B\u304D\u3001\u53F3\u4E0A\u306E\u300CRun Code\u300D\u30DC\u30BF\u30F3\u3092\u30AF\u30EA\u30C3\u30AF\u3059\u308B\u3060\u3051\u3067\u30B3\u30FC\u30C9\u304C\u5B9F\u884C\u3055\u308C\u307E\u3059\u3002\\n   - \u307E\u305F\u306F\u3001`Ctrl+Alt+N`\u3067\u5B9F\u884C\u53EF\u80FD\u3002\\n\\n3. \u5B9F\u884C\u7D50\u679C\u306FVSCode\u306E\u51FA\u529B\u30BF\u30FC\u30DF\u30CA\u30EB\u306B\u8868\u793A\u3055\u308C\u307E\u3059\u3002\\n\\n![Code Runner](https://preview.redd.it/matlab-via-vscode-v0-2pgle46f02oe1.png?width=640&crop=smart&auto=webp&s=d8e76100b548aaa2546a1c67ccbfa82285126087)\\n\\n## 4. \u88DC\u8DB3\u60C5\u5831\\n\\n### MATLAB Live Scripts\u306E\u6CE8\u610F\u70B9\\n\\nVSCode\u3067\u306FMATLAB Live Scripts (`.mlx`\u30D5\u30A1\u30A4\u30EB) \u306E\u7DE8\u96C6\u306F\u76F4\u63A5\u30B5\u30DD\u30FC\u30C8\u3055\u308C\u3066\u3044\u307E\u305B\u3093\u3002\u3053\u308C\u3089\u3092\u7DE8\u96C6\u3059\u308B\u5834\u5408\u306F\u3001MATLAB\u5C02\u7528\u306E\u30A8\u30C7\u30A3\u30BF\u3092\u4F7F\u7528\u3057\u3066\u304F\u3060\u3055\u3044\u3002\\n\\n## \u307E\u3068\u3081\\n\\nVSCode\u3067MATLAB\u3092\u4F7F\u7528\u3059\u308B\u3053\u3068\u3067\u3001\u67D4\u8EDF\u306A\u4F5C\u696D\u74B0\u5883\u3092\u69CB\u7BC9\u3067\u304D\u307E\u3059\u3002\u7279\u306B\u3001\u4ED6\u306E\u30D7\u30ED\u30B0\u30E9\u30DF\u30F3\u30B0\u8A00\u8A9E\u3068\u7D44\u307F\u5408\u308F\u305B\u305F\u30D7\u30ED\u30B8\u30A7\u30AF\u30C8\u3092\u6271\u3046\u969B\u306B\u306F\u4FBF\u5229\u3067\u3059\u3002\u305C\u3072\u8A66\u3057\u3066\u307F\u3066\u304F\u3060\u3055\u3044\uFF01\\n\\n## \u95A2\u9023\u30EA\u30F3\u30AF\\n\\n- [MATLAB\u516C\u5F0F\u30B5\u30A4\u30C8](https://matlab.mathworks.com)\\n- [VSCode\u516C\u5F0F\u30B5\u30A4\u30C8](https://code.visualstudio.com)\\n- [MATLAB Extension for VSCode](https://marketplace.visualstudio.com/items?itemName=MathWorks.language-matlab)\\n- [Code Runner Extension](https://marketplace.visualstudio.com/items?itemName=formulahendry.code-runner)"}]}}')}}]);